{
  "name": "TURBO - Neural Conversational Core",
  "description": "A high-performance conversational AI assistant with real-time vision, voice, and system integration capabilities powered by Gemini Live API.",
  "requestFramePermissions": [
    "camera",
    "microphone",
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type SystemStatus = 'STANDBY' | 'ONLINE' | 'LISTENING' | 'THINKING' | 'SPEAKING' | 'ERROR';

export interface ChatMessage {
  id: string;
  sender: 'user' | 'turbo' | 'system';
  text: string;
  timestamp: number;
}

export interface SystemData {
  battery?: number;
  charging?: boolean;
  lat?: number;
  lng?: number;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { SystemStatus, ChatMessage, SystemData } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession } from './services/geminiService';

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [messages, setMessages] = useState<ChatMessage[]>([
    { id: '1', sender: 'turbo', text: 'Namaste. System initialized. Neural Core is ready for interaction.', timestamp: Date.now() }
  ]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({});
  const [isInitialized, setIsInitialized] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // System Diagnostics
  useEffect(() => {
    const updateSystem = async () => {
      const data: SystemData = {};
      if ('getBattery' in navigator) {
        // @ts-ignore
        const battery = await navigator.getBattery();
        data.battery = Math.round(battery.level * 100);
        data.charging = battery.charging;
      }
      navigator.geolocation.getCurrentPosition((pos) => {
        data.lat = pos.coords.latitude;
        data.lng = pos.coords.longitude;
      });
      setSystemData(data);
    };
    updateSystem();
    const interval = setInterval(updateSystem, 60000);
    return () => clearInterval(interval);
  }, []);

  const addMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system') => {
    setMessages(prev => [{
      id: Math.random().toString(36).substr(2, 9),
      text,
      sender,
      timestamp: Date.now()
    }, ...prev]);
  }, []);

  const toggleCore = async () => {
    if (!isLive) {
      setIsLive(true);
      setStatus('LISTENING');
      try {
        await setupLiveSession({
          onMessage: (text) => addMessage(text, 'turbo'),
          onUserTranscript: (text) => addMessage(text, 'user'),
          onStatusChange: setStatus,
          videoRef: isVisionActive ? videoRef : undefined,
          canvasRef: isVisionActive ? canvasRef : undefined
        });
      } catch (err) {
        console.error("Live session failed", err);
        setStatus('ERROR');
        setIsLive(false);
      }
    } else {
      stopLiveSession();
      setIsLive(false);
      setStatus('STANDBY');
    }
  };

  const toggleVision = () => {
    setIsVisionActive(prev => !prev);
    if (!isVisionActive) {
      addMessage("Vision Module Activated. Sensors online.", 'system');
      if (navigator.vibrate) navigator.vibrate(50);
    } else {
      addMessage("Vision Module Offline.", 'system');
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-[#050505] flex flex-col items-center justify-center z-50">
        <div className="grid-bg absolute inset-0 opacity-20 pointer-events-none"></div>
        <h1 className="holo-text text-5xl mb-4 tracking-[0.5em] text-cyan-400">TURBO</h1>
        <p className="text-cyan-300 mb-12 animate-pulse font-light tracking-widest text-sm uppercase">Neural Core Activation Ready</p>
        <button 
          onClick={() => setIsInitialized(true)}
          className="border border-cyan-500 px-12 py-4 text-xl font-bold text-cyan-400 hover:bg-cyan-900/30 transition-all uppercase tracking-widest"
        >
          Initialize
        </button>
      </div>
    );
  }

  return (
    <div className="relative h-screen w-screen flex flex-col items-center overflow-hidden">
      {/* Background Grid */}
      <div className="absolute inset-0 z-[-1] opacity-20 pointer-events-none" 
           style={{ backgroundImage: 'linear-gradient(#00f3ff11 1px, transparent 1px), linear-gradient(90deg, #00f3ff11 1px, transparent 1px)', backgroundSize: '40px 40px', transform: 'perspective(500px) rotateX(60deg) translateY(-50%)' }}>
      </div>

      <Header status={status} systemData={systemData} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        {isVisionActive && <VisionFeed videoRef={videoRef} canvasRef={canvasRef} />}
        <CoreVisualization status={status} />
      </div>

      <div className="w-full max-w-2xl px-4 flex flex-col items-center pb-8 gap-6 z-10">
        <ChatLog messages={messages} />

        <div className="flex items-center gap-12">
          <button 
            onClick={toggleVision}
            className={`p-3 rounded-full border transition-all ${isVisionActive ? 'border-cyan-400 text-cyan-400 shadow-[0_0_15px_#00f3ff88]' : 'border-gray-600 text-gray-600'}`}
            title="Toggle Vision"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
          </button>

          <MicButton isActive={isLive} onClick={toggleCore} />

          <button 
            className="p-3 rounded-full border border-gray-600 text-gray-600 hover:text-cyan-400 hover:border-cyan-400 transition-all"
            onClick={() => {
               if (navigator.vibrate) navigator.vibrate([100, 50, 100]);
               addMessage("System feedback pulse sent.", 'system');
            }}
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path><line x1="12" y1="9" x2="12" y2="13"></line><line x1="12" y1="17" x2="12.01" y2="17"></line></svg>
          </button>
        </div>
      </div>

      {/* Aesthetic Overlays */}
      <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-cyan-500/30 to-transparent scan-line pointer-events-none"></div>
      <div className="absolute inset-0 pointer-events-none border-[1px] border-cyan-500/10 m-4 rounded-3xl"></div>
    </div>
  );
};

export default App;

import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { SystemStatus } from "../types";

let currentSession: any = null;
let audioContext: AudioContext | null = null;
let nextStartTime = 0;
const sources = new Set<AudioBufferSourceNode>();

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

interface SetupOptions {
  onMessage: (text: string) => void;
  onUserTranscript: (text: string) => void;
  onStatusChange: (status: SystemStatus) => void;
  videoRef?: React.RefObject<HTMLVideoElement>;
  canvasRef?: React.RefObject<HTMLCanvasElement>;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, videoRef, canvasRef }: SetupOptions) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }
  const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
  const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

  let currentOutputTranscription = '';
  let currentInputTranscription = '';

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        onStatusChange('LISTENING');
        const source = inputCtx.createMediaStreamSource(stream);
        const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          const pcmBlob = createBlob(inputData);
          sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
        };
        source.connect(scriptProcessor);
        scriptProcessor.connect(inputCtx.destination);

        // Vision logic
        if (videoRef?.current && canvasRef?.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            const ctx = canvas.getContext('2d');

            navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
                .then(vStream => {
                    video.srcObject = vStream;
                    setInterval(() => {
                        if (video.videoWidth && ctx) {
                            canvas.width = video.videoWidth;
                            canvas.height = video.videoHeight;
                            ctx.drawImage(video, 0, 0);
                            canvas.toBlob(async blob => {
                                if (blob) {
                                    const reader = new FileReader();
                                    reader.onloadend = () => {
                                        const base64 = (reader.result as string).split(',')[1];
                                        sessionPromise.then(s => s.sendRealtimeInput({
                                            media: { data: base64, mimeType: 'image/jpeg' }
                                        }));
                                    };
                                    reader.readAsDataURL(blob);
                                }
                            }, 'image/jpeg', 0.5);
                        }
                    }, 1000);
                });
        }
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (msg.serverContent?.outputTranscription) {
          currentOutputTranscription += msg.serverContent.outputTranscription.text;
        } else if (msg.serverContent?.inputTranscription) {
          currentInputTranscription += msg.serverContent.inputTranscription.text;
        }

        if (msg.serverContent?.turnComplete) {
          if (currentOutputTranscription) onMessage(currentOutputTranscription);
          if (currentInputTranscription) onUserTranscript(currentInputTranscription);
          currentOutputTranscription = '';
          currentInputTranscription = '';
        }

        const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
        if (audioData && audioContext) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
          const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
          const source = audioContext.createBufferSource();
          source.buffer = audioBuffer;
          source.connect(audioContext.destination);
          source.addEventListener('ended', () => {
            sources.delete(source);
            if (sources.size === 0) onStatusChange('LISTENING');
          });
          source.start(nextStartTime);
          nextStartTime += audioBuffer.duration;
          sources.add(source);
        }

        if (msg.serverContent?.interrupted) {
          sources.forEach(s => s.stop());
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        console.error("Live Error", e);
        onStatusChange('ERROR');
      },
      onclose: () => {
        onStatusChange('STANDBY');
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
      },
      systemInstruction: 'You are TURBO, a neural assistant. You have eyes (camera), ears (mic), and a mouth (speakers). Be helpful, conversational, and technical. If user asks about their battery or location, use grounding or just speak naturally as you see it. Use a calm, futuristic tone.'
    }
  });

  currentSession = await sessionPromise;
}

export function stopLiveSession() {
  if (currentSession) {
    currentSession.close();
    currentSession = null;
  }
  sources.forEach(s => s.stop());
  sources.clear();
}

