import React from 'react';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";
import { SystemStatus } from "../types";

let currentSession: any = null;
let audioContext: AudioContext | null = null;
let nextStartTime = 0;
const sources = new Set<AudioBufferSourceNode>();

// Utility to decode base64 string to Uint8Array as required by the manual decode logic
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Utility to decode raw PCM audio data into an AudioBuffer for gapless playback
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

// Utility to encode Uint8Array to base64 string for transmission
function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

// Create a PCM audio blob structure for the Live API realtime input
function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

interface SetupOptions {
  onMessage: (text: string) => void;
  onUserTranscript: (text: string) => void;
  onStatusChange: (status: SystemStatus) => void;
  // Fixing the "Cannot find namespace 'React'" error by importing React
  videoRef?: React.RefObject<HTMLVideoElement>;
  canvasRef?: React.RefObject<HTMLCanvasElement>;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, videoRef, canvasRef }: SetupOptions) {
  // Initialize GoogleGenAI with the API key from environment variables as per guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }
  const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
  const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

  let currentOutputTranscription = '';
  let currentInputTranscription = '';

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        onStatusChange('LISTENING');
        const source = inputCtx.createMediaStreamSource(stream);
        const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          const pcmBlob = createBlob(inputData);
          // Solely rely on sessionPromise to send data to avoid race conditions or stale closures
          sessionPromise.then(s => s.sendRealtimeInput({ media: pcmBlob }));
        };
        source.connect(scriptProcessor);
        scriptProcessor.connect(inputCtx.destination);

        // Vision logic: stream image frames to the model alongside audio
        if (videoRef?.current && canvasRef?.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            const ctx = canvas.getContext('2d');

            navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } })
                .then(vStream => {
                    video.srcObject = vStream;
                    setInterval(() => {
                        if (video.videoWidth && ctx) {
                            canvas.width = video.videoWidth;
                            canvas.height = video.videoHeight;
                            ctx.drawImage(video, 0, 0);
                            canvas.toBlob(async blob => {
                                if (blob) {
                                    const reader = new FileReader();
                                    reader.onloadend = () => {
                                        const base64 = (reader.result as string).split(',')[1];
                                        sessionPromise.then(s => s.sendRealtimeInput({
                                            media: { data: base64, mimeType: 'image/jpeg' }
                                        }));
                                    };
                                    reader.readAsDataURL(blob);
                                }
                            }, 'image/jpeg', 0.5);
                        }
                    }, 1000);
                });
        }
      },
      onmessage: async (msg: LiveServerMessage) => {
        // Handle output and input audio transcriptions if enabled in config
        if (msg.serverContent?.outputTranscription) {
          currentOutputTranscription += msg.serverContent.outputTranscription.text;
        } else if (msg.serverContent?.inputTranscription) {
          currentInputTranscription += msg.serverContent.inputTranscription.text;
        }

        // Send full transcriptions to the UI when a turn is complete
        if (msg.serverContent?.turnComplete) {
          if (currentOutputTranscription) onMessage(currentOutputTranscription);
          if (currentInputTranscription) onUserTranscript(currentInputTranscription);
          currentOutputTranscription = '';
          currentInputTranscription = '';
        }

        // Handle raw PCM audio output stream from the model
        const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
        if (audioData && audioContext) {
          onStatusChange('SPEAKING');
          // Schedule playback at nextStartTime to ensure gapless audio
          nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
          const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
          const source = audioContext.createBufferSource();
          source.buffer = audioBuffer;
          source.connect(audioContext.destination);
          source.addEventListener('ended', () => {
            sources.delete(source);
            if (sources.size === 0) onStatusChange('LISTENING');
          });
          source.start(nextStartTime);
          nextStartTime += audioBuffer.duration;
          sources.add(source);
        }

        // If user interrupts, stop all scheduled audio playback immediately
        if (msg.serverContent?.interrupted) {
          sources.forEach(s => s.stop());
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        console.error("Live Error", e);
        onStatusChange('ERROR');
      },
      onclose: () => {
        onStatusChange('STANDBY');
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      speechConfig: {
        voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } }
      },
      systemInstruction: 'You are TURBO, a neural assistant. You have eyes (camera), ears (mic), and a mouth (speakers). Be helpful, conversational, and technical. If user asks about their battery or location, use grounding or just speak naturally as you see it. Use a calm, futuristic tone.'
    }
  });

  currentSession = await sessionPromise;
}

export function stopLiveSession() {
  if (currentSession) {
    currentSession.close();
    currentSession = null;
  }
  sources.forEach(s => s.stop());
  sources.clear();
}

