import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { SystemStatus, ChatMessage, SystemData, BossProfile, SecurityEvent } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis, announcePowerStatus } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Empathetic & Narrative',
  affinityLevel: 10,
  isVerified: false,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({});
  const [isInitialized, setIsInitialized] = useState(false);

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };
      if (activeIdRef.current) {
        const updated = prev.map(m => m.id === activeIdRef.current ? { ...m, text, timestamp: Date.now() } : m);
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text, sender, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleSecurityAction = useCallback((action: 'MUTE' | 'VERIFIED' | 'LOG', data?: any) => {
    if (action === 'VERIFIED') {
      setBossProfile(p => ({ ...p, isVerified: true }));
      setStatus('ONLINE');
      updateOrAddMessage("Identity confirmed. Welcome back, BOSS. I am now fully operational.", 'turbo', true);
    } else if (action === 'MUTE') {
      setIsMuted(true);
      setStatus('SECURITY_ALERT');
      updateOrAddMessage("UNAUTHORIZED STRANGER DETECTED. ENTERING SILENT OBSERVATION.", 'system', true);
    } else if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: data.type,
        description: data.description,
        capturedImage: data.image,
        relation: data.relation
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
      if (data.type === 'BOSS_RETURNED') {
        setIsMuted(false);
        setStatus('ONLINE');
      }
    }
  }, [updateOrAddMessage]);

  const toggleCore = async () => {
    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
      try {
        await setupLiveSession({
          onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
          onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
          onStatusChange: (s) => setStatus(isMuted ? 'SECURITY_ALERT' : s),
          onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
          onSecurityAction: handleSecurityAction,
          bossProfile: bossProfile,
          videoRef: videoRef,
          canvasRef: canvasRef
        });
      } catch (err) {
        setStatus('ERROR');
        setIsLive(false);
      }
    } else {
      stopLiveSession();
      setIsLive(false);
      setStatus('STANDBY');
    }
  };

  const clearLogs = () => setBossProfile(p => ({ ...p, securityLog: [] }));

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <h1 className="holo-text text-6xl mb-4 text-cyan-400">TURBO</h1>
        <p className="text-purple-400 mb-12 animate-pulse">SECURITY PROTOCOLS LOADED</p>
        <button onClick={() => setIsInitialized(true)} className="border border-cyan-500 px-16 py-5 text-xl text-cyan-400 hover:bg-cyan-500/20">AWAKEN CORE</button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-colors duration-1000 ${isMuted ? 'bg-red-950/20' : 'bg-transparent'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed videoRef={videoRef} canvasRef={canvasRef} isVisible={isVisionActive} isScanning={isDeepScanning} isMuted={isMuted} />
        <CoreVisualization status={status} />
      </div>

      {/* Security Report Overlay */}
      {bossProfile.securityLog.length > 0 && bossProfile.isVerified && !isMuted && (
        <div className="absolute right-4 top-24 w-64 max-h-[60vh] overflow-y-auto bg-black/80 border border-red-500/30 p-4 rounded-xl backdrop-blur-md z-30 animate-in fade-in slide-in-from-right-4">
           <div className="flex justify-between items-center mb-4">
             <h3 className="text-red-400 text-xs font-bold uppercase tracking-widest">Security Report</h3>
             <button onClick={clearLogs} className="text-[0.6rem] text-gray-500 hover:text-white uppercase">Clear</button>
           </div>
           {bossProfile.securityLog.map(log => (
             <div key={log.id} className="mb-4 border-b border-gray-800 pb-2">
               <span className="text-[0.5rem] text-gray-500">{new Date(log.timestamp).toLocaleTimeString()}</span>
               <p className="text-[0.7rem] text-cyan-200 mt-1">{log.description}</p>
               {log.capturedImage && (
                 <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="mt-2 w-full rounded border border-red-500/20" alt="Stranger" />
               )}
               {log.relation && <div className="mt-1 text-[0.6rem] text-purple-400 uppercase">Claimed: {log.relation}</div>}
             </div>
           ))}
        </div>
      )}

      <div className="w-full max-w-2xl px-4 flex flex-col items-center pb-8 gap-6 z-10">
        <ChatLog messages={messages} />
        <div className="flex items-center gap-12">
          <button onClick={() => setIsVisionActive(!isVisionActive)} className={`p-3 rounded-full border ${isVisionActive ? 'border-cyan-400 text-cyan-400' : 'border-gray-600'}`}>
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
          </button>
          <MicButton isActive={isLive} onClick={toggleCore} />
        </div>
      </div>
    </div>
  );
};

