  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const profileContext = `BOSS PROFILE: Verified=${bossProfile.isVerified}, Interests=${bossProfile.interests.join(',')}`;
  const response = await ai.models.generateContent({
