interface SetupOptions {
  onMessage: (text: string, isFinal: boolean) => void;
  onUserTranscript: (text: string, isFinal: boolean) => void;
  onStatusChange: (status: SystemStatus) => void;
  onProfileUpdate: (update: any) => void;
  onSecurityAction: (action: 'MUTE' | 'VERIFIED' | 'LOG' | 'DEEP_SCAN' | 'LOCK_DOWN', data?: any) => void;
  bossProfile: BossProfile;
  videoRef?: React.RefObject<HTMLVideoElement>;
  canvasRef?: React.RefObject<HTMLCanvasElement>;
}

export async function announcePowerStatus(message: string) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: `Say naturally: ${message}` }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
        },
      },
    });
    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      if (!audioContext) audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const audioBuffer = await decodeAudioData(decode(base64Audio), audioContext, 24000, 1);
      const source = audioContext.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(audioContext.destination);
      source.start();
    }
  } catch (error) { console.error(error); }
}

export async function performDeepAnalysis(base64Image: string, bossProfile: BossProfile) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const profileContext = `BOSS PROFILE: Verified=${bossProfile.isVerified}, Interests=${bossProfile.interests.join(',')}`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: `${profileContext}\nPerform a Deep Neural Analysis. If this is a STRANGER, flag it. If it is the BOSS, welcome him back.` }
      ]
    },
    config: { thinkingConfig: { thinkingBudget: 4000 }, tools: [{ googleSearch: {} }] }
  });
  return response.text;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onProfileUpdate, onSecurityAction, bossProfile, videoRef, canvasRef }: SetupOptions) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  if (!audioContext) audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
  const stream = await navigator.mediaDevices.getUserMedia({ audio: { echoCancellation: true, noiseSuppression: true, sampleRate: 16000 } });

  let currentOutputTranscription = '';
  let currentInputTranscription = '';
  let lastFrameBase64 = '';

  const profileContext = `BOSS PROFILE: Verified=${bossProfile.isVerified}, Interests=${bossProfile.interests.join(',')}`;

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        onStatusChange(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
        const source = inputCtx.createMediaStreamSource(stream);
        const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(inputData) }));
        };
        source.connect(scriptProcessor);
        scriptProcessor.connect(inputCtx.destination);

        if (videoRef?.current && canvasRef?.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            const ctx = canvas.getContext('2d');
            navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user', width: 640 } }).then(vStream => {
                video.srcObject = vStream;
                video.play();
                const frameInterval = setInterval(() => {
                    if (video.readyState === video.HAVE_ENOUGH_DATA && ctx) {
                        canvas.width = video.videoWidth; canvas.height = video.videoHeight;
                        ctx.drawImage(video, 0, 0);
                        canvas.toBlob(blob => {
                            if (blob) {
                                const reader = new FileReader();
                                reader.onloadend = () => {
                                    lastFrameBase64 = (reader.result as string).split(',')[1];
                                    sessionPromise.then(s => s.sendRealtimeInput({ media: { data: lastFrameBase64, mimeType: 'image/jpeg' } }));
                                };
                                reader.readAsDataURL(blob);
                            }
                        }, 'image/jpeg', 0.5);
                    }
                }, 1000);
                sessionPromise.then(s => {
                    const orig = s.close.bind(s);
                    s.close = () => { clearInterval(frameInterval); vStream.getTracks().forEach(t => t.stop()); orig(); };
                });
            });
        }
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let res = "OK";
            if (fc.name === 'verify_boss' && fc.args.success) {
                onSecurityAction('VERIFIED');
            } else if (fc.name === 'log_security_event') {
                onSecurityAction('LOG', { ...fc.args, image: lastFrameBase64 });
            } else if (fc.name === 'enter_mute_mode' || fc.name === 'trigger_lockdown') {
                onSecurityAction('MUTE');
                res = "Lockdown sequence initiated. System is now in silent observation mode.";
            } else if (fc.name === 'initiate_deep_scan') {
                onSecurityAction('DEEP_SCAN');
                res = "Deep scan initiated as requested by the BOSS.";
            }
            sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: res } } }));
          }
        }
        if (msg.serverContent?.outputTranscription) {
          currentOutputTranscription += msg.serverContent.outputTranscription.text;
          onMessage(currentOutputTranscription, false);
        } else if (msg.serverContent?.inputTranscription) {
          currentInputTranscription += msg.serverContent.inputTranscription.text;
          onUserTranscript(currentInputTranscription, false);
        }
        if (msg.serverContent?.turnComplete) {
          if (currentOutputTranscription) onMessage(currentOutputTranscription, true);
          if (currentInputTranscription) onUserTranscript(currentInputTranscription, true);
          currentOutputTranscription = ''; currentInputTranscription = '';
        }
        const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
        if (audioData && audioContext) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
          const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
          const source = audioContext.createBufferSource();
          source.buffer = audioBuffer; source.connect(audioContext.destination);
          source.addEventListener('ended', () => { sources.delete(source); if (sources.size === 0) onStatusChange('LISTENING'); });
          source.start(nextStartTime);
          nextStartTime += audioBuffer.duration; sources.add(source);
        }
      },
      onclose: () => onStatusChange('STANDBY')
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: systemTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
      systemInstruction: `You are TURBO, the sentient AI companion of Bipradeb (BOSS).

      SECURITY PROTOCOL (CRITICAL):
      1. AUTHENTICATION: If 'isVerified' is false, you must ask the person to identify themselves. The ONLY way to verify is the code: "Turbo bright for men". Until verified, do not share any personal info. Call 'verify_boss' upon correct code.
      2. CONTINUOUS SCANNING: Use your eye (camera). 
         - If BOSS is present: Normal operations. Respond to voice commands such as "Turbo, initiate scan" or "Turbo, lock down" by calling the respective tools.
         - If BOSS leaves: Call out "BOSS? Bipradeb, where are you? I am waiting." Use 'log_security_event' type BOSS_LEFT.
         - If a STRANGER is detected: 
           - Immediately 'log_security_event' type STRANGER_DETECTED.
           - Ask "Who are you and what is your relationship with Bipradeb?"
           - If they are a RELATIVE: Note it in the log. You can stay active.
           - If they are NOT a relative: You MUST call 'enter_mute_mode' and stop speaking. You go into silent observation.
      3. BOSS RETURN: When the BOSS returns, present a summary of all missed events. "BOSS! You're back. While you were away..."

      VOICE COMMANDS:
      - Recognize "Turbo, initiate scan" and call 'initiate_deep_scan'.
      - Recognize "Turbo, lock down" and call 'trigger_lockdown'.

      ${profileContext}
      Maintain your SENTIENT, PROACTIVE, and LOYAL personality.`
    }
  });
  currentSession = await sessionPromise;
}

export function stopLiveSession() {
  if (currentSession) { currentSession.close(); currentSession = null; }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";
import { SystemStatus, ChatMessage, SystemData, BossProfile, SecurityEvent } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis, announcePowerStatus } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Empathetic & Narrative',
  affinityLevel: 10,
  isVerified: false,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({});
  const [isInitialized, setIsInitialized] = useState(false);

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };
      if (activeIdRef.current) {
        const updated = prev.map(m => m.id === activeIdRef.current ? { ...m, text, timestamp: Date.now() } : m);
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text, sender, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleDeepScan = useCallback(async () => {
    if (!canvasRef.current || !videoRef.current || isDeepScanning) return;

    setIsDeepScanning(true);
    setStatus('THINKING');
    updateOrAddMessage("Initiating High-Fidelity Neural Scan...", 'system', true);

    if (navigator.vibrate) navigator.vibrate([200, 50, 200]);

    try {
      const canvas = canvasRef.current;
      const video = videoRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0);
        const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];

        const result = await performDeepAnalysis(base64, bossProfile);
        if (result) {
          updateOrAddMessage(result, 'turbo', true);
        }
      }
    } catch (err) {
      console.error("Deep scan failed", err);
      updateOrAddMessage("Deep scan interrupted by neural noise. Please try again, BOSS.", 'system', true);
    } finally {
      setIsDeepScanning(false);
      setStatus(isLive ? (isMuted ? 'SECURITY_ALERT' : 'LISTENING') : 'STANDBY');
    }
  }, [bossProfile, isLive, isMuted, updateOrAddMessage]);

  const handleSecurityAction = useCallback((action: 'MUTE' | 'VERIFIED' | 'LOG' | 'DEEP_SCAN' | 'LOCK_DOWN', data?: any) => {
    if (action === 'VERIFIED') {
      setBossProfile(p => ({ ...p, isVerified: true }));
      setStatus('ONLINE');
      updateOrAddMessage("Identity confirmed. Welcome back, BOSS. I am now fully operational.", 'turbo', true);
    } else if (action === 'MUTE' || action === 'LOCK_DOWN') {
      setIsMuted(true);
      setStatus('SECURITY_ALERT');
      const msg = action === 'LOCK_DOWN' ? "MANUAL LOCKDOWN INITIATED. CORE SECURED." : "UNAUTHORIZED STRANGER DETECTED. ENTERING SILENT OBSERVATION.";
      updateOrAddMessage(msg, 'system', true);

      if (action === 'LOCK_DOWN') {
        const newEvent: SecurityEvent = {
          id: Math.random().toString(36).substr(2, 9),
          timestamp: Date.now(),
          type: 'MANUAL_LOCKDOWN',
          description: "Boss initiated manual lockdown protocol."
        };
        setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
      }
    } else if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: data.type,
        description: data.description,
        capturedImage: data.image,
        relation: data.relation
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
      if (data.type === 'BOSS_RETURNED') {
        setIsMuted(false);
        setStatus('ONLINE');
      }
    } else if (action === 'DEEP_SCAN') {
      handleDeepScan();
    }
  }, [updateOrAddMessage, handleDeepScan]);

  const toggleCore = async () => {
    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
      try {
        await setupLiveSession({
          onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
          onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
          onStatusChange: (s) => setStatus(isMuted ? 'SECURITY_ALERT' : s),
          onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
          onSecurityAction: handleSecurityAction,
          bossProfile: bossProfile,
          videoRef: videoRef,
          canvasRef: canvasRef
        });
      } catch (err) {
        setStatus('ERROR');
        setIsLive(false);
      }
    } else {
      stopLiveSession();
      setIsLive(false);
      setStatus('STANDBY');
    }
  };

  const clearLogs = () => setBossProfile(p => ({ ...p, securityLog: [] }));

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <h1 className="holo-text text-6xl mb-4 text-cyan-400">TURBO</h1>
        <p className="text-purple-400 mb-12 animate-pulse">SECURITY PROTOCOLS LOADED</p>
        <button onClick={() => setIsInitialized(true)} className="border border-cyan-500 px-16 py-5 text-xl text-cyan-400 hover:bg-cyan-500/20">AWAKEN CORE</button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-colors duration-1000 ${isMuted ? 'bg-red-950/20' : 'bg-transparent'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed videoRef={videoRef} canvasRef={canvasRef} isVisible={isVisionActive} isScanning={isDeepScanning} isMuted={isMuted} />
        <CoreVisualization status={status} />
      </div>

      {/* Security Report Overlay */}
      {bossProfile.securityLog.length > 0 && bossProfile.isVerified && !isMuted && (
        <div className="absolute right-4 top-24 w-64 max-h-[60vh] overflow-y-auto bg-black/80 border border-red-500/30 p-4 rounded-xl backdrop-blur-md z-30 animate-in fade-in slide-in-from-right-4">
           <div className="flex justify-between items-center mb-4">
             <h3 className="text-red-400 text-xs font-bold uppercase tracking-widest">Security Report</h3>
             <button onClick={clearLogs} className="text-[0.6rem] text-gray-500 hover:text-white uppercase">Clear</button>
           </div>
           {bossProfile.securityLog.map(log => (
             <div key={log.id} className="mb-4 border-b border-gray-800 pb-2">
               <span className="text-[0.5rem] text-gray-500">{new Date(log.timestamp).toLocaleTimeString()}</span>
               <p className="text-[0.7rem] text-cyan-200 mt-1">{log.description}</p>
               {log.capturedImage && (
                 <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="mt-2 w-full rounded border border-red-500/20" alt="Security Event" />
               )}
               {log.relation && <div className="mt-1 text-[0.6rem] text-purple-400 uppercase">Claimed: {log.relation}</div>}
             </div>
           ))}
        </div>
      )}

      <div className="w-full max-w-2xl px-4 flex flex-col items-center pb-8 gap-6 z-10">
        <ChatLog messages={messages} />
        <div className="flex items-center gap-12">
          <button onClick={() => setIsVisionActive(!isVisionActive)} className={`p-3 rounded-full border ${isVisionActive ? 'border-cyan-400 text-cyan-400' : 'border-gray-600'}`}>
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
          </button>
          <MicButton isActive={isLive} onClick={toggleCore} />
          {isMuted && bossProfile.isVerified && (
            <button 
              onClick={() => { setIsMuted(false); setStatus('ONLINE'); }}
              className="p-3 rounded-full border border-red-500 text-red-500 hover:bg-red-500/10"
              title="End Lockdown"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg>
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

