      {/* Verified BOSS Only Assets */}
      {bossProfile.isVerified && !bossProfile.isHideMode && bossProfile.securityLog.length > 0 && (
        <div className="absolute right-6 top-24 w-80 max-h-[60vh] overflow-y-auto bg-black/90 border border-cyan-500/30 p-5 rounded-3xl backdrop-blur-2xl z-40 transition-all duration-700 animate-in slide-in-from-right-10">
           <div className="flex justify-between items-center mb-6 border-b border-cyan-500/20 pb-2">
