           <div className="flex flex-col gap-6">
             {bossProfile.securityLog.map(log => (
               <div key={log.id} className="border-l border-cyan-500/20 pl-4 py-1">
                 <div className="flex justify-between items-start mb-2">
                   <span className="text-[0.5rem] text-gray-500 font-mono tracking-widest">{new Date(log.timestamp).toLocaleTimeString()}</span>
                   <span className={`text-[0.45rem] px-1.5 py-0.5 rounded uppercase font-black tracking-widest ${log.type === 'STRANGER_DETECTED' ? 'bg-red-500/20 text-red-400' : 'bg-cyan-500/20 text-cyan-400'}`}>{log.type}</span>
                 </div>
                 <p className="text-[0.75rem] text-gray-300 leading-relaxed mb-3">{log.description}</p>

                 {log.capturedImage && (
                   <div className="mt-3 group relative overflow-hidden rounded-xl border border-cyan-500/20">
                     <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="w-full h-40 object-cover opacity-90 hover:opacity-100 transition-opacity" alt="Secret Capture" />
