      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-10 gap-8 z-10">
        <ChatLog messages={messages} />
        <div className="flex items-center gap-14">
          <button onClick={() => setIsVisionActive(!isVisionActive)} className={`p-5 rounded-full border transition-all duration-500 ${isVisionActive ? 'border-cyan-400 text-cyan-400 bg-cyan-400/10 shadow-[0_0_20px_rgba(0,243,255,0.2)]' : 'border-gray-700 text-gray-500 hover:border-gray-500'}`} title="Neural Eye">
            <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
          </button>
          <MicButton isActive={isLive} onClick={toggleCore} />
