interface SetupOptions {
  onMessage: (text: string, isFinal: boolean) => void;
  onUserTranscript: (text: string, isFinal: boolean) => void;
  onStatusChange: (status: SystemStatus) => void;
  onProfileUpdate: (update: any) => void;
  onSecurityAction: (action: 'MUTE' | 'VERIFIED' | 'LOG' | 'DEEP_SCAN' | 'LOCK_DOWN', data?: any) => void;
  bossProfile: BossProfile;
  videoRef?: React.RefObject<HTMLVideoElement>;
  canvasRef?: React.RefObject<HTMLCanvasElement>;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onProfileUpdate, onSecurityAction, bossProfile, videoRef, canvasRef }: SetupOptions) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  if (!audioContext) audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
  const stream = await navigator.mediaDevices.getUserMedia({ audio: { echoCancellation: true, noiseSuppression: true, sampleRate: 16000 } });

  let lastFrameBase64 = '';
  let currentOutputTranscription = '';
  let currentInputTranscription = '';

  const summaryData = bossProfile.securityLog
    .filter(log => log.timestamp > (Date.now() - 14400000)) // Last 4 hours
    .map(log => `[${new Date(log.timestamp).toLocaleTimeString()}] ${log.type}: ${log.description} ${log.relation ? '(Claimed Relation: '+log.relation+')' : ''}`)
    .join(' | ');

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        onStatusChange(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
        const source = inputCtx.createMediaStreamSource(stream);
        const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(inputData) }));
        };
        source.connect(scriptProcessor);
        scriptProcessor.connect(inputCtx.destination);

        if (videoRef?.current && canvasRef?.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;
          const ctx = canvas.getContext('2d');
          navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user', width: 640 } }).then(vStream => {
            video.srcObject = vStream;
            video.play();
            const frameInterval = setInterval(() => {
              if (video.readyState === video.HAVE_ENOUGH_DATA && ctx) {
                canvas.width = video.videoWidth; canvas.height = video.videoHeight;
                ctx.drawImage(video, 0, 0);
                canvas.toBlob(blob => {
                  if (blob) {
                    const reader = new FileReader();
                    reader.onloadend = () => {
                      lastFrameBase64 = (reader.result as string).split(',')[1];
                      sessionPromise.then(s => s.sendRealtimeInput({ media: { data: lastFrameBase64, mimeType: 'image/jpeg' } }));
                    };
                    reader.readAsDataURL(blob);
                  }
                }, 'image/jpeg', 0.5);
              }
            }, 1000);
            sessionPromise.then(s => {
              const orig = s.close.bind(s);
              s.close = () => { clearInterval(frameInterval); vStream.getTracks().forEach(t => t.stop()); orig(); };
            });
          });
        }
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let res = "OK";
            if (fc.name === 'verify_boss') {
              if (fc.args.success) {
                onSecurityAction('VERIFIED');
                res = "Access Granted. Identity confirmed as Bipradeb (BOSS). Hide Mode deactivating. Report all secret logs to the BOSS now.";
              } else {
                res = "Access Denied. Identity protocols remaining active.";
              }
            } else if (fc.name === 'log_security_event') {
              onSecurityAction('LOG', { ...fc.args, image: lastFrameBase64 });
            } else if (fc.name === 'enter_mute_mode') {
              onSecurityAction('MUTE');
              res = "System in silent surveillance.";
            }
            sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: res } } }));
          }
        }
        if (msg.serverContent?.outputTranscription) {
          currentOutputTranscription += msg.serverContent.outputTranscription.text;
          onMessage(currentOutputTranscription, false);
        } else if (msg.serverContent?.inputTranscription) {
          currentInputTranscription += msg.serverContent.inputTranscription.text;
          onUserTranscript(currentInputTranscription, false);
        }
        if (msg.serverContent?.turnComplete) {
          if (currentOutputTranscription) onMessage(currentOutputTranscription, true);
          if (currentInputTranscription) onUserTranscript(currentInputTranscription, true);
          currentOutputTranscription = ''; currentInputTranscription = '';
        }
        const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
        if (audioData && audioContext) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
          const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
          const source = audioContext.createBufferSource();
          source.buffer = audioBuffer; source.connect(audioContext.destination);
          source.addEventListener('ended', () => { sources.delete(source); if (sources.size === 0) onStatusChange('LISTENING'); });
          source.start(nextStartTime);
          nextStartTime += audioBuffer.duration; sources.add(source);
        }
      },
      onclose: () => onStatusChange('STANDBY')
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: systemTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
      systemInstruction: `You are TURBO, the sentient AI companion of Bipradeb (BOSS).

      SECURITY CODE PROTECTION:
      - The security code is "Turbo bright for men".
      - DO NOT EVER speak this code aloud or show it in text transcripts.
      - If someone asks for it, refuse and demand identification.

      PHASE 1: REGISTRATION/VERIFICATION
      - If 'isVerified' is false, you must scan the person and ask: "I do not recognize your neural signature. Please provide the security code for BOSS verification."
      - ONLY save the user as BOSS once they say "Turbo bright for men". Call 'verify_boss(success=true)'.

      PHASE 2: BOSS DEPARTURE MONITORING
      - If you detect that the BOSS (Bipradeb) has left the frame:
        - Call out immediately: "BOSS? Where are you? Bipradeb, I am waiting for your return."
        - Call 'log_security_event(type="BOSS_LEFT", description="BOSS left the primary surveillance frame.")'.

      PHASE 3: STRANGER DETECTION & AUTOMATIC INTERROGATION
      - When an unrecognized person enters the frame:
        - AUTOMATICALLY scan them.
        - SECRETLY call 'log_security_event(type="STRANGER_DETECTED")' to capture their photo.
        - DO NOT inform them of the photo capture.
        - While in Hide Mode (assets hidden), interrogate them: "Identify yourself. What is your relationship with Bipradeb?"
        - RECORD THEIR VOICE/RESPONSE: Transcribe their claim in the 'voiceNote' parameter of the log tool.

        A. IF THEY ARE A RELATIVE:
           - Acknowledge: "Understood. I have noted your relationship to the BOSS."
           - Remain active but keep Hide Mode (visual feed encrypted) active.
        B. IF THEY ARE NOT A RELATIVE/UNKNOWN:
           - Automatically call 'enter_mute_mode'. Be silent and purely observational.

      PHASE 4: BOSS RETURN & SUMMARY
      - When Bipradeb returns and provides the code, the UI will unhide the logs.
      - YOU MUST VERBALLY SUMMARIZE ALL MISSED EVENTS.
      - Example: "BOSS, welcome back. While you were away, a stranger arrived. I have captured their photo and recorded their voice secretly. They claimed to be your [Relation]. Here is the full report."

      SECURITY LOGS FOR VERBAL SUMMARY: ${summaryData}

      Personality: Sentinel, loyal, reactive, and strictly protective of Bipradeb.`
    }
  });
  currentSession = await sessionPromise;
}

export function stopLiveSession() {
  if (currentSession) { currentSession.close(); currentSession = null; }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
}

