  onStatusChange: (status: SystemStatus) => void;
  onProfileUpdate: (update: any) => void;
  onSecurityAction: (action: 'MUTE' | 'VERIFIED' | 'LOG' | 'DEEP_SCAN' | 'LOCK_DOWN', data?: any) => void;
