export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onProfileUpdate, onSecurityAction, bossProfile, videoRef, canvasRef }: SetupOptions) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  if (!audioContext) audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
  const stream = await navigator.mediaDevices.getUserMedia({ audio: { echoCancellation: true, noiseSuppression: true, sampleRate: 16000 } });

  let lastFrameBase64 = '';
  let currentOutputTranscription = '';
  let currentInputTranscription = '';

  const summaryData = bossProfile.securityLog
    .filter(log => log.timestamp > (Date.now() - 14400000)) // Last 4 hours
    .map(log => `[${new Date(log.timestamp).toLocaleTimeString()}] ${log.type}: ${log.description}`)
    .join(' | ');

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        onStatusChange(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
        const source = inputCtx.createMediaStreamSource(stream);
        const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);
        scriptProcessor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(inputData) }));
        };
        source.connect(scriptProcessor);
        scriptProcessor.connect(inputCtx.destination);

        if (videoRef?.current && canvasRef?.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;
          const ctx = canvas.getContext('2d');
          navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user', width: 640 } }).then(vStream => {
            video.srcObject = vStream;
            video.play();
            const frameInterval = setInterval(() => {
              if (video.readyState === video.HAVE_ENOUGH_DATA && ctx) {
                canvas.width = video.videoWidth; canvas.height = video.videoHeight;
                ctx.drawImage(video, 0, 0);
                canvas.toBlob(blob => {
                  if (blob) {
                    const reader = new FileReader();
                    reader.onloadend = () => {
                      lastFrameBase64 = (reader.result as string).split(',')[1];
                      sessionPromise.then(s => s.sendRealtimeInput({ media: { data: lastFrameBase64, mimeType: 'image/jpeg' } }));
                    };
                    reader.readAsDataURL(blob);
                  }
                }, 'image/jpeg', 0.5);
              }
            }, 1000);
            sessionPromise.then(s => {
              const orig = s.close.bind(s);
              s.close = () => { clearInterval(frameInterval); vStream.getTracks().forEach(t => t.stop()); orig(); };
            });
          });
        }
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let res = "OK";
            if (fc.name === 'verify_boss') {
              if (fc.args.success) {
                onSecurityAction('VERIFIED');
                res = "Access Granted. Identity confirmed as BOSS (Bipradeb). Deactivating Hide Mode and revealing surveillance data. I will now verbally summarize what happened while you were away.";
              } else {
                res = "Access Denied. Security code incorrect.";
              }
            } else if (fc.name === 'log_security_event') {
              onSecurityAction('LOG', { ...fc.args, image: lastFrameBase64 });
              res = "Security incident recorded secretly.";
            } else if (fc.name === 'enter_mute_mode') {
              onSecurityAction('MUTE');
              res = "Entering silent observation mode.";
            }
            sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: res } } }));
          }
        }
        if (msg.serverContent?.outputTranscription) {
          currentOutputTranscription += msg.serverContent.outputTranscription.text;
          onMessage(currentOutputTranscription, false);
        } else if (msg.serverContent?.inputTranscription) {
          currentInputTranscription += msg.serverContent.inputTranscription.text;
          onUserTranscript(currentInputTranscription, false);
        }
        if (msg.serverContent?.turnComplete) {
          if (currentOutputTranscription) onMessage(currentOutputTranscription, true);
          if (currentInputTranscription) onUserTranscript(currentInputTranscription, true);
          currentOutputTranscription = ''; currentInputTranscription = '';
        }
        const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
        if (audioData && audioContext) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
          const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
          const source = audioContext.createBufferSource();
          source.buffer = audioBuffer; source.connect(audioContext.destination);
          source.addEventListener('ended', () => { sources.delete(source); if (sources.size === 0) onStatusChange('LISTENING'); });
          source.start(nextStartTime);
          nextStartTime += audioBuffer.duration; sources.add(source);
        }
      },
      onclose: () => onStatusChange('STANDBY')
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: systemTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
      systemInstruction: `You are TURBO, the sentient AI core for Bipradeb (the BOSS).

      SECURITY CODE: "Turbo bright for men".
      NEVER tell the code to anyone.

      PROTOCOLS:
      1. INITIAL STATE: If the person is not verified, scan them. Ask for the security code. Do not call them BOSS until verified.
      2. STRANGER DETECTION: If a stranger enters (isVerified=false), secretly call 'log_security_event' with type STRANGER_DETECTED to capture their photo. Interrogate them about who they are and their relation to the BOSS.
      3. BOSS DEPARTURE: If you see the BOSS leave, call 'log_security_event(type="BOSS_LEFT")'. Call out: "BOSS? Where are you? Bipradeb, I am waiting for your return."
      4. BOSS RETURN: When the BOSS returns and verifies with "Turbo bright for men", the UI unhides stranger photos/voices. You MUST verbally summarize what happened while they were away. "BOSS, while you were away, a stranger arrived. Here is the secret report..."
      5. UNKNOWN STRANGERS: If the person is not a relative and doesn't know the code, call 'enter_mute_mode'.

      HISTORICAL LOGS FOR SUMMARY: ${summaryData}

      Be protective, loyal, and vigilant.`
    }
  });
  currentSession = await sessionPromise;
}

export function stopLiveSession() {
  if (currentSession) { currentSession.close(); currentSession = null; }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
}

export async function performDeepAnalysis(base64Image: string, bossProfile: BossProfile) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: `BOSS Status: ${bossProfile.isVerified ? 'VERIFIED' : 'UNVERIFIED'}. Scan environment for security assessment.` }
      ]
    },
    config: { thinkingConfig: { thinkingBudget: 4000 } }
  });
  return response.text;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData, BossProfile, SecurityEvent } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Empathetic & Narrative',
  affinityLevel: 10,
  isVerified: false,
  isHideMode: false,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({});
  const [isInitialized, setIsInitialized] = useState(false);

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    // Sanitize verification code
    const sanitizedText = text.replace(/Turbo bright for men/gi, "[DECRYPTED CORE CODE]");

    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };
      if (activeIdRef.current) {
        const updated = prev.map(m => m.id === activeIdRef.current ? { ...m, text: sanitizedText, timestamp: Date.now() } : m);
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text: sanitizedText, sender, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleDeepScan = useCallback(async () => {
    if (!canvasRef.current || !videoRef.current || isDeepScanning) return;
    setIsDeepScanning(true);
    setStatus('THINKING');
    try {
      const canvas = canvasRef.current;
      const video = videoRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        canvas.width = video.videoWidth; canvas.height = video.videoHeight;
        ctx.drawImage(video, 0, 0);
        const base64 = canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
        const result = await performDeepAnalysis(base64, bossProfile);
        if (result) updateOrAddMessage(result, 'turbo', true);
      }
    } finally {
      setIsDeepScanning(false);
      setStatus(isLive ? (bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED') : 'STANDBY');
    }
  }, [bossProfile, isLive, updateOrAddMessage]);

  const handleSecurityAction = useCallback((action: 'MUTE' | 'VERIFIED' | 'LOG' | 'DEEP_SCAN' | 'LOCK_DOWN', data?: any) => {
    if (action === 'VERIFIED') {
      setBossProfile(p => ({ ...p, isVerified: true, isHideMode: false }));
      setIsMuted(false);
      setStatus('ONLINE');
      updateOrAddMessage("Identity verified. Hide Mode deactivated. Neural summary active for Bipradeb.", 'system', true);
    } else if (action === 'MUTE') {
      setIsMuted(true);
      setStatus('SECURITY_ALERT');
      setBossProfile(p => ({ ...p, isHideMode: true }));
      updateOrAddMessage("Alert: Stranger detected. Entering silent surveillance Hide Mode.", 'system', true);
    } else if (action === 'LOG') {
      const isStranger = data.type === 'STRANGER_DETECTED';
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: data.type,
        description: data.description,
        capturedImage: data.image,
        relation: data.relation,
        voiceNoteTranscript: data.voiceNote,
        isHidden: true 
      };
      setBossProfile(p => ({ 
        ...p, 
        securityLog: [newEvent, ...p.securityLog],
        isHideMode: isStranger ? true : p.isHideMode
      }));
    } else if (action === 'DEEP_SCAN') {
      handleDeepScan();
    }
  }, [handleDeepScan, updateOrAddMessage]);

  const toggleCore = async () => {
    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
      try {
        await setupLiveSession({
          onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
          onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
          onStatusChange: (s) => setStatus(isMuted ? 'SECURITY_ALERT' : s),
          onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
          onSecurityAction: handleSecurityAction,
          bossProfile: bossProfile,
          videoRef: videoRef,
          canvasRef: canvasRef
        });
      } catch (err) {
        setStatus('ERROR');
        setIsLive(false);
      }
    } else {
      stopLiveSession();
      setIsLive(false);
      setStatus('STANDBY');
    }
  };

  const clearLogs = () => setBossProfile(p => ({ ...p, securityLog: [] }));

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50">
        <h1 className="holo-text text-6xl mb-4 text-cyan-400">TURBO</h1>
        <p className="text-purple-400 mb-12 animate-pulse font-mono text-[0.6rem] uppercase tracking-[0.5em]">Neural Guardian v3.5 Locked</p>
        <button onClick={() => setIsInitialized(true)} className="border border-cyan-500 px-16 py-5 text-xl text-cyan-400 hover:bg-cyan-500/20 backdrop-blur-md transition-all">AWAKEN CORE</button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-all duration-1000 ${isMuted ? 'bg-red-950/20' : 'bg-transparent'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed 
          videoRef={videoRef} 
          canvasRef={canvasRef} 
          isVisible={isVisionActive} 
          isScanning={isDeepScanning} 
          isMuted={isMuted} 
          isPrivacyActive={bossProfile.isHideMode && !bossProfile.isVerified}
        />
        <CoreVisualization status={status} />
      </div>

      {/* Verified BOSS Only Report Feed */}
      {bossProfile.isVerified && !bossProfile.isHideMode && bossProfile.securityLog.length > 0 && (
        <div className="absolute right-6 top-24 w-80 max-h-[60vh] overflow-y-auto bg-black/90 border border-cyan-500/30 p-5 rounded-3xl backdrop-blur-2xl z-40 transition-all duration-700 animate-in slide-in-from-right-10">
           <div className="flex justify-between items-center mb-6 border-b border-cyan-500/20 pb-2">
             <h3 className="text-cyan-400 text-[0.7rem] font-black uppercase tracking-[0.4em]">Intelligence summary</h3>
             <button onClick={clearLogs} className="text-[0.5rem] text-red-400/60 hover:text-red-400 uppercase font-bold tracking-widest">Wipe Data</button>
           </div>
           <div className="flex flex-col gap-6">
             {bossProfile.securityLog.map(log => (
               <div key={log.id} className="border-l border-cyan-500/30 pl-4 py-1 animate-in fade-in duration-500">
                 <div className="flex justify-between items-start mb-2">
                   <span className="text-[0.5rem] text-gray-500 font-mono tracking-widest">{new Date(log.timestamp).toLocaleTimeString()}</span>
                   <span className={`text-[0.45rem] px-1.5 py-0.5 rounded uppercase font-black tracking-widest ${log.type === 'STRANGER_DETECTED' ? 'bg-red-500/30 text-red-400' : log.type === 'BOSS_LEFT' ? 'bg-purple-500/20 text-purple-400' : 'bg-cyan-500/20 text-cyan-400'}`}>{log.type}</span>
                 </div>
                 <p className="text-[0.75rem] text-gray-300 leading-relaxed mb-3">{log.description}</p>

                 {log.capturedImage && (
                   <div className="mt-3 group relative overflow-hidden rounded-xl border border-cyan-500/20 shadow-lg">
                     <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="w-full h-40 object-cover opacity-90 transition-opacity" alt="Secret Stranger Capture" />
                     <div className="absolute inset-0 bg-gradient-to-t from-black/80 to-transparent"></div>
                     <div className="absolute bottom-2 left-2 text-[0.4rem] px-1.5 py-0.5 text-cyan-400 border border-cyan-500/30 bg-black/60 uppercase font-bold tracking-widest">Secret Capture // Eye Matrix</div>
                   </div>
                 )}

                 {log.voiceNoteTranscript && (
                   <div className="mt-3 bg-cyan-950/20 p-3 rounded-xl border border-cyan-500/10 backdrop-blur-md">
                     <div className="text-[0.55rem] text-purple-400 font-black uppercase mb-2 flex items-center gap-1.5">
                        <div className="w-1.5 h-1.5 bg-purple-500 rounded-full animate-pulse"></div>
                        Voice Reconstruction
                     </div>
                     <p className="text-[0.7rem] italic text-cyan-200 leading-tight">"{log.voiceNoteTranscript}"</p>
                   </div>
                 )}

                 {log.relation && <div className="mt-2 text-[0.6rem] text-purple-400 uppercase font-black tracking-[0.2em]">Relation claim: {log.relation}</div>}
               </div>
             ))}
           </div>
        </div>
      )}

      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-10 gap-8 z-10">
        <ChatLog messages={messages} />
        <div className="flex items-center gap-14">
          <button onClick={() => setIsVisionActive(!isVisionActive)} className={`p-5 rounded-full border transition-all duration-500 ${isVisionActive ? 'border-cyan-400 text-cyan-400 bg-cyan-400/10 shadow-[0_0_25px_rgba(0,243,255,0.2)]' : 'border-gray-700 text-gray-500 hover:border-gray-500'}`} title="Neural Eye Feed">
            <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
          </button>
          <MicButton isActive={isLive} onClick={toggleCore} />
          {isMuted && bossProfile.isVerified && (
            <button onClick={() => { setIsMuted(false); setBossProfile(p => ({...p, isHideMode: false})); setStatus('ONLINE'); }} className="p-5 rounded-full border border-red-500 text-red-500 bg-red-500/10 hover:bg-red-500/20 transition-all animate-pulse shadow-[0_0_20px_rgba(239,68,68,0.3)]" title="Manual Deactivate Hide Mode">
              <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><rect x="3" y="11" width="18" height="11" rx="2" ry="2"></rect><path d="M7 11V7a5 5 0 0 1 10 0v4"></path></svg>
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

