  id: string;
  timestamp: number;
  type: 'STRANGER_DETECTED' | 'BOSS_RETURNED' | 'BOSS_LEFT' | 'MANUAL_LOCKDOWN' | 'RELATIVE_IDENTIFIED';
  description: string;
  capturedImage?: string; // base64
  relation?: string;
  voiceNoteTranscript?: string;
  isHidden?: boolean;
}

export interface ChatMessage {
  id: string;
  sender: 'user' | 'turbo' | 'system';
  text: string;
  timestamp: number;
}

export interface SystemData {
  battery?: number;
  charging?: boolean;
  lat?: number;
  lng?: number;
}

export interface BossProfile {
  preferences: string[];
  interests: string[];
  communicationStyle: string;
  affinityLevel: number;
  isVerified: boolean;
  isHideMode: boolean; 
  isBossPresent: boolean;
  securityLog: SecurityEvent[];
