      setBossProfile(p => ({ ...p, isVerified: true, isHideMode: false, isBossPresent: true }));
      setIsMuted(false);
      setStatus('ONLINE');
      updateOrAddMessage("Identity confirmed. Access Granted to Bipradeb. Visualizing neural security logs.", 'system', true);
    } else if (action === 'MUTE') {
      setIsMuted(true);
      setStatus('SECURITY_ALERT');
      setBossProfile(p => ({ ...p, isHideMode: true }));
      updateOrAddMessage("Threat Assessment: Potential intruder. Entering Silent Observation (Hide Mode).", 'system', true);
    } else if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: data.type,
        description: data.description,
        capturedImage: data.image,
        relation: data.relation,
        voiceNoteTranscript: data.voiceNote,
      };

      setBossProfile(p => {
        const isLeaving = data.type === 'BOSS_LEFT';
        const isReturning = data.type === 'BOSS_RETURNED';
        return { 
          ...p, 
          isBossPresent: isReturning ? true : (isLeaving ? false : p.isBossPresent),
          securityLog: [newEvent, ...p.securityLog]
        };
      });
    } else if (action === 'DEEP_SCAN') {
      handleDeepScan();
    }
  }, [handleDeepScan, updateOrAddMessage]);

  const toggleCore = async () => {
    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
      try {
        await setupLiveSession({
          onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
          onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
          onStatusChange: (s) => setStatus(isMuted ? 'SECURITY_ALERT' : s),
          onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
          onSecurityAction: handleSecurityAction,
          bossProfile: bossProfile,
          videoRef: videoRef,
          canvasRef: canvasRef
        });
      } catch (err) {
        setStatus('ERROR');
        setIsLive(false);
      }
    } else {
      stopLiveSession();
      setIsLive(false);
      setStatus('STANDBY');
    }
  };

  const clearLogs = () => setBossProfile(p => ({ ...p, securityLog: [] }));

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(0,243,255,0.05)_0%,transparent_70%)]"></div>
        <h1 className="holo-text text-7xl mb-4 text-cyan-400 animate-pulse">TURBO</h1>
        <p className="text-purple-400 mb-12 font-mono text-[0.6rem] uppercase tracking-[0.5em] opacity-60">Secure Neural Core // Version 4.0</p>
        <button onClick={() => setIsInitialized(true)} className="group relative border border-cyan-500/50 px-20 py-6 text-xl text-cyan-400 hover:text-white transition-all overflow-hidden">
          <div className="absolute inset-0 bg-cyan-500/10 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
          <span className="relative z-10 font-bold tracking-widest">INITIALIZE CORE</span>
        </button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-all duration-1000 ${isMuted ? 'bg-red-950/30' : 'bg-transparent'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed 
          videoRef={videoRef} 
          canvasRef={canvasRef} 
          isVisible={isVisionActive} 
          isScanning={isDeepScanning} 
          isMuted={isMuted} 
          isPrivacyActive={bossProfile.isHideMode && !bossProfile.isVerified}
        />
        <CoreVisualization status={status} />
      </div>

      {/* Security Intel Panel - Only visible for verified Boss */}
      {bossProfile.isVerified && bossProfile.securityLog.length > 0 && (
        <div className="absolute right-6 top-24 w-80 max-h-[65vh] overflow-y-auto bg-black/80 border border-cyan-500/20 p-5 rounded-2xl backdrop-blur-3xl z-40 transition-all duration-700 animate-in slide-in-from-right-10">
           <div className="flex justify-between items-center mb-6 border-b border-cyan-500/10 pb-3">
             <div className="flex flex-col">
                <h3 className="text-cyan-400 text-[0.7rem] font-black uppercase tracking-[0.4em]">Surveillance Log</h3>
                <span className="text-[0.45rem] text-gray-500 uppercase tracking-widest">Automated Sentinel Output</span>
             </div>
             <button onClick={clearLogs} className="p-2 hover:bg-red-500/10 rounded-full transition-colors">
               <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#ef4444" strokeWidth="2"><path d="M3 6h18m-2 0v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6m3 0V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"></path></svg>
             </button>
           </div>
           <div className="flex flex-col gap-6">
             {bossProfile.securityLog.map(log => (
               <div key={log.id} className="relative border-l border-cyan-500/20 pl-4 py-1 group">
                 <div className="absolute -left-1.5 top-2 w-3 h-3 bg-black border border-cyan-500 rounded-full"></div>
                 <div className="flex justify-between items-start mb-2">
                   <span className="text-[0.5rem] text-gray-500 font-mono">{new Date(log.timestamp).toLocaleTimeString()}</span>
                   <span className={`text-[0.45rem] px-1.5 py-0.5 rounded uppercase font-black tracking-widest ${log.type === 'STRANGER_DETECTED' ? 'bg-red-500/30 text-red-400' : 'bg-cyan-500/10 text-cyan-400'}`}>{log.type.replace('_', ' ')}</span>
                 </div>
                 <p className="text-[0.75rem] text-gray-300 leading-snug mb-3">{log.description}</p>

                 {log.capturedImage && (
