                     <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="w-full h-32 object-cover opacity-80" alt="Secret Capture" />
                     <div className="absolute inset-0 bg-gradient-to-t from-black/60 to-transparent"></div>
                     <span className="absolute bottom-1 right-2 text-[0.4rem] text-cyan-400 font-bold uppercase tracking-widest">Neural Snapshot</span>
                   </div>
