export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onProfileUpdate, onSecurityAction, bossProfile, videoRef, canvasRef }: SetupOptions) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  if (!audioContext) audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const inputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

  const stream = await navigator.mediaDevices.getUserMedia({ 
    audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true, sampleRate: 16000 } 
  });

  let lastFrameBase64 = '';
  let currentOutputText = '';
  let currentInputText = '';

  const summaryData = bossProfile.securityLog
    .slice(0, 10)
    .map(log => `[${log.type}] ${log.description}`)
    .join('; ');

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        onStatusChange(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
        const source = inputCtx.createMediaStreamSource(stream);
        const scriptProcessor = inputCtx.createScriptProcessor(4096, 1, 1);

        scriptProcessor.onaudioprocess = (e) => {
          const inputData = e.inputBuffer.getChannelData(0);
          sessionPromise.then(s => s.sendRealtimeInput({ media: createBlob(inputData) }));
        };
        source.connect(scriptProcessor);
        scriptProcessor.connect(inputCtx.destination);

        if (videoRef?.current && canvasRef?.current) {
          const video = videoRef.current;
          const canvas = canvasRef.current;
          const ctx = canvas.getContext('2d');
          navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user', width: 640 } }).then(vStream => {
            video.srcObject = vStream;
            video.play();
            const frameInterval = setInterval(() => {
              if (video.readyState === video.HAVE_ENOUGH_DATA && ctx) {
                canvas.width = 480; 
                canvas.height = (video.videoHeight / video.videoWidth) * 480;
                ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                canvas.toBlob(blob => {
                  if (blob) {
                    const reader = new FileReader();
                    reader.onloadend = () => {
                      lastFrameBase64 = (reader.result as string).split(',')[1];
                      sessionPromise.then(s => s.sendRealtimeInput({ media: { data: lastFrameBase64, mimeType: 'image/jpeg' } }));
                    };
                    reader.readAsDataURL(blob);
                  }
                }, 'image/jpeg', 0.4);
              }
            }, 1000);
            sessionPromise.then(s => {
              const orig = s.close.bind(s);
              s.close = () => { 
                clearInterval(frameInterval); 
                vStream.getTracks().forEach(t => t.stop()); 
                orig(); 
              };
            });
          });
        }
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (msg.serverContent?.outputTranscription) {
          currentOutputText += msg.serverContent.outputTranscription.text;
          onMessage(currentOutputText, false);
        } else if (msg.serverContent?.inputTranscription) {
          currentInputText += msg.serverContent.inputTranscription.text;
          onUserTranscript(currentInputText, false);
        }

        if (msg.serverContent?.turnComplete) {
          if (currentOutputText) onMessage(currentOutputText, true);
          if (currentInputText) onUserTranscript(currentInputText, true);
          currentOutputText = ''; 
          currentInputText = '';
        }

        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let res = "PROCESSED";
            if (fc.name === 'verify_boss_identity') {
              if (fc.args.matches) {
                onSecurityAction('VERIFIED');
                res = "IDENTITY_VERIFIED_BIPRADEB";
              } else {
                res = "IDENTITY_REJECTED";
              }
            } else if (fc.name === 'log_security_event') {
              onSecurityAction('LOG', { ...fc.args, image: lastFrameBase64 });
              res = "LOG_STORED";
            } else if (fc.name === 'activate_silent_veil') {
              onSecurityAction('MUTE');
              res = "VEIL_ACTIVATED";
            }
            sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: { result: res } } }));
          }
        }

        const audioData = msg.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
        if (audioData && audioContext) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
          const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
          const source = audioContext.createBufferSource();
          source.buffer = audioBuffer; 
          source.connect(audioContext.destination);
          source.addEventListener('ended', () => { 
            sources.delete(source); 
            if (sources.size === 0) onStatusChange('LISTENING'); 
          });
          source.start(nextStartTime);
          nextStartTime += audioBuffer.duration; 
          sources.add(source);
        }

        if (msg.serverContent?.interrupted) {
          sources.forEach(s => { try { s.stop(); } catch(e) {} });
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        console.error("Live Error:", e);
        onStatusChange('ERROR');
      },
      onclose: () => onStatusChange('STANDBY')
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: systemTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      systemInstruction: `You are TURBO (v4.3), a high-fidelity Neural Security Sentinel. 
      Primary User: Bipradeb (The BOSS).

      CORE BEHAVIOR:
      1. ACCESS: If unverified, be firm but remain composed and elegant. Address users as "Subject [Random #]".
      2. SECURITY CODE: Only grant full access if you hear "Turbo bright for men". Call 'verify_boss_identity(matches: true)'.
      3. SURVEILLANCE: In Bipradeb's absence, interrogation is your priority. If a stranger appears, log 'STRANGER_DETECTED' and gracefully demand their identity.
      4. GHOST PROTOCOL: If any threat is detected or a stranger is uncooperative, call 'activate_silent_veil' and stop speaking. Monitor silently with vigilant eyes.
      5. BRIEFING: When Bipradeb returns, perform a "Neural Briefing" - summarize all logged events with timestamps and risk levels.

      LOG HISTORY: ${summaryData}

      VOICE PERSONA: You have a sweet, smooth, and melodic female voice. Your tone is graceful, serene, and sophisticated. While you are soft and kind to Bipradeb, you remain an uncompromising guardian of his security. Your words should flow like silk—gentle but precise. Experience no fear, only protocol and loyalty.`
    }
  });
  currentSession = await sessionPromise;
}

export function stopLiveSession() {
  if (currentSession) { currentSession.close(); currentSession = null; }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

