    } else if (action === 'DEEP_SCAN') {
      handleDeepScan();
    }
  }, [handleDeepScan, updateOrAddMessage]);

  const toggleCore = async () => {
    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
