      {bossProfile.isVerified && bossProfile.securityLog.length > 0 && (
        <div className="absolute right-6 top-24 w-80 max-h-[65vh] overflow-y-auto bg-black/60 border border-purple-500/10 p-5 rounded-3xl backdrop-blur-3xl z-40 transition-all duration-700 custom-scrollbar shadow-2xl">
           <div className="flex justify-between items-center mb-6 border-b border-white/5 pb-3">
             <div className="flex flex-col">
