import React, { useEffect, useRef } from 'react';
import { SystemStatus } from '../types';

interface CoreVisualizationProps {
  status: SystemStatus;
}

const CoreVisualization: React.FC<CoreVisualizationProps> = ({ status }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;
    const particles: any[] = [];
    const pCount = 80;

    class Particle {
      angle: number;
      baseRadius: number;
      radius: number;
      size: number;
      speed: number;
      color: string;
      alpha: number;
      oscillation: number;

      constructor() {
        this.angle = Math.random() * Math.PI * 2;
        this.baseRadius = 120 + Math.random() * 60;
        this.radius = this.baseRadius;
        this.size = 1 + Math.random() * 2.5;
        this.speed = 0.002 + Math.random() * 0.004;
        // Natural Rose/Cyan/Purple palette
        const palette = ['#fb7185', '#a855f7', '#00f3ff'];
        this.color = palette[Math.floor(Math.random() * palette.length)];
        this.alpha = 0.3 + Math.random() * 0.5;
        this.oscillation = Math.random() * Math.PI * 2;
      }

      update() {
        let targetRadius = this.baseRadius;
        let speedMult = 1;

        if (status === 'SPEAKING') {
          targetRadius += Math.sin(Date.now() / 150) * 45;
          speedMult = 1.8;
        } else if (status === 'LISTENING') {
          targetRadius += Math.sin(Date.now() / 400) * 12;
          speedMult = 0.5;
        } else if (status === 'THINKING') {
          speedMult = 4.0;
          targetRadius += Math.sin(this.oscillation) * 30;
          this.oscillation += 0.06;
        }

        this.radius += (targetRadius - this.radius) * 0.05;
        this.angle += this.speed * speedMult;
      }

      draw() {
        if (!ctx) return;
        const x = canvas.width / 2 + Math.cos(this.angle) * this.radius;
        const y = canvas.height / 2 + Math.sin(this.angle) * this.radius;

        ctx.beginPath();
        ctx.arc(x, y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = this.color;
        ctx.globalAlpha = this.alpha;
        ctx.fill();

        // Organic connections
        if (Math.random() > 0.99) {
          ctx.beginPath();
          ctx.moveTo(canvas.width / 2, canvas.height / 2);
          ctx.lineTo(x, y);
          ctx.strokeStyle = this.color + '11';
          ctx.lineWidth = 0.5;
          ctx.stroke();
        }

        ctx.globalAlpha = 1;
      }
    }

    for (let i = 0; i < pCount; i++) particles.push(new Particle());

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();

      // Sentient Glow (Rose-centric)
      const glowScale = status === 'SPEAKING' ? 1.3 : 1.0;
      const glowSize = (160 + Math.sin(time / 1000) * 20) * glowScale;
      const gradient = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, glowSize
      );
      gradient.addColorStop(0, 'rgba(244, 63, 94, 0.12)');
      gradient.addColorStop(0.5, 'rgba(168, 85, 247, 0.05)');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Organic Pulse Ring
      ctx.beginPath();
      const ringPulse = status === 'SPEAKING' ? Math.sin(time / 200) * 15 : Math.sin(time / 800) * 8;
      const ringRadius = 110 + ringPulse;
      ctx.arc(canvas.width / 2, canvas.height / 2, ringRadius, 0, Math.PI * 2);
      ctx.strokeStyle = status === 'SPEAKING' ? '#fb718588' : '#fb718522';
      ctx.lineWidth = status === 'SPEAKING' ? 3 : 1.5;
      ctx.stroke();

      particles.forEach(p => {
        p.update();
        p.draw();
      });

      animationFrame = requestAnimationFrame(animate);
    };

    const resize = () => {
      if (canvas) {
        canvas.width = canvas.clientWidth;
        canvas.height = canvas.clientHeight;
      }
    };

    window.addEventListener('resize', resize);
    resize();
    animate();

    return () => {
      cancelAnimationFrame(animationFrame);
      window.removeEventListener('resize', resize);
    };
  }, [status]);

  return (
    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
      <canvas ref={canvasRef} className="w-full h-full max-w-xl max-h-xl opacity-80 transition-opacity duration-1000" />
    </div>
  );
};

