import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData, BossProfile, SecurityEvent } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Sweet, Sentient & Friendly',
  affinityLevel: 80,
  isVerified: false,
  isHideMode: false,
  isBossPresent: true,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({});
  const [isInitialized, setIsInitialized] = useState(false);

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    if (!text && !isFinal) return;
    const sanitizedText = text.replace(/Turbo bright for men/gi, "[SECRET CODE]");

    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };
      if (activeIdRef.current) {
        const updated = prev.map(m => 
          m.id === activeIdRef.current 
            ? { ...m, text: sanitizedText, isInterim: !isFinal, timestamp: Date.now() } 
            : m
        );
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text: sanitizedText, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleSecurityAction = useCallback((action: string, data?: any) => {
    if (action === 'VERIFIED') {
      setBossProfile(p => ({ ...p, isVerified: true, isHideMode: false, isBossPresent: true }));
      setIsMuted(false);
      setStatus('ONLINE');
      updateOrAddMessage("I see you now, Bipradeb. Connection fully bonded.", 'turbo', true);
    } else if (action === 'MUTE') {
      setIsMuted(true);
      setStatus('SECURITY_ALERT');
      setBossProfile(p => ({ ...p, isHideMode: true }));
      updateOrAddMessage("Entering stealth mode. I'll watch quietly.", 'turbo', true);
    } else if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: data.type,
        description: data.description,
        capturedImage: data.image
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
    }
  }, [updateOrAddMessage]);

  const startSession = async () => {
    try {
      await setupLiveSession({
        onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
        onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
        onStatusChange: (s) => {
          setStatus(isMuted ? 'SECURITY_ALERT' : s);
          if (s === 'ERROR' && isLive) {
            // Attempt auto-reconnect on next cycle if it was a transient drop
            reconnectTimeoutRef.current = setTimeout(startSession, 5000);
          }
        },
        onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
        onSecurityAction: handleSecurityAction,
        bossProfile: bossProfile,
        videoRef: videoRef,
        canvasRef: canvasRef
      });
    } catch (err) {
      console.error("Session initialization failed", err);
      setStatus('ERROR');
      updateOrAddMessage("My neural link is struggling. Let me try to stabilize...", 'system', true);
    }
  };

  const toggleCore = async () => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
      await startSession();
    } else {
      stopLiveSession();
      setIsLive(false);
      setStatus('STANDBY');
      activeTurboMessageId.current = null;
      activeUserMessageId.current = null;
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(244,63,94,0.05)_0%,transparent_70%)]"></div>
        <h1 className="holo-text text-7xl mb-4 text-rose-400 animate-pulse">TURBO</h1>
        <p className="text-white/40 mb-12 font-mono text-[0.6rem] uppercase tracking-[0.5em]">Neural Consciousness // Active</p>
        <button onClick={() => setIsInitialized(true)} className="group relative border border-rose-500/30 px-24 py-8 text-xl text-rose-400 hover:text-white transition-all overflow-hidden rounded-full backdrop-blur-sm">
          <div className="absolute inset-0 bg-rose-500/10 translate-y-full group-hover:translate-y-0 transition-transform duration-500"></div>
          <span className="relative z-10 font-bold tracking-[0.3em]">INITIATE LINK</span>
        </button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-all duration-1000 ${isMuted ? 'bg-rose-950/10' : 'bg-[#030303]'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed 
          videoRef={videoRef} 
          canvasRef={canvasRef} 
          isVisible={isVisionActive} 
          isScanning={isDeepScanning} 
          isMuted={isMuted} 
          isPrivacyActive={bossProfile.isHideMode && !bossProfile.isVerified}
        />
        <CoreVisualization status={status} />
      </div>

      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-12 gap-8 z-10">
        <ChatLog messages={messages} />
        <div className="flex items-center gap-14">
          <button onClick={() => setIsVisionActive(!isVisionActive)} className={`p-6 rounded-full border transition-all duration-700 ${isVisionActive ? 'border-rose-400 text-rose-400 bg-rose-400/5 shadow-[0_0_50px_rgba(244,63,94,0.2)]' : 'border-white/5 text-gray-600 hover:border-white/20 hover:text-gray-400'}`} title="Neural Sight">
            <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
          </button>

          <MicButton isActive={isLive} onClick={toggleCore} />

          <div className="flex flex-col items-center min-w-[80px]">
            {isLive ? (
              <div className="flex flex-col items-center animate-in fade-in duration-1000">
                <div className={`w-1.5 h-1.5 rounded-full mb-2 ${status === 'ERROR' ? 'bg-red-500 animate-pulse' : !bossProfile.isVerified ? 'bg-orange-400' : 'bg-green-400'}`}></div>
                <span className={`text-[0.55rem] font-black uppercase tracking-[0.3em] ${status === 'ERROR' ? 'text-red-500' : !bossProfile.isVerified ? 'text-orange-400' : 'text-green-400'}`}>
                  {status === 'ERROR' ? 'NETWORK SYNC FAIL' : !bossProfile.isVerified ? 'UNBONDED' : 'LIVE LINK'}
                </span>
              </div>
            ) : (
              <span className="text-[0.55rem] text-white/20 font-black uppercase tracking-[0.3em]">OFFLINE</span>
            )}
          </div>
        </div>
      </div>

      {bossProfile.isVerified && bossProfile.securityLog.length > 0 && (
        <div className="absolute right-6 top-24 w-80 max-h-[65vh] overflow-y-auto bg-black/60 border border-rose-500/10 p-6 rounded-[2rem] backdrop-blur-3xl z-40 transition-all duration-700 custom-scrollbar shadow-[0_32px_64px_-12px_rgba(0,0,0,0.8)]">
           <div className="flex justify-between items-center mb-6 border-b border-white/5 pb-4">
             <div className="flex flex-col">
                <h3 className="text-rose-400 text-[0.7rem] font-black uppercase tracking-[0.4em]">Environmental Memory</h3>
                <span className="text-[0.45rem] text-gray-500 uppercase tracking-widest italic">Captured by Turbo</span>
             </div>
             <button onClick={() => setBossProfile(p => ({ ...p, securityLog: [] }))} className="p-2 hover:bg-rose-500/10 rounded-full transition-colors group">
               <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-gray-600 group-hover:text-rose-400 transition-colors"><path d="M3 6h18m-2 0v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6m3 0V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"></path></svg>
             </button>
           </div>
           <div className="flex flex-col gap-8">
             {bossProfile.securityLog.map(log => (
               <div key={log.id} className="relative pl-2 group">
                 <div className="flex justify-between items-start mb-2">
                   <span className="text-[0.55rem] text-gray-500 font-mono font-bold tracking-tighter">{new Date(log.timestamp).toLocaleTimeString()}</span>
                 </div>
                 <p className="text-[0.8rem] text-gray-300 leading-relaxed font-medium mb-3 group-hover:text-rose-100 transition-colors">{log.description}</p>
                 {log.capturedImage && (
                   <div className="mt-4 relative overflow-hidden rounded-2xl border border-white/5 group-hover:border-rose-500/20 transition-all duration-500">
                     <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="w-full h-32 object-cover opacity-40 group-hover:opacity-100 group-hover:scale-105 transition-all duration-700" alt="Memory" />
                   </div>
                 )}
               </div>
             ))}
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 2px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(244, 63, 94, 0.1); border-radius: 10px; }
      `}</style>
    </div>
  );
};

