        const updated = prev.map(m => 
          m.id === activeIdRef.current 
            ? { ...m, text: sanitizedText, isInterim: !isFinal, timestamp: Date.now() } 
            : m
        );
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text: sanitizedText, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
