      console.error("Neural init failed", err);
      setStatus('ERROR');
      updateOrAddMessage("Link failure. Attempting reconnection...", 'system', true);
    }
  };

  const toggleCore = async () => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
      await startSession();
    } else {
      stopLiveSession();
      setIsLive(false);
      setIsVisionActive(false);
      setStatus('STANDBY');
      activeTurboMessageId.current = null;
      activeUserMessageId.current = null;
    }
  };

