    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(168,85,247,0.1)_0%,transparent_70%)]"></div>
        <div className="relative mb-12 text-center">
          <h1 className="holo-text text-8xl text-white tracking-[0.2em] font-black">TURBO</h1>
          <div className="text-[0.6rem] text-rose-500 font-bold tracking-[0.8em] uppercase mt-2">Always Active Core</div>
        </div>
        <button onClick={() => setIsInitialized(true)} className="group relative border border-rose-500/30 px-32 py-10 text-xl text-rose-400 hover:text-white transition-all overflow-hidden rounded-full backdrop-blur-md">
          <div className="absolute inset-0 bg-rose-500/10 translate-y-full group-hover:translate-y-0 transition-transform duration-700"></div>
          <span className="relative z-10 font-black tracking-[0.5em] uppercase">Connect Neural Link</span>
        </button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-all duration-1000 ${isMuted ? 'bg-rose-950/10' : 'bg-[#030303]'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed 
          videoRef={videoRef} 
          canvasRef={canvasRef} 
          isVisible={isVisionActive} 
          isScanning={isDeepScanning} 
          isMuted={isMuted} 
          isPrivacyActive={bossProfile.isHideMode && !bossProfile.isVerified}
        />
        <CoreVisualization status={status} />

        <div className={`fixed inset-0 bg-white transition-opacity duration-200 pointer-events-none z-[100] ${showShutter ? 'opacity-30' : 'opacity-0'}`}></div>
      </div>

      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-14 gap-10 z-10">
        <ChatLog messages={messages} />

        <div className="flex items-center gap-16">
          <div className="flex gap-6">
            <button 
              onClick={() => setIsVisionActive(!isVisionActive)} 
              className={`p-7 rounded-full border transition-all duration-700 ${isVisionActive ? 'border-rose-400 text-rose-400 bg-rose-400/5 shadow-[0_0_40px_rgba(244,63,94,0.15)]' : 'border-white/5 text-gray-700 hover:border-white/20 hover:text-gray-400'}`} 
              title="Toggle Vision"
            >
