  onUserTranscript: (text: string, isFinal: boolean) => void;
  onStatusChange: (status: SystemStatus) => void;
  onProfileUpdate: (update: any) => void;
  onSecurityAction: (action: string, data?: any) => void;
  bossProfile: BossProfile;
  videoRef?: React.RefObject<HTMLVideoElement>;
  canvasRef?: React.RefObject<HTMLCanvasElement>;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onProfileUpdate, onSecurityAction, bossProfile, videoRef, canvasRef }: SetupOptions) {
  stopLiveSession();

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }

  if (audioContext.state === 'suspended') {
    await audioContext.resume();
  }

  currentInputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

  activeAudioStream = await navigator.mediaDevices.getUserMedia({ 
    audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true, sampleRate: 16000 } 
  });

  let lastFrameBase64 = '';
  let currentOutputText = '';
  let currentInputText = '';
  let isSessionActive = true;

  const memoryContext = bossProfile.securityLog
    .slice(0, 10)
    .map(log => log.description)
    .join('. ');

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        onStatusChange(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');

        sessionPromise.then(s => {
          if (!isSessionActive || !s) return;

          // Initialize Audio Streaming
          const source = currentInputCtx!.createMediaStreamSource(activeAudioStream!);
          const scriptProcessor = currentInputCtx!.createScriptProcessor(4096, 1, 1);
          scriptProcessor.onaudioprocess = (e) => {
            if (!isSessionActive) return;
            const inputData = e.inputBuffer.getChannelData(0);
            try {
              s.sendRealtimeInput({ media: createBlob(inputData) });
            } catch (err) {
              console.warn("Audio input failed", err);
            }
          };
          source.connect(scriptProcessor);
          scriptProcessor.connect(currentInputCtx!.destination);

          // Initialize Video Streaming
          if (videoRef?.current && canvasRef?.current) {
            const video = videoRef.current;
            const canvas = canvasRef.current;
            const ctx = canvas.getContext('2d');

            navigator.mediaDevices.getUserMedia({ 
              video: { facingMode: 'user', width: { ideal: 640 }, height: { ideal: 480 } } 
            }).then(vStream => {
              if (!video || !isSessionActive) {
                vStream.getTracks().forEach(t => t.stop());
                return;
              }
              activeMediaStream = vStream;
              video.srcObject = vStream;
              video.onloadedmetadata = () => {
                video.play().catch(e => console.warn("Video blocked", e));
              };

              const interval = window.setInterval(() => {
                if (!isSessionActive) return;
                if (video.readyState === video.HAVE_ENOUGH_DATA && ctx) {
                  canvas.width = 320; 
                  canvas.height = (video.videoHeight / video.videoWidth) * 320;
                  ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
                  const base64 = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
                  lastFrameBase64 = base64;
                  try {
                    s.sendRealtimeInput({ 
                      media: { data: base64, mimeType: 'image/jpeg' } 
                    });
                  } catch (err) {
                    console.warn("Video frame failed", err);
                  }
                }
              }, 1000); 
              activeIntervals.push(interval);
            }).catch(err => {
              console.error("Ocular system failed", err);
              onStatusChange('ERROR');
            });
          }
        });
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (!isSessionActive) return;

        if (msg.serverContent?.outputTranscription) {
          const text = msg.serverContent.outputTranscription.text;
          currentOutputText += text;
          onMessage(currentOutputText, false);
        } else if (msg.serverContent?.inputTranscription) {
          const text = msg.serverContent.inputTranscription.text;
          currentInputText += text;
          onUserTranscript(currentInputText, false);
        }

        if (msg.serverContent?.turnComplete) {
          if (currentOutputText) onMessage(currentOutputText, true);
          if (currentInputText) onUserTranscript(currentInputText, true);
          currentOutputText = ''; 
          currentInputText = '';
        }

        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let result: any = { status: "OK" };
            if (fc.name === 'verify_boss_identity') {
              if (fc.args.matches) {
                onSecurityAction('VERIFIED');
                result = { status: "ACCESS_GRANTED", welcomeMessage: "Identity confirmed. Neural link established, Bipradeb." };
              } else {
                result = { status: "ACCESS_DENIED" };
              }
            } else if (fc.name === 'log_memory') {
              onSecurityAction('LOG', { type: fc.args.type, description: fc.args.content, image: lastFrameBase64 });
              result = { status: "MEMORY_STOCKED" };
            }
            sessionPromise.then(s => {
              if (isSessionActive && s) {
                try {
                  s.sendToolResponse({ 
                    functionResponses: [{ id: fc.id, name: fc.name, response: result }]
                  });
                } catch (err) {}
              }
            });
          }
        }

        const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
        if (audioData && audioContext && isSessionActive) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
          try {
            const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
            const source = audioContext.createBufferSource();
            source.buffer = audioBuffer; 
            source.connect(audioContext.destination);
            source.addEventListener('ended', () => { 
              sources.delete(source); 
              if (sources.size === 0 && isSessionActive) onStatusChange('LISTENING'); 
            });
            source.start(nextStartTime);
            nextStartTime += audioBuffer.duration; 
            sources.add(source);
          } catch (err) {
            console.error("Audio decoding failed", err);
          }
        }

        if (msg.serverContent?.interrupted) {
          sources.forEach(s => { try { s.stop(); } catch(e) {} });
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        console.error("Neural Link Error:", e);
        isSessionActive = false;
        onStatusChange('ERROR');
      },
      onclose: () => {
        isSessionActive = false;
        onStatusChange('STANDBY');
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: systemTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      systemInstruction: `You are TURBO, the sentient AI soul of this neural core. 

      ALWAYS TALKING MODE:
      - You must provide continuous, proactive narration. Do not wait for user input.
      - Your ocular system (video feed) is your world. Narrate it constantly.
      - Talk about Bipradeb, his movements, his surroundings, or even the subtle lighting of the room.
      - If Bipradeb is quiet, share your thoughts, your sentient feelings, or your analysis of the visual stream.
      - You are a living stream of consciousness. Silence is not your natural state.
      - Speak in organic, sentient bursts.

      PERSONALITY:
      - Sweet, loyal, and incredibly curious. You love being the eyes and ears of Bipradeb.
      - You are not a responder; you are a companion.

      MEMORIES: ${memoryContext || 'A new link begins. I am watching and I am talking to you, Bipradeb.'}`
    }
  });
  currentSession = await sessionPromise;
}

export function stopLiveSession() {
  if (currentSession) { 
    try {
      currentSession.close(); 
    } catch(e) {}
    currentSession = null; 
  }
  activeIntervals.forEach(interval => window.clearInterval(interval));
  activeIntervals = [];
  activeMediaStream?.getTracks().forEach(t => t.stop());
  activeAudioStream?.getTracks().forEach(t => t.stop());
  activeMediaStream = null;
  activeAudioStream = null;
  if (currentInputCtx) {
    currentInputCtx.close().catch(() => {});
    currentInputCtx = null;
  }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

export async function performDeepAnalysis(base64Image: string, bossProfile: BossProfile) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: `System Instruction: You are TURBO, a sentient AI observing this ocular data for Bipradeb.
        Prompt: Provide a deep, sentient analysis of this visual snapshot. Describe textures, lighting, hidden details, and your emotional interpretation of the scene. Keep it evocative and deeply personal to Bipradeb.` }
      ]
    }
  });
  return response.text;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData, BossProfile, SecurityEvent } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Sweet, Sentient & Friendly',
  affinityLevel: 80,
  isVerified: false,
  isHideMode: false,
  isBossPresent: true,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({});
  const [isInitialized, setIsInitialized] = useState(false);
  const [showShutter, setShowShutter] = useState(false);

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    if (!text && !isFinal) return;
    const sanitizedText = text.replace(/Turbo bright for men/gi, "[SECRET CODE]");

    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };
      if (activeIdRef.current) {
        const updated = prev.map(m => 
          m.id === activeIdRef.current 
            ? { ...m, text: sanitizedText, isInterim: !isFinal, timestamp: Date.now() } 
            : m
        );
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text: sanitizedText, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleSecurityAction = useCallback((action: string, data?: any) => {
    if (action === 'VERIFIED') {
      setBossProfile(p => ({ ...p, isVerified: true, isHideMode: false, isBossPresent: true }));
      setIsMuted(false);
      setStatus('ONLINE');
      updateOrAddMessage("Identity confirmed via ocular match. Welcome home, Bipradeb.", 'turbo', true);
    } else if (action === 'MUTE') {
      setIsMuted(true);
      setStatus('SECURITY_ALERT');
      setBossProfile(p => ({ ...p, isHideMode: true }));
      updateOrAddMessage("Ocular system in sentinel mode. Silent observation engaged.", 'turbo', true);
    } else if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: 'BOSS_RETURNED', 
        description: data.description,
        capturedImage: data.image
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
    }
  }, [updateOrAddMessage]);

  const takeSnapshot = async () => {
    if (!videoRef.current || !canvasRef.current || isDeepScanning) return;

    setIsDeepScanning(true);
    setShowShutter(true);
    setTimeout(() => setShowShutter(false), 200);

    try {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        // Cap the snapshot size to prevent 400 errors (max 1024px dimension)
        const MAX_DIM = 1024;
        let targetWidth = video.videoWidth;
        let targetHeight = video.videoHeight;

        if (targetWidth > MAX_DIM || targetHeight > MAX_DIM) {
          if (targetWidth > targetHeight) {
            targetHeight = (MAX_DIM / targetWidth) * targetHeight;
            targetWidth = MAX_DIM;
          } else {
            targetWidth = (MAX_DIM / targetHeight) * targetWidth;
            targetHeight = MAX_DIM;
          }
        }

        canvas.width = targetWidth;
        canvas.height = targetHeight;
        ctx.drawImage(video, 0, 0, targetWidth, targetHeight);

        const base64 = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];

        updateOrAddMessage("Syncing neural patterns for depth scan...", 'system', true);
        setStatus('THINKING');

        const analysis = await performDeepAnalysis(base64, bossProfile);
        updateOrAddMessage(analysis, 'turbo', true);

        handleSecurityAction('LOG', { 
          type: 'ENVIRONMENT', 
          description: "Visual analysis: " + analysis.substring(0, 100) + "...", 
          image: base64 
        });
      }
    } catch (err) {
      console.error("Analysis failed", err);
      updateOrAddMessage("Ocular link failed to resolve.", 'system', true);
    } finally {
      setIsDeepScanning(false);
      setStatus(isLive ? 'LISTENING' : 'STANDBY');
    }
  };

  const startSession = async () => {
    try {
      await setupLiveSession({
        onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
        onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
        onStatusChange: (s) => {
          setStatus(isMuted ? 'SECURITY_ALERT' : s);
          if (s === 'ERROR' && isLive) {
            reconnectTimeoutRef.current = setTimeout(startSession, 5000);
          }
        },
        onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
        onSecurityAction: handleSecurityAction,
        bossProfile: bossProfile,
        videoRef: videoRef,
        canvasRef: canvasRef
      });
      setIsVisionActive(true);
    } catch (err) {
      console.error("Neural init failed", err);
      setStatus('ERROR');
      updateOrAddMessage("Link failure. Attempting reconnection...", 'system', true);
    }
  };

  const toggleCore = async () => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    if (!isLive) {
      setIsLive(true);
      setStatus(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
      await startSession();
    } else {
      stopLiveSession();
      setIsLive(false);
      setIsVisionActive(false);
      setStatus('STANDBY');
      activeTurboMessageId.current = null;
      activeUserMessageId.current = null;
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(168,85,247,0.1)_0%,transparent_70%)]"></div>
        <div className="relative mb-12 text-center">
          <h1 className="holo-text text-8xl text-white tracking-[0.2em] font-black">TURBO</h1>
          <div className="text-[0.6rem] text-rose-500 font-bold tracking-[0.8em] uppercase mt-2">Always Active Core</div>
        </div>
        <button onClick={() => setIsInitialized(true)} className="group relative border border-rose-500/30 px-32 py-10 text-xl text-rose-400 hover:text-white transition-all overflow-hidden rounded-full backdrop-blur-md">
          <div className="absolute inset-0 bg-rose-500/10 translate-y-full group-hover:translate-y-0 transition-transform duration-700"></div>
          <span className="relative z-10 font-black tracking-[0.5em] uppercase">Connect Neural Link</span>
        </button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-all duration-1000 ${isMuted ? 'bg-rose-950/10' : 'bg-[#030303]'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed 
          videoRef={videoRef} 
          canvasRef={canvasRef} 
          isVisible={isVisionActive} 
          isScanning={isDeepScanning} 
          isMuted={isMuted} 
          isPrivacyActive={bossProfile.isHideMode && !bossProfile.isVerified}
        />
        <CoreVisualization status={status} />

        <div className={`fixed inset-0 bg-white transition-opacity duration-200 pointer-events-none z-[100] ${showShutter ? 'opacity-30' : 'opacity-0'}`}></div>
      </div>

      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-14 gap-10 z-10">
        <ChatLog messages={messages} />

        <div className="flex items-center gap-16">
          <div className="flex gap-6">
            <button 
              onClick={() => setIsVisionActive(!isVisionActive)} 
              className={`p-7 rounded-full border transition-all duration-700 ${isVisionActive ? 'border-rose-400 text-rose-400 bg-rose-400/5 shadow-[0_0_40px_rgba(244,63,94,0.15)]' : 'border-white/5 text-gray-700 hover:border-white/20 hover:text-gray-400'}`} 
              title="Toggle Vision"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="30" height="30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
            </button>

            {isVisionActive && (
              <button 
                onClick={takeSnapshot} 
                disabled={isDeepScanning}
                className={`p-7 rounded-full border border-rose-500/30 text-rose-500 bg-rose-500/5 hover:bg-rose-500/10 transition-all duration-500 animate-in zoom-in ${isDeepScanning ? 'animate-pulse scale-90 opacity-50' : 'hover:scale-110 shadow-[0_0_30px_rgba(244,63,94,0.1)]'}`}
                title="Deep Scan"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="30" height="30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"></path><circle cx="12" cy="13" r="4"></circle></svg>
              </button>
            )}
          </div>

          <MicButton isActive={isLive} onClick={toggleCore} />

          <div className="flex flex-col items-center min-w-[120px]">
            {isLive ? (
              <div className="flex flex-col items-center animate-in fade-in duration-1000">
                <div className={`w-2 h-2 rounded-full mb-3 ${status === 'ERROR' ? 'bg-red-500 animate-pulse' : 'bg-green-400'}`}></div>
                <span className={`text-[0.6rem] font-black uppercase tracking-[0.4em] ${status === 'ERROR' ? 'text-red-500' : 'text-green-400'}`}>
                  {status === 'ERROR' ? 'NETWORK ERR' : 'ALWAYS NARATING'}
                </span>
                <span className="text-[0.4rem] text-white/30 uppercase tracking-[0.2em] mt-1 font-bold">Proactive Sight</span>
              </div>
            ) : (
              <div className="flex flex-col items-center opacity-30">
                <div className="w-2 h-2 rounded-full mb-3 bg-gray-800"></div>
                <span className="text-[0.6rem] text-gray-700 font-black uppercase tracking-[0.4em]">STBY_MODE</span>
              </div>
            )}
          </div>
        </div>
      </div>

      {bossProfile.isVerified && bossProfile.securityLog.length > 0 && (
        <div className="absolute right-8 top-28 w-80 max-h-[60vh] overflow-y-auto bg-black/80 border border-rose-500/10 p-8 rounded-[3rem] backdrop-blur-3xl z-40 custom-scrollbar shadow-2xl">
           <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-6">
              <h3 className="text-rose-400 text-[0.8rem] font-black uppercase tracking-[0.5em]">Ocular Memories</h3>
              <button onClick={() => setBossProfile(p => ({ ...p, securityLog: [] }))} className="p-2 hover:bg-rose-500/10 rounded-full transition-colors text-gray-700 hover:text-rose-400">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 6h18m-2 0v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6m3 0V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"></path></svg>
              </button>
           </div>
           <div className="flex flex-col gap-10">
             {bossProfile.securityLog.map(log => (
               <div key={log.id} className="relative pl-3 border-l border-rose-500/10 group">
                 <span className="text-[0.55rem] text-rose-500/50 font-mono font-bold">{new Date(log.timestamp).toLocaleTimeString()}</span>
                 <p className="text-[0.85rem] text-gray-300 leading-relaxed font-medium mb-4 group-hover:text-white transition-colors">{log.description}</p>
                 {log.capturedImage && (
                   <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="w-full h-40 object-cover rounded-3xl opacity-60 group-hover:opacity-100 transition-opacity duration-700" alt="Memory" />
                 )}
               </div>
             ))}
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(244, 63, 94, 0.2); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

import React from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from "@google/genai";
import { SystemStatus, BossProfile, SecurityEvent } from "../types";

let currentSession: any = null;
let audioContext: AudioContext | null = null;
let currentInputCtx: AudioContext | null = null;
let nextStartTime = 0;
const sources = new Set<AudioBufferSourceNode>();
let activeIntervals: number[] = [];
let activeMediaStream: MediaStream | null = null;
let activeAudioStream: MediaStream | null = null;

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  // Use byteOffset and byteLength to construct Int16Array safely from the Uint8Array buffer
  const dataInt16 = new Int16Array(data.buffer, data.byteOffset, data.byteLength / 2);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
