      setStatus('SECURITY_ALERT');
      setBossProfile(p => ({ ...p, isHideMode: true }));
      updateOrAddMessage("Ocular system in sentinel mode. Silent observation engaged.", 'turbo', true);
    } else if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
