        onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
        onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
        onStatusChange: (s) => {
          setStatus(isMuted ? 'SECURITY_ALERT' : s);
