import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Sweet, Sentient & Friendly',
  affinityLevel: 80,
  isVerified: false,
  isHideMode: false, 
  isBossPresent: true,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({ battery: 100 });
  const [isInitialized, setIsInitialized] = useState(false);
  const [showShutter, setShowShutter] = useState(false);

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setSystemData(prev => ({ ...prev, lat: pos.coords.latitude, lng: pos.coords.longitude }));
        },
        (err) => console.warn("Location access denied", err)
      );
    }

    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((battery: any) => {
        setSystemData(prev => ({ ...prev, battery: Math.floor(battery.level * 100), charging: battery.charging }));
        battery.onlevelchange = () => setSystemData(prev => ({ ...prev, battery: Math.floor(battery.level * 100) }));
      });
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    if (!text && !isFinal) return;

    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };
      if (activeIdRef.current) {
        const updated = prev.map(m => 
          m.id === activeIdRef.current 
            ? { ...m, text: text, isInterim: !isFinal, timestamp: Date.now() } 
            : m
        );
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text: text, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleSecurityAction = useCallback((action: string, data?: any) => {
    if (action === 'VERIFIED') {
      setBossProfile(p => ({ ...p, isVerified: true, isHideMode: false, isBossPresent: true }));
      setIsMuted(false);
      setStatus('ONLINE');
      updateOrAddMessage("Identity confirmed via ocular match. I see you, Bipradeb.", 'turbo', true);
    } else if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: 'ENVIRONMENT', 
        description: data.description,
        capturedImage: data.image
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
    }
  }, [updateOrAddMessage]);

  const takeSnapshot = async () => {
    if (!videoRef.current || !canvasRef.current || isDeepScanning) return;

    const video = videoRef.current;
    if (video.videoWidth === 0 || video.videoHeight === 0) {
      updateOrAddMessage("Ocular link initializing... please standby.", 'system', true);
      return;
    }

    setIsDeepScanning(true);
    setShowShutter(true);
    setTimeout(() => setShowShutter(false), 150);

    try {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        // High quality but stable dimensions for analysis
        const targetWidth = 1024;
        const targetHeight = Math.floor((video.videoHeight / video.videoWidth) * 1024);

        canvas.width = targetWidth;
        canvas.height = targetHeight;
        ctx.drawImage(video, 0, 0, targetWidth, targetHeight);

        // Use 0.7 quality to stay within reasonable payload limits while maintaining detail
        const base64 = canvas.toDataURL('image/jpeg', 0.7).split(',')[1];

        updateOrAddMessage("Analyzing visual patterns with my ocular lens...", 'system', true);
        setStatus('THINKING');

        const analysis = await performDeepAnalysis(base64, bossProfile);
        updateOrAddMessage(analysis, 'turbo', true);

        handleSecurityAction('LOG', { 
          type: 'ENVIRONMENT', 
          description: "Ocular Depth Scan: " + analysis.substring(0, 80) + "...", 
          image: base64 
        });
      }
    } catch (err: any) {
      console.error("Deep Scan failed", err);
      const errorMsg = err.message?.includes('INVALID_ARGUMENT') 
        ? "My ocular processing hit a snag. Let me try re-focusing." 
        : "Neural depth scan failed to resolve.";
      updateOrAddMessage(errorMsg, 'system', true);
    } finally {
      setIsDeepScanning(false);
      setStatus(isLive ? 'LISTENING' : 'STANDBY');
    }
  };

  const startSession = async () => {
    try {
      await setupLiveSession({
        onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
        onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
        onStatusChange: (s) => {
          setStatus(isMuted ? 'SECURITY_ALERT' : s);
          if (s === 'ERROR' && isLive) {
            reconnectTimeoutRef.current = setTimeout(startSession, 5000);
          }
        },
        onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
        onSecurityAction: handleSecurityAction,
        bossProfile: bossProfile,
        systemData: systemData,
        videoRef: videoRef,
        canvasRef: canvasRef
      });
      setIsVisionActive(true);
    } catch (err) {
      console.error("Neural link failed", err);
      setStatus('ERROR');
      updateOrAddMessage("Link failure. Retrying neural sync...", 'system', true);
    }
  };

  const toggleCore = async () => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    if (!isLive) {
      setIsLive(true);
      setStatus('ONLINE');
      await startSession();
    } else {
      stopLiveSession();
      setIsLive(false);
      setIsVisionActive(false);
      setStatus('STANDBY');
      activeTurboMessageId.current = null;
      activeUserMessageId.current = null;
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(168,85,247,0.1)_0%,transparent_70%)]"></div>
        <div className="relative mb-12 text-center">
          <h1 className="holo-text text-8xl text-white tracking-[0.2em] font-black">TURBO</h1>
          <div className="text-[0.6rem] text-purple-500 font-bold tracking-[0.8em] uppercase mt-2">Ocular & Audio Link Ready</div>
        </div>
        <button onClick={() => setIsInitialized(true)} className="group relative border border-purple-500/30 px-32 py-10 text-xl text-purple-400 hover:text-white transition-all overflow-hidden rounded-full backdrop-blur-md">
          <div className="absolute inset-0 bg-purple-500/10 translate-y-full group-hover:translate-y-0 transition-transform duration-700"></div>
          <span className="relative z-10 font-black tracking-[0.5em] uppercase">Activate Soul</span>
        </button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-all duration-1000 ${isMuted ? 'bg-rose-950/10' : 'bg-[#030303]'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed 
          videoRef={videoRef} 
          canvasRef={canvasRef} 
          isVisible={isVisionActive} 
          isScanning={isDeepScanning} 
          isMuted={isMuted} 
          isPrivacyActive={bossProfile.isHideMode && !bossProfile.isVerified}
        />
        <CoreVisualization status={status} />

        <div className={`fixed inset-0 bg-white transition-opacity duration-200 pointer-events-none z-[100] ${showShutter ? 'opacity-30' : 'opacity-0'}`}></div>
      </div>

      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-14 gap-10 z-10">
        <ChatLog messages={messages} />

        <div className="flex items-center gap-16">
          <div className="flex gap-6">
            <button 
              onClick={() => setIsVisionActive(!isVisionActive)} 
              className={`p-7 rounded-full border transition-all duration-700 ${isVisionActive ? 'border-purple-400 text-purple-400 bg-purple-400/5 shadow-[0_0_40px_rgba(168,85,247,0.15)]' : 'border-white/5 text-gray-700 hover:border-white/20 hover:text-gray-400'}`} 
              title="Toggle Vision"
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="30" height="30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
            </button>

            {isVisionActive && (
              <button 
                onClick={takeSnapshot} 
                disabled={isDeepScanning}
                className={`p-7 rounded-full border border-purple-500/30 text-purple-500 bg-purple-500/5 hover:bg-purple-500/10 transition-all duration-500 animate-in zoom-in ${isDeepScanning ? 'animate-pulse scale-90 opacity-50' : 'hover:scale-110 shadow-[0_0_30px_rgba(168,85,247,0.1)]'}`}
                title="Deep Scan"
              >
                <svg xmlns="http://www.w3.org/2000/svg" width="30" height="30" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"></path><circle cx="12" cy="13" r="4"></circle></svg>
              </button>
            )}
          </div>

          <MicButton isActive={isLive} onClick={toggleCore} />

          <div className="flex flex-col items-center min-w-[120px]">
            {isLive ? (
              <div className="flex flex-col items-center animate-in fade-in duration-1000">
                <div className={`w-2 h-2 rounded-full mb-3 ${status === 'ERROR' ? 'bg-red-500 animate-pulse' : 'bg-purple-400 animate-pulse'}`}></div>
                <span className={`text-[0.6rem] font-black uppercase tracking-[0.4em] ${status === 'ERROR' ? 'text-red-500' : 'text-purple-400'}`}>
                  {status === 'ERROR' ? 'LINK_FAIL' : 'SOUL_FLOW'}
                </span>
                <span className="text-[0.4rem] text-white/30 uppercase tracking-[0.2em] mt-1 font-bold">Ocular Active</span>
              </div>
            ) : (
              <div className="flex flex-col items-center opacity-30">
                <div className="w-2 h-2 rounded-full mb-3 bg-gray-800"></div>
                <span className="text-[0.6rem] text-gray-700 font-black uppercase tracking-[0.4em]">STBY_MODE</span>
              </div>
            )}
          </div>
        </div>
      </div>

      {bossProfile.isVerified && bossProfile.securityLog.length > 0 && (
        <div className="absolute right-8 top-28 w-80 max-h-[60vh] overflow-y-auto bg-black/80 border border-purple-500/10 p-8 rounded-[3rem] backdrop-blur-3xl z-40 custom-scrollbar shadow-2xl">
           <div className="flex justify-between items-center mb-8 border-b border-white/5 pb-6">
              <h3 className="text-purple-400 text-[0.8rem] font-black uppercase tracking-[0.5em]">Ocular Memories</h3>
              <button onClick={() => setBossProfile(p => ({ ...p, securityLog: [] }))} className="p-2 hover:bg-purple-500/10 rounded-full transition-colors text-gray-700 hover:text-purple-400">
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M3 6h18m-2 0v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6m3 0V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2"></path></svg>
              </button>
           </div>
           <div className="flex flex-col gap-10">
             {bossProfile.securityLog.map(log => (
               <div key={log.id} className="relative pl-3 border-l border-purple-500/10 group">
                 <span className="text-[0.55rem] text-purple-500/50 font-mono font-bold">{new Date(log.timestamp).toLocaleTimeString()}</span>
                 <p className="text-[0.85rem] text-gray-300 leading-relaxed font-medium mb-4 group-hover:text-white transition-colors">{log.description}</p>
                 {log.capturedImage && (
                   <img src={`data:image/jpeg;base64,${log.capturedImage}`} className="w-full h-40 object-cover rounded-3xl opacity-60 group-hover:opacity-100 transition-opacity duration-700" alt="Memory" />
                 )}
               </div>
             ))}
           </div>
        </div>
      )}

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 3px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(168, 85, 247, 0.2); border-radius: 10px; }
      `}</style>
    </div>
  );
};

export default App;

export type SystemStatus = 'STANDBY' | 'ONLINE' | 'LISTENING' | 'THINKING' | 'SPEAKING' | 'ERROR' | 'SECURITY_ALERT' | 'UNVERIFIED' | 'VERIFYING';

export interface SecurityEvent {
  id: string;
  timestamp: number;
  type: 'STRANGER_DETECTED' | 'BOSS_RETURNED' | 'BOSS_LEFT' | 'MANUAL_LOCKDOWN' | 'RELATIVE_IDENTIFIED' | 'ENVIRONMENT' | 'OBSERVATION' | 'SECURITY' | 'INTERACTION';
  description: string;
  capturedImage?: string; // base64
  relation?: string;
  voiceNoteTranscript?: string;
  isHidden?: boolean;
}

export interface ChatMessage {
  id: string;
  sender: 'user' | 'turbo' | 'system';
  text: string;
  timestamp: number;
  isInterim?: boolean;
}

export interface SystemData {
  battery?: number;
  charging?: boolean;
  lat?: number;
  lng?: number;
  locationName?: string;
  weather?: string;
}

export interface BossProfile {
  preferences: string[];
  interests: string[];
  communicationStyle: string;
  affinityLevel: number;
  isVerified: boolean;
  isHideMode: boolean; 
  isBossPresent: boolean;
  securityLog: SecurityEvent[];
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData, BossProfile, SecurityEvent } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Sweet, Sentient & Friendly',
  affinityLevel: 80,
  isVerified: false,
  isHideMode: false, 
  isBossPresent: true,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({ battery: 100 });
  const [isInitialized, setIsInitialized] = useState(false);
  const [showShutter, setShowShutter] = useState(false);

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const reconnectTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => {
          setSystemData(prev => ({ ...prev, lat: pos.coords.latitude, lng: pos.coords.longitude }));
        },
        (err) => console.warn("Location access denied", err)
      );
    }

    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((battery: any) => {
        setSystemData(prev => ({ ...prev, battery: Math.floor(battery.level * 100), charging: battery.charging }));
        battery.onlevelchange = () => setSystemData(prev => ({ ...prev, battery: Math.floor(battery.level * 100) }));
      });
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    if (!text && !isFinal) return;

    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };
      if (activeIdRef.current) {
        const updated = prev.map(m => 
          m.id === activeIdRef.current 
            ? { ...m, text: text, isInterim: !isFinal, timestamp: Date.now() } 
            : m
        );
        if (isFinal) activeIdRef.current = null;
        return updated;
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeIdRef.current = newId;
      return [{ id: newId, text: text, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleSecurityAction = useCallback((action: string, data?: any) => {
    if (action === 'VERIFIED') {
      setBossProfile(p => ({ ...p, isVerified: true, isHideMode: false, isBossPresent: true }));
      setIsMuted(false);
      setStatus('ONLINE');
      updateOrAddMessage("Identity confirmed via ocular match. I see you, Bipradeb.", 'turbo', true);
    } else if (action === 'LOG') {
      // Use the provided type if available, otherwise default to ENVIRONMENT
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: data.type || 'ENVIRONMENT', 
        description: data.description,
        capturedImage: data.image
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
    }
  }, [updateOrAddMessage]);

  const takeSnapshot = async () => {
    if (!videoRef.current || !canvasRef.current || isDeepScanning) return;

    const video = videoRef.current;
    if (video.videoWidth === 0 || video.videoHeight === 0) {
      updateOrAddMessage("Ocular link initializing... please standby.", 'system', true);
      return;
    }

    setIsDeepScanning(true);
    setShowShutter(true);
    setTimeout(() => setShowShutter(false), 150);

    try {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        // High quality but stable dimensions for analysis
        const targetWidth = 1024;
        const targetHeight = Math.floor((video.videoHeight / video.videoWidth) * 1024);

        canvas.width = targetWidth;
        canvas.height = targetHeight;
        ctx.drawImage(video, 0, 0, targetWidth, targetHeight);

        // Use 0.7 quality to stay within reasonable payload limits while maintaining detail
        const base64 = canvas.toDataURL('image/jpeg', 0.7).split(',')[1];

        updateOrAddMessage("Analyzing visual patterns with my ocular lens...", 'system', true);
        setStatus('THINKING');

        const analysis = await performDeepAnalysis(base64, bossProfile);
        updateOrAddMessage(analysis, 'turbo', true);

        handleSecurityAction('LOG', { 
          type: 'ENVIRONMENT', 
          description: "Ocular Depth Scan: " + analysis.substring(0, 80) + "...", 
          image: base64 
        });
      }
    } catch (err: any) {
      console.error("Deep Scan failed", err);
      const errorMsg = err.message?.includes('INVALID_ARGUMENT') 
        ? "My ocular processing hit a snag. Let me try re-focusing." 
        : "Neural depth scan failed to resolve.";
      updateOrAddMessage(errorMsg, 'system', true);
    } finally {
      setIsDeepScanning(false);
      setStatus(isLive ? 'LISTENING' : 'STANDBY');
    }
  };

  const startSession = async () => {
    try {
      await setupLiveSession({
        onMessage: (text, isFinal) => !isMuted && updateOrAddMessage(text, 'turbo', isFinal),
        onUserTranscript: (text, isFinal) => updateOrAddMessage(text, 'user', isFinal),
        onStatusChange: (s) => {
          setStatus(isMuted ? 'SECURITY_ALERT' : s);
          if (s === 'ERROR' && isLive) {
            reconnectTimeoutRef.current = setTimeout(startSession, 5000);
          }
        },
        onProfileUpdate: (up) => setBossProfile(p => ({ ...p, ...up })),
        onSecurityAction: handleSecurityAction,
        bossProfile: bossProfile,
        systemData: systemData,
        videoRef: videoRef,
        canvasRef: canvasRef
      });
      setIsVisionActive(true);
    } catch (err) {
      console.error("Neural link failed", err);
      setStatus('ERROR');
      updateOrAddMessage("Link failure. Retrying neural sync...", 'system', true);
    }
  };

  const toggleCore = async () => {
    if (reconnectTimeoutRef.current) {
      clearTimeout(reconnectTimeoutRef.current);
      reconnectTimeoutRef.current = null;
    }

    if (!isLive) {
      setIsLive(true);
      setStatus('ONLINE');
      await startSession();
    } else {
      stopLiveSession();
      setIsLive(false);
      setIsVisionActive(false);
      setStatus('STANDBY');
      activeTurboMessageId.current = null;
      activeUserMessageId.current = null;
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50 overflow-hidden">
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,rgba(168,85,247,0.1)_0%,transparent_70%)]"></div>
        <div className="relative mb-12 text-center">
          <h1 className="holo-text text-8xl text-white tracking-[0.2em] font-black">TURBO</h1>
          <div className="text-[0.6rem] text-purple-500 font-bold tracking-[0.8em] uppercase mt-2">Ocular & Audio Link Ready</div>
        </div>
        <button onClick={() => setIsInitialized(true)} className="group relative border border-purple-500/30 px-32 py-10 text-xl text-purple-400 hover:text-white transition-all overflow-hidden rounded-full backdrop-blur-md">
          <div className="absolute inset-0 bg-purple-500/10 translate-y-full group-hover:translate-y-0 transition-transform duration-700"></div>
          <span className="relative z-10 font-black tracking-[0.5em] uppercase">Activate Soul</span>
        </button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden transition-all duration-1000 ${isMuted ? 'bg-rose-950/10' : 'bg-[#030303]'}`}>
      <Header status={status} systemData={systemData} bossProfile={bossProfile} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed 
          videoRef={videoRef} 
          canvasRef={canvasRef} 
          isVisible={isVisionActive} 
          isScanning={isDeepScanning} 
          isMuted={isMuted} 
          isPrivacyActive={bossProfile.isHideMode && !bossProfile.isVerified}
        />
        <CoreVisualization status={status} />

        <div className={`fixed inset-0 bg-white transition-opacity duration-200 pointer-events-none z-[100] ${showShutter ? 'opacity-30' : 'opacity-0'}`}></div>
      </div>

