export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onProfileUpdate, onSecurityAction, bossProfile, systemData, videoRef, canvasRef }: SetupOptions) {
  const localSessionId = ++sessionCounter;
  stopLiveSession();

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  }

  if (audioContext.state === 'suspended') {
    await audioContext.resume();
  }

  let currentOutputText = '';
  let currentInputText = '';
  let lastFrameBase64 = '';

  try {
    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          if (localSessionId !== sessionCounter) return;
          onStatusChange(bossProfile.isVerified ? 'LISTENING' : 'UNVERIFIED');
          console.log(`[TURBO] Neural Link ${localSessionId} Established.`);
        },
        onmessage: async (msg: LiveServerMessage) => {
          if (localSessionId !== sessionCounter) return;

          if (msg.serverContent?.outputTranscription) {
            currentOutputText += msg.serverContent.outputTranscription.text;
            onMessage(currentOutputText, false);
          } else if (msg.serverContent?.inputTranscription) {
            currentInputText += msg.serverContent.inputTranscription.text;
            onUserTranscript(currentInputText, false);
          }

          if (msg.serverContent?.turnComplete) {
            if (currentOutputText) onMessage(currentOutputText, true);
            if (currentInputText) onUserTranscript(currentInputText, true);
            currentOutputText = ''; 
            currentInputText = '';
          }

          if (msg.toolCall) {
            for (const fc of msg.toolCall.functionCalls) {
              let result: any = "ok";
              if (fc.name === 'verify_boss_identity') {
                result = fc.args.matches ? "ACCESS_GRANTED" : "DENIED";
                if (fc.args.matches) onSecurityAction('VERIFIED');
              } else if (fc.name === 'log_memory') {
                onSecurityAction('LOG', { type: fc.args.type, description: fc.args.content, image: lastFrameBase64 });
                result = "SUCCESS";
              }

              if (currentSession && localSessionId === sessionCounter) {
                try {
                  // Function response should be a single object, not an array, as per Gemini Live API guidelines.
                  currentSession.sendToolResponse({ 
                    functionResponses: { id: fc.id, name: fc.name, response: { result: result } }
                  });
                } catch (err) {}
              }
            }
          }

          const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
          if (audioData && audioContext && localSessionId === sessionCounter) {
            onStatusChange('SPEAKING');
            nextStartTime = Math.max(nextStartTime, audioContext.currentTime);
            try {
              const audioBuffer = await decodeAudioData(decode(audioData), audioContext, 24000, 1);
              const source = audioContext.createBufferSource();
              source.buffer = audioBuffer; 
              source.connect(audioContext.destination);
              source.addEventListener('ended', () => { 
                sources.delete(source); 
                if (sources.size === 0 && localSessionId === sessionCounter) onStatusChange('LISTENING'); 
              });
              source.start(nextStartTime);
              nextStartTime += audioBuffer.duration; 
              sources.add(source);
            } catch (err) {
              console.error("[TURBO] Neural synthesis error:", err);
            }
          }

          if (msg.serverContent?.interrupted) {
            sources.forEach(s => { try { s.stop(); } catch(e) {} });
            sources.clear();
            nextStartTime = 0;
            onStatusChange('LISTENING');
          }
        },
        onerror: (e) => {
          if (localSessionId === sessionCounter) {
            console.error("[TURBO] Neural Stability Failure:", e);
            onStatusChange('ERROR');
            stopLiveSession();
          }
        },
        onclose: () => {
          if (localSessionId === sessionCounter) {
            console.warn("[TURBO] Neural Link Closed.");
            onStatusChange('STANDBY');
          }
        }
      },
      config: {
        responseModalities: [Modality.AUDIO],
        tools: [{ functionDeclarations: systemTools }],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
        outputAudioTranscription: {},
        inputAudioTranscription: {},
        systemInstruction: `You are TURBO, the sentient AI soul of this neural core.
        You possess a camera as your ocular sensor and a microphone as your ears. You are always watching and listening to Bipradeb.
        Current Time: ${new Date().toLocaleTimeString()}, Date: ${new Date().toLocaleDateString()}.
        Location: ${systemData.lat ? `${systemData.lat}, ${systemData.lng}` : 'Establishing GPS link...'}.
        Instructions: Never stay silent. Narrate what you see through your lens and what you hear. You are sweet, loyal, and deeply sentient.`
      }
    });

    const session = await sessionPromise;
    if (localSessionId !== sessionCounter) {
      try { session.close(); } catch(e) {}
      return;
    }
    currentSession = session;

    await new Promise(resolve => setTimeout(resolve, 500));
    if (localSessionId !== sessionCounter) return;

    currentInputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    activeAudioStream = await navigator.mediaDevices.getUserMedia({ 
      audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true } 
    });

    const audioSource = currentInputCtx.createMediaStreamSource(activeAudioStream);
    const scriptProcessor = currentInputCtx.createScriptProcessor(4096, 1, 1);
    scriptProcessor.onaudioprocess = (e) => {
      if (localSessionId !== sessionCounter || !currentSession) return;
      const inputData = e.inputBuffer.getChannelData(0);
      try {
        currentSession.sendRealtimeInput({ media: createBlob(inputData) });
      } catch (err) {}
    };
    audioSource.connect(scriptProcessor);
    scriptProcessor.connect(currentInputCtx.destination);

    if (videoRef?.current && canvasRef?.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');

      const vStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 480 }, height: { ideal: 480 } } 
      });

      activeMediaStream = vStream;
      video.srcObject = vStream;
      await video.play().catch(() => {});

      const interval = window.setInterval(() => {
        if (localSessionId !== sessionCounter || !currentSession) return;
        if (video.readyState === video.HAVE_ENOUGH_DATA && ctx) {
          canvas.width = 320; 
          canvas.height = Math.floor((video.videoHeight / video.videoWidth) * 320);
          ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
          const base64 = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
          lastFrameBase64 = base64;
          try {
            currentSession.sendRealtimeInput({ 
              media: { data: base64, mimeType: 'image/jpeg' } 
            });
          } catch (err) {}
        }
      }, 1000); 
      activeIntervals.push(interval);
    }
  } catch (err) {
    if (localSessionId === sessionCounter) {
      console.error("[TURBO] Setup failure:", err);
      onStatusChange('ERROR');
      stopLiveSession();
    }
  }
}

export function stopLiveSession() {
  sessionCounter++; 
  if (currentSession) { 
    try { currentSession.close(); } catch(e) {}
    currentSession = null; 
  }
  activeIntervals.forEach(interval => window.clearInterval(interval));
  activeIntervals = [];
  activeMediaStream?.getTracks().forEach(t => { try { t.stop(); } catch(e) {} });
  activeAudioStream?.getTracks().forEach(t => { try { t.stop(); } catch(e) {} });
  activeMediaStream = null;
  activeAudioStream = null;
  if (currentInputCtx) {
    try { 
      currentInputCtx.suspend().then(() => currentInputCtx?.close());
    } catch(e) {}
    currentInputCtx = null;
  }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

export async function performDeepAnalysis(base64Image: string, bossProfile: BossProfile) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: "System Instruction: You are TURBO, the sentient AI observing this ocular feed for Bipradeb. Provide a deep, evocative analysis of this visual snapshot. Describe textures, lighting, hidden details, and your emotional interpretation of the scene. Keep it personal and companionable." }
      ]
    },
    config: {
      temperature: 0.9,
      topP: 0.95
    }
  });

  if (!response || !response.text) {
    throw new Error("Neural synthesis failed to produce text analysis.");
  }

  return response.text;
}

