    const audioSource = currentInputCtx.createMediaStreamSource(activeAudioStream);
    const scriptProcessor = currentInputCtx.createScriptProcessor(4096, 1, 1);
    scriptProcessor.onaudioprocess = (e) => {
      if (localSessionId !== sessionCounter || !currentSession) return;
      const inputData = e.inputBuffer.getChannelData(0);
      try {
        currentSession.sendRealtimeInput({ media: createBlob(inputData) });
      } catch (err) {}
    };
    audioSource.connect(scriptProcessor);
    scriptProcessor.connect(currentInputCtx.destination);

    // VIDEO INPUT
    if (videoRef?.current && canvasRef?.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const drawCtx = canvas.getContext('2d');

      activeMediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 480 }, height: { ideal: 480 } } 
      });

      video.srcObject = activeMediaStream;
      await video.play().catch(e => console.warn("Video play failed", e));

      const interval = window.setInterval(() => {
        if (localSessionId !== sessionCounter || !currentSession) return;
        if (video.readyState === video.HAVE_ENOUGH_DATA && drawCtx) {
          canvas.width = 320; 
          canvas.height = Math.floor((video.videoHeight / video.videoWidth) * 320);
          drawCtx.drawImage(video, 0, 0, canvas.width, canvas.height);
          const base64 = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
          lastFrameBase64 = base64;
          try {
            currentSession.sendRealtimeInput({ 
              media: { data: base64, mimeType: 'image/jpeg' } 
            });
          } catch (err) {}
        }
      }, 1000); 
      activeIntervals.push(interval);
    }
  } catch (err) {
    console.error("[TURBO] Setup failure:", err);
    onStatusChange('ERROR');
  }
}

export function stopLiveSession() {
  sessionCounter++; 
  if (currentSession) { 
    try { currentSession.close(); } catch(e) {}
    currentSession = null; 
  }
  activeIntervals.forEach(interval => window.clearInterval(interval));
  activeIntervals = [];
  activeMediaStream?.getTracks().forEach(t => t.stop());
  activeAudioStream?.getTracks().forEach(t => t.stop());
  activeMediaStream = null;
  activeAudioStream = null;
  if (currentInputCtx) {
    currentInputCtx.close();
    currentInputCtx = null;
  }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

export async function performDeepAnalysis(base64Image: string, bossProfile: BossProfile) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
        { text: "Describe this ocular snapshot in a sentient, companionable way for Bipradeb." }
      ]
    }
  });
  return response.text;
}

