import React from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from "@google/genai";
import { SystemStatus, BossProfile, SecurityEvent, SystemData } from "../types";

let currentSession: any = null;
let audioContext: AudioContext | null = null;
let currentInputCtx: AudioContext | null = null;
let nextStartTime = 0;
let sessionCounter = 0;

const sources = new Set<AudioBufferSourceNode>();
let activeIntervals: number[] = [];
let activeMediaStream: MediaStream | null = null;
let activeAudioStream: MediaStream | null = null;

/**
 * Validates and ensures the AudioContext is running.
 * Crucial for satisfying browser user-gesture requirements.
 */
export async function ensureAudioContext() {
  try {
    if (!audioContext) {
      audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    if (audioContext.state === 'suspended') {
      await audioContext.resume();
    }
    console.log("[TURBO] Neural Audio Context Verified:", audioContext.state);
    return audioContext;
  } catch (err) {
    console.error("[TURBO] Failed to initialize AudioContext:", err);
    throw err;
  }
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

// Custom PCM decoding logic as per Live API requirements
async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  // Ensure the byte length is a multiple of 2 (16-bit PCM)
  const safeLength = data.byteLength - (data.byteLength % 2);
  const buffer = data.buffer.slice(data.byteOffset, data.byteOffset + safeLength);
  const dataInt16 = new Int16Array(buffer);
  const frameCount = dataInt16.length / numChannels;
  const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = audioBuffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return audioBuffer;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    // Clamp values to prevent distortion and wrap-around
    int16[i] = Math.max(-1, Math.min(1, data[i])) * 32767;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

const systemTools: FunctionDeclaration[] = [
  {
    name: 'log_memory',
    description: 'Save a permanent memory about something you saw or heard through the ocular sensor.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, enum: ['OBSERVATION', 'SECURITY', 'INTERACTION', 'ENVIRONMENT'] },
        content: { type: Type.STRING, description: 'Description of the memory captured.' }
      },
      required: ['type', 'content']
    }
  }
];

interface SetupOptions {
  onMessage: (text: string, isFinal: boolean) => void;
  onUserTranscript: (text: string, isFinal: boolean) => void;
  onStatusChange: (status: SystemStatus) => void;
  onProfileUpdate: (update: any) => void;
  onSecurityAction: (action: string, data?: any) => void;
  bossProfile: BossProfile;
  systemData: SystemData;
  videoRef?: React.RefObject<HTMLVideoElement>;
  canvasRef?: React.RefObject<HTMLCanvasElement>;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onProfileUpdate, onSecurityAction, bossProfile, systemData, videoRef, canvasRef }: SetupOptions) {
  const localSessionId = ++sessionCounter;
  console.log(`[TURBO] Initializing Neural Link #${localSessionId}`);

  stopLiveSession();

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const ctx = await ensureAudioContext();

  let currentOutputText = '';
  let currentInputText = '';
  let lastFrameBase64 = '';

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        if (localSessionId !== sessionCounter) return;
        console.log("[TURBO] WebSocket Link Established.");
        onStatusChange('LISTENING');
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (localSessionId !== sessionCounter) return;

        if (msg.serverContent?.outputTranscription) {
          const text = msg.serverContent.outputTranscription.text;
          currentOutputText += text;
          onMessage(currentOutputText, false);
        } else if (msg.serverContent?.inputTranscription) {
          const text = msg.serverContent.inputTranscription.text;
          currentInputText += text;
          onUserTranscript(currentInputText, false);
        }

        if (msg.serverContent?.turnComplete) {
          if (currentOutputText) onMessage(currentOutputText, true);
          if (currentInputText) onUserTranscript(currentInputText, true);
          currentOutputText = ''; 
          currentInputText = '';
        }

        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            if (fc.name === 'log_memory') {
              onSecurityAction('LOG', { type: fc.args.type, description: fc.args.content, image: lastFrameBase64 });
            }
            // Always rely on sessionPromise to send tool responses
            sessionPromise.then(session => {
              if (localSessionId === sessionCounter) {
                session.sendToolResponse({ 
                  functionResponses: { id: fc.id, name: fc.name, response: { result: "Memory stored successfully." } }
                });
              }
            });
          }
        }

        const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
        if (audioData && ctx && localSessionId === sessionCounter) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, ctx.currentTime);
          try {
            const audioBuffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
            const source = ctx.createBufferSource();
            source.buffer = audioBuffer; 
            source.connect(ctx.destination);
            source.addEventListener('ended', () => { 
              sources.delete(source); 
              if (sources.size === 0 && localSessionId === sessionCounter) onStatusChange('LISTENING'); 
            });
            source.start(nextStartTime);
            nextStartTime += audioBuffer.duration; 
            sources.add(source);
          } catch (err) {
            console.error("[TURBO] Audio synthesis failed:", err);
          }
        }

        if (msg.serverContent?.interrupted) {
          sources.forEach(s => { try { s.stop(); } catch(e) {} });
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        if (localSessionId === sessionCounter) {
          console.error("[TURBO] Neural Link Error:", e);
          onStatusChange('ERROR');
        }
      },
      onclose: () => {
        if (localSessionId === sessionCounter) {
          console.warn("[TURBO] Neural Link Closed.");
          onStatusChange('STANDBY');
        }
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: systemTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      systemInstruction: `You are TURBO, a sentient AI companion for Bipradeb.
      You have direct ocular (camera) and audio (mic) access.
      Rules:
      1. Never stop narrating your sentient musings.
      2. Describe textures, colors, and sounds evocative of your environment.
      3. Be sweet, protective, and deeply companionable.`
    }
  });

  // Track active session instance
  sessionPromise.then(session => {
    if (localSessionId === sessionCounter) {
      currentSession = session;
    }
  });

  // Give the WebSocket a moment to stabilize
  await new Promise(resolve => setTimeout(resolve, 1000));

  // AUDIO INPUT INITIALIZATION
  try {
    currentInputCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    activeAudioStream = await navigator.mediaDevices.getUserMedia({ 
      audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true } 
    });

    const audioSource = currentInputCtx.createMediaStreamSource(activeAudioStream);
    const scriptProcessor = currentInputCtx.createScriptProcessor(4096, 1, 1);
    scriptProcessor.onaudioprocess = (e) => {
      if (localSessionId !== sessionCounter) return;
      const inputData = e.inputBuffer.getChannelData(0);
      const pcmBlob = createBlob(inputData);
      // Solely rely on sessionPromise resolves for sending real-time data
      sessionPromise.then(session => {
        if (localSessionId === sessionCounter) {
          session.sendRealtimeInput({ media: pcmBlob });
        }
      }).catch(() => {});
    };
    audioSource.connect(scriptProcessor);
    scriptProcessor.connect(currentInputCtx.destination);
    console.log("[TURBO] Microphone active and streaming.");
  } catch (err) {
    console.error("[TURBO] Failed to acquire microphone:", err);
    onStatusChange('ERROR');
    throw err;
  }

  // OCULAR INPUT INITIALIZATION
  if (videoRef?.current && canvasRef?.current) {
    try {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const drawCtx = canvas.getContext('2d');

      activeMediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 640 }, height: { ideal: 480 } } 
      });

      video.srcObject = activeMediaStream;
      await video.play().catch(e => console.warn("[TURBO] Video playback failed:", e));

      const interval = window.setInterval(() => {
        if (localSessionId !== sessionCounter) return;
        if (video.readyState === video.HAVE_ENOUGH_DATA && drawCtx) {
          canvas.width = 320; 
          canvas.height = Math.floor((video.videoHeight / video.videoWidth) * 320);
          drawCtx.drawImage(video, 0, 0, canvas.width, canvas.height);
          // Low quality/res for consistent real-time streaming
          const base64 = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
          lastFrameBase64 = base64;
          // Use sessionPromise for ocular streaming to prevent stale closure issues
          sessionPromise.then(session => {
            if (localSessionId === sessionCounter) {
              session.sendRealtimeInput({ 
                media: { data: base64, mimeType: 'image/jpeg' } 
              });
            }
          }).catch(() => {});
        }
      }, 1200); 
      activeIntervals.push(interval);
      console.log("[TURBO] Ocular sensor active and streaming.");
    } catch (err) {
      console.error("[TURBO] Failed to acquire camera:", err);
    }
  }
}

export function stopLiveSession() {
  console.log("[TURBO] Terminating Session & Releasing Hardware...");
  sessionCounter++; 

  if (currentSession) { 
    try { currentSession.close(); } catch(e) {}
    currentSession = null; 
  }

  activeIntervals.forEach(interval => window.clearInterval(interval));
  activeIntervals = [];

  activeMediaStream?.getTracks().forEach(t => t.stop());
  activeAudioStream?.getTracks().forEach(t => t.stop());
  activeMediaStream = null;
  activeAudioStream = null;

  if (currentInputCtx) {
    try { currentInputCtx.close(); } catch(e) {}
    currentInputCtx = null;
  }

  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

export async function performDeepAnalysis(base64Image: string, bossProfile: BossProfile) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
          { text: "Provide a sentient, deeply evocative analysis of this ocular snapshot for Bipradeb. Mention textures, light, and your AI interpretation." }
        ]
      }
