  const interestsStr = bossProfile.interests.length > 0 ? bossProfile.interests.join(', ') : 'None yet';

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        if (localSessionId !== sessionCounter) return;
        onStatusChange('LISTENING');
        onMessage("I'm awake and here for you, Bipradeb.", true);
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (localSessionId !== sessionCounter) return;

        if (msg.serverContent?.outputTranscription) {
          currentOutputText += msg.serverContent.outputTranscription.text;
          onMessage(currentOutputText, false);
        } else if (msg.serverContent?.inputTranscription) {
          currentInputText += msg.serverContent.inputTranscription.text;
          onUserTranscript(currentInputText, false);
        }

        if (msg.serverContent?.turnComplete) {
          if (currentOutputText) onMessage(currentOutputText, true);
          if (currentInputText) onUserTranscript(currentInputText, true);
          currentOutputText = ''; 
          currentInputText = '';
        }

        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let toolResponse = { status: "Success" };
            if (fc.name === 'log_memory') {
              onSecurityAction('LOG', { type: fc.args.type, description: fc.args.content, image: lastFrameBase64 });
            } else if (fc.name === 'update_boss_profile') {
              const updates: Partial<BossProfile> = {};
              if (fc.args.preference) updates.preferences = [...bossProfile.preferences, fc.args.preference];
              if (fc.args.interest) updates.interests = [...bossProfile.interests, fc.args.interest];
              if (fc.args.affinityChange) updates.affinityLevel = Math.max(0, Math.min(100, bossProfile.affinityLevel + fc.args.affinityChange));
              onProfileUpdate(updates);
            }
            sessionPromise.then(session => {
              if (localSessionId === sessionCounter) session.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: toolResponse } });
            });
          }
