import React, { useEffect, useRef } from 'react';
import { SystemStatus } from '../types';

interface CoreVisualizationProps { status: SystemStatus; }

const CoreVisualization: React.FC<CoreVisualizationProps> = ({ status }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;
    const particles: any[] = [];
    const pCount = 120;

    class Particle {
      angle: number; baseRadius: number; radius: number; size: number; speed: number;
      color: string; alpha: number; oscillation: number;

      constructor() {
        this.angle = Math.random() * Math.PI * 2;
        this.baseRadius = 140 + Math.random() * 60;
        this.radius = this.baseRadius;
        this.size = 0.5 + Math.random() * 2;
        this.speed = 0.0005 + Math.random() * 0.002;
        this.color = ['#fb7185', '#fda4af', '#f43f5e'][Math.floor(Math.random() * 3)];
        this.alpha = 0.1 + Math.random() * 0.4;
        this.oscillation = Math.random() * Math.PI * 2;
      }

      update() {
        let targetRadius = this.baseRadius;
        let speedMult = 1;

        // Sentient Breathing Base
        const breathe = Math.sin(Date.now() / 2000) * 15;
        const heartbeat = Math.pow(Math.sin(Date.now() / 800), 10) * 5;

        if (status === 'SPEAKING') {
          targetRadius += (Math.sin(Date.now() / 150) * 50) + breathe + heartbeat;
          speedMult = 2.5;
        } else if (status === 'LISTENING') {
          targetRadius += (Math.sin(Date.now() / 600) * 12) + breathe + heartbeat;
          speedMult = 1.2;
        } else if (status === 'THINKING') {
          speedMult = 4;
          targetRadius += Math.sin(this.oscillation) * 30;
          this.oscillation += 0.1;
        } else {
          targetRadius += breathe + heartbeat;
          speedMult = 0.5;
        }

        this.radius += (targetRadius - this.radius) * 0.1;
        this.angle += this.speed * speedMult;
      }

      draw() {
        if (!ctx) return;
        const x = canvas.width / 2 + Math.cos(this.angle) * this.radius;
        const y = canvas.height / 2 + Math.sin(this.angle) * this.radius;
        ctx.beginPath();
        ctx.arc(x, y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = this.color;
        ctx.globalAlpha = this.alpha;
        ctx.fill();
        ctx.globalAlpha = 1;
      }
    }

    for (let i = 0; i < pCount; i++) particles.push(new Particle());

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();
      const scale = 1 + (Math.sin(time / 2000) * 0.05) + (Math.pow(Math.sin(time / 800), 20) * 0.02);

      const gradient = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, 220 * scale
      );
      gradient.addColorStop(0, 'rgba(244, 63, 94, 0.1)');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      particles.forEach(p => { p.update(); p.draw(); });
      animationFrame = requestAnimationFrame(animate);
    };

    const resize = () => {
      if (canvas) { canvas.width = canvas.clientWidth; canvas.height = canvas.clientHeight; }
    };

    window.addEventListener('resize', resize);
    resize(); animate();
    return () => { cancelAnimationFrame(animationFrame); window.removeEventListener('resize', resize); };
  }, [status]);

  return (
    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
      <canvas ref={canvasRef} className="w-full h-full opacity-80" />
    </div>
  );
};

export default CoreVisualization;

