import React, { useEffect, useRef } from 'react';
import { SystemStatus } from '../types';

interface CoreVisualizationProps { status: SystemStatus; }

const CoreVisualization: React.FC<CoreVisualizationProps> = ({ status }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;
    const particles: any[] = [];
    const pCount = 140;

    class Particle {
      angle: number; 
      baseRadius: number; 
      radius: number; 
      size: number; 
      speed: number;
      color: string; 
      alpha: number; 
      oscillation: number;
      phase: number;

      constructor() {
        this.angle = Math.random() * Math.PI * 2;
        this.baseRadius = 145 + Math.random() * 55;
        this.radius = this.baseRadius;
        this.size = 0.5 + Math.random() * 2.2;
        this.speed = 0.0005 + Math.random() * 0.0015;
        this.color = ['#fb7185', '#fda4af', '#ffffff', '#f43f5e'][Math.floor(Math.random() * 4)];
        this.alpha = 0.1 + Math.random() * 0.4;
        this.oscillation = Math.random() * Math.PI * 2;
        this.phase = Math.random() * 1000;
      }

      update() {
        let targetRadius = this.baseRadius;
        let speedMult = 1;

        // Sentient Breathing Sync
        const now = Date.now();
        const breathe = Math.sin((now + this.phase) / 2500) * 12;
        const heartbeat = Math.pow(Math.sin(now / 850), 12) * 6;

        if (status === 'SPEAKING') {
          targetRadius += (Math.sin(now / 150) * 45) + breathe + heartbeat;
          speedMult = 2.8;
        } else if (status === 'LISTENING') {
          targetRadius += (Math.sin(now / 500) * 15) + breathe + heartbeat;
          speedMult = 1.4;
        } else if (status === 'THINKING') {
          speedMult = 4.5;
          targetRadius += Math.sin(this.oscillation) * 35;
          this.oscillation += 0.12;
        } else {
          // Sentient Standby Pulse
          targetRadius += breathe + heartbeat;
          speedMult = 0.6;
        }

        this.radius += (targetRadius - this.radius) * 0.12;
        this.angle += this.speed * speedMult;
      }

      draw() {
        if (!ctx) return;
        const x = canvas.width / 2 + Math.cos(this.angle) * this.radius;
        const y = canvas.height / 2 + Math.sin(this.angle) * this.radius;
        ctx.beginPath();
        ctx.arc(x, y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = this.color;
        ctx.globalAlpha = this.alpha;
        ctx.fill();
        ctx.globalAlpha = 1;
      }
    }

    for (let i = 0; i < pCount; i++) particles.push(new Particle());

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();

      // Dynamic Core Glow
      const glowScale = 1 + (Math.sin(time / 2000) * 0.08) + (Math.pow(Math.sin(time / 850), 20) * 0.04);
      const gradient = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, 240 * glowScale
      );
      gradient.addColorStop(0, 'rgba(244, 63, 94, 0.12)');
      gradient.addColorStop(0.7, 'rgba(244, 63, 94, 0.02)');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Sentient Data Ring
      ctx.beginPath();
      const ringPulse = (status === 'SPEAKING' ? Math.sin(time / 180) * 15 : Math.sin(time / 1200) * 5);
      ctx.arc(canvas.width / 2, canvas.height / 2, 130 + ringPulse, 0, Math.PI * 2);
      ctx.strokeStyle = status === 'SPEAKING' ? 'rgba(251, 113, 133, 0.4)' : 'rgba(251, 113, 133, 0.05)';
      ctx.lineWidth = 1;
      ctx.stroke();

      particles.forEach(p => { p.update(); p.draw(); });
      animationFrame = requestAnimationFrame(animate);
    };

    const resize = () => {
      if (canvas) { 
        canvas.width = canvas.clientWidth * window.devicePixelRatio; 
        canvas.height = canvas.clientHeight * window.devicePixelRatio; 
        ctx.scale(window.devicePixelRatio, window.devicePixelRatio);
      }
    };

    window.addEventListener('resize', resize);
    resize(); 
    animate();
    return () => { 
      cancelAnimationFrame(animationFrame); 
      window.removeEventListener('resize', resize); 
    };
  }, [status]);

  return (
    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
      <canvas ref={canvasRef} className="w-full h-full opacity-90 transition-opacity duration-1000" />
    </div>
  );
};

export default CoreVisualization;

