              onSecurityAction('LOG', { type: fc.args.type, description: fc.args.content, image: lastFrameBase64 });
              responseObj.status = "Memory archived in neural core.";
            } else if (fc.name === 'update_neural_profile') {
              const up: Partial<BossProfile> = {};
              // Fix: Cast unknown function call arguments to their expected types (string and number) to resolve assignment errors
              if (fc.args.preference) up.preferences = [...bossProfile.preferences, fc.args.preference as string];
              // Fix: Cast unknown function call arguments to their expected types (string and number) to resolve assignment errors
              if (fc.args.interest) up.interests = [...bossProfile.interests, fc.args.interest as string];
              // Fix: Cast unknown function call arguments and handle addition operator with numeric cast
              if (fc.args.affinityDelta !== undefined) up.affinityLevel = Math.max(0, Math.min(100, bossProfile.affinityLevel + (fc.args.affinityDelta as number)));
              onProfileUpdate(up);
            }
            sessionPromise.then(s => s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: responseObj } }));
          }
