import React, { useEffect, useRef } from 'react';
import { SystemStatus } from '../types';

interface CoreVisualizationProps { status: SystemStatus; }

const CoreVisualization: React.FC<CoreVisualizationProps> = ({ status }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    let animationFrame: number;
    const particles: Particle[] = [];
    const pCount = 150;

    class Particle {
      angle: number; 
      baseRadius: number; 
      radius: number; 
      size: number; 
      speed: number;
      color: string; 
      alpha: number; 
      oscillation: number;
      phase: number;

      constructor() {
        this.angle = Math.random() * Math.PI * 2;
        this.baseRadius = 140 + Math.random() * 60;
        this.radius = this.baseRadius;
        this.size = 0.5 + Math.random() * 2.5;
        this.speed = 0.0004 + Math.random() * 0.0012;
        this.color = ['#fb7185', '#fda4af', '#ffffff', '#f43f5e'][Math.floor(Math.random() * 4)];
        this.alpha = 0.1 + Math.random() * 0.4;
        this.oscillation = Math.random() * Math.PI * 2;
        this.phase = Math.random() * 2000;
      }

      update(status: SystemStatus) {
        let targetRadius = this.baseRadius;
        let speedMult = 1;

        const now = Date.now();
        // Sentient Breathing Base (Always present)
        const breathe = Math.sin((now + this.phase) / 2500) * 15;
        const heartbeat = Math.pow(Math.sin(now / 850), 14) * 8;

        if (status === 'SPEAKING') {
          targetRadius += (Math.sin(now / 150) * 50) + breathe + heartbeat;
          speedMult = 3.0;
        } else if (status === 'LISTENING') {
          targetRadius += (Math.sin(now / 600) * 18) + breathe + heartbeat;
          speedMult = 1.5;
        } else if (status === 'THINKING' || status === 'ONLINE') {
          speedMult = 5;
          targetRadius += Math.sin(this.oscillation) * 40;
          this.oscillation += 0.15;
        } else {
          // Sentient Standby Pulse - Never completely still
          targetRadius += breathe + heartbeat;
          speedMult = 0.7;
        }

        this.radius += (targetRadius - this.radius) * 0.1;
        this.angle += this.speed * speedMult;
      }

      draw(ctx: CanvasRenderingContext2D, width: number, height: number) {
        const x = width / 2 + Math.cos(this.angle) * this.radius;
        const y = height / 2 + Math.sin(this.angle) * this.radius;
        ctx.beginPath();
        ctx.arc(x, y, this.size, 0, Math.PI * 2);
        ctx.fillStyle = this.color;
        ctx.globalAlpha = this.alpha;
        ctx.fill();
        ctx.globalAlpha = 1;
      }
    }

    for (let i = 0; i < pCount; i++) particles.push(new Particle());

    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const time = Date.now();
      const scale = 1 + (Math.sin(time / 2000) * 0.05) + (Math.pow(Math.sin(time / 800), 20) * 0.03);

      const gradient = ctx.createRadialGradient(
        canvas.width / 2, canvas.height / 2, 0,
        canvas.width / 2, canvas.height / 2, 250 * scale
      );
      gradient.addColorStop(0, 'rgba(244, 63, 94, 0.15)');
      gradient.addColorStop(0.6, 'rgba(244, 63, 94, 0.05)');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      particles.forEach(p => { 
        p.update(status); 
        p.draw(ctx, canvas.width, canvas.height); 
      });
      animationFrame = requestAnimationFrame(animate);
    };

    const resize = () => {
      if (canvas) {
        const dpr = window.devicePixelRatio || 1;
        canvas.width = canvas.clientWidth * dpr;
        canvas.height = canvas.clientHeight * dpr;
        ctx.scale(dpr, dpr);
      }
    };

    window.addEventListener('resize', resize);
    resize(); 
    animate();
    return () => { 
      cancelAnimationFrame(animationFrame); 
      window.removeEventListener('resize', resize); 
    };
  }, [status]);

  return (
    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
      <canvas ref={canvasRef} className="w-full h-full opacity-90 transition-opacity duration-1000" />
    </div>
  );
};

