        />
        <CoreVisualization status={status} />
        <div className={`fixed inset-0 bg-white transition-opacity duration-300 pointer-events-none z-[100] ${showShutter ? 'opacity-40' : 'opacity-0'}`}></div>
      </div>
      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-16 gap-10 z-10">
        <ChatLog messages={messages} />
        <div className="flex items-center gap-16">
          <button 
            onClick={() => setIsVisionActive(!isVisionActive)} 
            className={`p-8 rounded-full border transition-all duration-700 ${isVisionActive ? 'border-cyan-400 text-cyan-400 bg-cyan-400/5 shadow-[0_0_30px_rgba(0,243,255,0.1)]' : 'border-white/5 text-gray-800'}`} 
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path><circle cx="12" cy="12" r="3"></circle></svg>
          </button>
          <MicButton isActive={isLive} onClick={toggleCore} />
          {isVisionActive && (
            <button 
              onClick={takeSnapshot} 
              disabled={isDeepScanning}
              className={`p-8 rounded-full border border-cyan-500/30 text-cyan-500 bg-cyan-500/5 transition-all duration-500 ${isDeepScanning ? 'animate-pulse' : 'hover:scale-110 shadow-[0_0_40px_rgba(0,243,255,0.15)]'}`}
            >
              <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5"><path d="M23 19a2 2 0 0 1-2 2H3a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h4l2-3h6l2 3h4a2 2 0 0 1 2 2z"></path><circle cx="12" cy="13" r="4"></circle></svg>
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

