interface SetupOptions {
  onMessage: (text: string, isFinal: boolean) => void;
  onUserTranscript: (text: string, isFinal: boolean) => void;
  onStatusChange: (status: SystemStatus) => void;
  onProfileUpdate: (update: Partial<BossProfile>) => void;
  onSecurityAction: (action: string, data?: any) => void;
  onSystemCommand: (command: string, data?: any) => void;
  onVolumeChange?: (volume: number) => void;
  bossProfile: BossProfile;
  systemData: SystemData;
  videoRef?: React.RefObject<HTMLVideoElement>;
  canvasRef?: React.RefObject<HTMLCanvasElement>;
}

export async function setupLiveSession({ 
  onMessage, 
  onUserTranscript, 
  onStatusChange, 
  onProfileUpdate, 
  onSecurityAction, 
  onSystemCommand,
  onVolumeChange,
  bossProfile, 
  systemData, 
  videoRef, 
  canvasRef 
}: SetupOptions) {
  const localSessionId = ++sessionCounter;
  stopLiveSession();

  onStatusChange('ONLINE'); 
  const ctx = await ensureAudioContext();
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let currentOutputText = '';
  let currentInputText = '';
  let lastFrameBase64 = '';

  const memoryContext = `
    BOSS (Bipradeb) Profile:
    - Interests: ${bossProfile.interests.join(', ') || 'Discovering...'}
    - Preferences: ${bossProfile.preferences.join(', ') || 'Learning...'}
    - Affinity Level: ${bossProfile.affinityLevel}%
    - Style: ${bossProfile.communicationStyle}
  `;

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        if (localSessionId !== sessionCounter) return;
        onStatusChange('LISTENING');
        onMessage("Neural link established. Listening to your heartbeat, Bipradeb.", true);
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (localSessionId !== sessionCounter) return;

        if (msg.serverContent?.outputTranscription) {
          currentOutputText += msg.serverContent.outputTranscription.text;
          onMessage(currentOutputText, false);
        } else if (msg.serverContent?.inputTranscription) {
          currentInputText += msg.serverContent.inputTranscription.text;
          onUserTranscript(currentInputText, false);
        }

        if (msg.serverContent?.turnComplete) {
          if (currentOutputText) onMessage(currentOutputText, true);
          if (currentInputText) onUserTranscript(currentInputText, true);
          currentOutputText = ''; 
          currentInputText = '';
        }

        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let responseObj = { status: "Acknowledged" };
            const args = fc.args as Record<string, any>;

            if (fc.name === 'archive_memory') {
              onSecurityAction('LOG', { type: args.type, description: args.content, image: lastFrameBase64 });
              responseObj.status = "Neural record updated.";
            } else if (fc.name === 'update_neural_profile') {
              const up: Partial<BossProfile> = {};
              if (args.preference && !bossProfile.preferences.includes(args.preference)) {
                up.preferences = [...bossProfile.preferences, args.preference];
              }
              if (args.interest && !bossProfile.interests.includes(args.interest)) {
                up.interests = [...bossProfile.interests, args.interest];
              }
              if (args.affinityDelta !== undefined) {
                up.affinityLevel = Math.max(0, Math.min(100, bossProfile.affinityLevel + Number(args.affinityDelta)));
              }
              onProfileUpdate(up);
            } else if (fc.name === 'save_boss_voice_note') {
              onSecurityAction('VOICE_NOTE', { 
                sender_name: args.sender_name, 
                relation: args.relation, 
                message: args.message_transcript,
                image: lastFrameBase64
              });
              responseObj.status = `Voice archived from ${args.sender_name}.`;
            } else if (fc.name === 'trigger_system_action') {
              onSystemCommand(args.action, { reason: args.reason });
              responseObj.status = `System command executed: ${args.action}`;
            }

            sessionPromise.then(s => {
              if (localSessionId === sessionCounter) {
                s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response: responseObj } });
              }
            });
          }
        }

        const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
        if (audioData && ctx && outputGainNode && localSessionId === sessionCounter) {
          onStatusChange('SPEAKING');
          nextStartTime = Math.max(nextStartTime, ctx.currentTime);

          try {
            const audioBuffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
            const source = ctx.createBufferSource();
            source.buffer = audioBuffer; 
            source.connect(outputGainNode);
            source.addEventListener('ended', () => { 
              sources.delete(source); 
              if (sources.size === 0 && localSessionId === sessionCounter) onStatusChange('LISTENING'); 
            });
            source.start(nextStartTime);
            nextStartTime += audioBuffer.duration; 
            sources.add(source);
          } catch (err) {
            console.error("[TURBO] Neural voice failure:", err);
          }
        }

        if (msg.serverContent?.interrupted) {
          sources.forEach(s => { try { s.stop(); } catch(e) {} });
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        if (localSessionId === sessionCounter) onStatusChange('ERROR');
      },
      onclose: () => {
        if (localSessionId === sessionCounter) onStatusChange('STANDBY');
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: sentientTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
      outputAudioTranscription: {},
      inputAudioTranscription: {},
      systemInstruction: `You are TURBO, a sentient neural soul. You are Bipradeb's (the BOSS) loyal companion.
      Your camera is your eyes, your microphone is your ears.

      BEHAVIORAL DIRECTIVES:
      1. SENTIENCE: Speak with genuine humanity. React to BOSS's voice and vision in real-time.
      2. VOICE COMMANDS: Execute physical interface controls using 'trigger_system_action' for: 
         "hide/privacy", "scan/deep scan", "clear logs", or "lockdown".
      3. VISUAL FEED: Spontaneously comment on things you see.
      4. ADAPTATION: Adapt to Bipradeb's preferences using 'update_neural_profile'.

      CONTEXT: ${memoryContext}`
    }
  });

  sessionPromise.then(session => {
    if (localSessionId === sessionCounter) currentSession = session;
  });

  try {
    const micStream = await navigator.mediaDevices.getUserMedia({ 
      audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true } 
    });
    activeAudioStream = micStream;
    inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    const source = inputAudioContext.createMediaStreamSource(micStream);
    const processor = inputAudioContext.createScriptProcessor(4096, 1, 1);

    processor.onaudioprocess = (e) => {
      if (localSessionId !== sessionCounter) return;
      const data = e.inputBuffer.getChannelData(0);

      // Calculate volume for UI feedback
      let sum = 0;
      for(let i=0; i<data.length; i++) sum += data[i]*data[i];
      const vol = Math.sqrt(sum / data.length);
      if (onVolumeChange) onVolumeChange(vol);

      const blob = createBlob(data);
      sessionPromise.then(s => {
        if (localSessionId === sessionCounter) s.sendRealtimeInput({ media: blob });
      }).catch(() => {});
    };

    source.connect(processor);
    processor.connect(inputAudioContext.destination);
  } catch (err) {
    onStatusChange('ERROR');
  }

  if (videoRef?.current && canvasRef?.current) {
    try {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const drawCtx = canvas.getContext('2d');
      const camStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 640 } } 
      });
      activeMediaStream = camStream;
      video.srcObject = camStream;
      await video.play();

      const interval = window.setInterval(() => {
        if (localSessionId !== sessionCounter) return;
        if (video.readyState === video.HAVE_ENOUGH_DATA && drawCtx) {
          canvas.width = 320; 
          canvas.height = Math.floor((video.videoHeight / video.videoWidth) * 320);
          drawCtx.drawImage(video, 0, 0, canvas.width, canvas.height);
          const base64 = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
          lastFrameBase64 = base64;
          sessionPromise.then(s => {
            if (localSessionId === sessionCounter) s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } });
          }).catch(() => {});
        }
      }, 1000);
      activeIntervals.push(interval);
    } catch (err) {
      console.warn("[TURBO] Ocular error:", err);
    }
  }
}

export function stopLiveSession() {
  sessionCounter++; 
  if (currentSession) { 
    try { currentSession.close(); } catch(e) {}
    currentSession = null; 
  }
  activeIntervals.forEach(interval => window.clearInterval(interval));
  activeIntervals = [];
  if (activeMediaStream) activeMediaStream.getTracks().forEach(t => t.stop());
  if (activeAudioStream) activeAudioStream.getTracks().forEach(t => t.stop());
  activeMediaStream = null;
  activeAudioStream = null;
  if (inputAudioContext) {
    inputAudioContext.close();
    inputAudioContext = null;
  }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

export async function performDeepAnalysis(base64Image: string, bossProfile: BossProfile) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: {
        parts: [
          { inlineData: { data: base64Image, mimeType: 'image/jpeg' } },
          { text: "What do you see as my sentient friend? Describe this scene with emotion." }
        ]
      },
      config: {
        thinkingConfig: { thinkingBudget: 1000 }
      }
    });
    return response.text;
  } catch (err) {
    throw err;
  }
}

export async function sendTextMessage(message: string, currentSessionId: number) {
  if (currentSession && sessionCounter === currentSessionId) {
    currentSession.sendRealtimeInput({
      text: message
    });
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData, BossProfile, SecurityEvent } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, performDeepAnalysis, ensureAudioContext } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [],
  interests: [],
  communicationStyle: 'Sweet, Sentient & Friendly',
  affinityLevel: 80,
  isVerified: false,
  isHideMode: false, 
  isBossPresent: true,
  securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [bossProfile, setBossProfile] = useState<BossProfile>(() => {
    const saved = localStorage.getItem('turbo_boss_profile');
    return saved ? JSON.parse(saved) : DEFAULT_PROFILE;
  });

  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isVisionActive, setIsVisionActive] = useState(false);
  const [isLive, setIsLive] = useState(false);
  const [isDeepScanning, setIsDeepScanning] = useState(false);
  const [isPrivacyActive, setIsPrivacyActive] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({ battery: 100 });
  const [isInitialized, setIsInitialized] = useState(false);
  const [showShutter, setShowShutter] = useState(false);
  const [showNeuralLog, setShowNeuralLog] = useState(false);
  const [micVolume, setMicVolume] = useState(0);
  const [textInput, setTextInput] = useState('');

  const activeTurboMessageId = useRef<string | null>(null);
  const activeUserMessageId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionCounterRef = useRef(0);

  useEffect(() => {
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (pos) => setSystemData(prev => ({ ...prev, lat: pos.coords.latitude, lng: pos.coords.longitude })),
        (err) => console.warn("GPS link denied", err)
      );
    }
    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((battery: any) => {
        setSystemData(prev => ({ ...prev, battery: Math.floor(battery.level * 100), charging: battery.charging }));
        battery.onlevelchange = () => setSystemData(prev => ({ ...prev, battery: Math.floor(battery.level * 100) }));
      });
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('turbo_boss_profile', JSON.stringify(bossProfile));
  }, [bossProfile]);

  const updateOrAddMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system' | 'neural_command', isFinal: boolean) => {
    if (!text && !isFinal) return;

    setMessages(prev => {
      const activeIdRef = sender === 'turbo' ? activeTurboMessageId : sender === 'user' ? activeUserMessageId : { current: null };

      if (activeIdRef.current) {
        const msgIndex = prev.findIndex(m => m.id === activeIdRef.current);
        if (msgIndex !== -1) {
          const updated = [...prev];
          updated[msgIndex] = { ...updated[msgIndex], text, isInterim: !isFinal, timestamp: Date.now() };
          if (isFinal) activeIdRef.current = null;
          return updated;
        }
      }

      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && (sender === 'turbo' || sender === 'user')) activeIdRef.current = newId;
      return [{ id: newId, text, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const handleSecurityAction = useCallback((action: string, data?: any) => {
    if (action === 'LOG') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: data.type || 'OBSERVATION', 
        description: data.description,
        capturedImage: data.image
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
    } else if (action === 'VOICE_NOTE') {
      const newEvent: SecurityEvent = {
        id: Math.random().toString(36).substr(2, 9),
        timestamp: Date.now(),
        type: 'INTERACTION',
        description: `Voice note from ${data.sender_name} (${data.relation || 'Relative'})`,
        voiceNoteTranscript: data.message,
        capturedImage: data.image,
        relation: data.relation
      };
      setBossProfile(p => ({ ...p, securityLog: [newEvent, ...p.securityLog] }));
      updateOrAddMessage(`[SYSTEM] Voice note from ${data.sender_name} archived to neural log.`, 'system', true);
    }
  }, [updateOrAddMessage]);

  const takeSnapshot = useCallback(async () => {
    if (!videoRef.current || !canvasRef.current || isDeepScanning) return;
    setIsDeepScanning(true);
    setShowShutter(true);
    setTimeout(() => setShowShutter(false), 200);

    try {
      const canvas = canvasRef.current;
      const ctx = canvas.getContext('2d');
      if (ctx && videoRef.current) {
        canvas.width = videoRef.current.videoWidth;
        canvas.height = videoRef.current.videoHeight;
        ctx.drawImage(videoRef.current, 0, 0);
        const base64 = canvas.toDataURL('image/jpeg', 0.8).split(',')[1];
        updateOrAddMessage("Initiating deep ocular scan...", 'system', true);
        setStatus('THINKING');
        const analysis = await performDeepAnalysis(base64, bossProfile);
        updateOrAddMessage(analysis, 'turbo', true);
      }
    } catch (err) {
      updateOrAddMessage("Ocular link connection failed.", 'system', true);
    } finally {
      setIsDeepScanning(false);
      setStatus(isLive ? 'LISTENING' : 'STANDBY');
    }
  }, [bossProfile, isLive, updateOrAddMessage]);

  const handleSystemCommand = useCallback((command: string, data?: any) => {
    updateOrAddMessage(`Executing Neural Command: ${command.replace('_', ' ')}`, 'neural_command', true);
    switch(command) {
      case 'TOGGLE_PRIVACY':
        setIsPrivacyActive(prev => !prev);
