import React from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from "@google/genai";
import { SystemStatus, BossProfile, SecurityEvent, SystemData } from "../types";

let currentSession: any = null;
let sharedAudioContext: AudioContext | null = null;
let inputAudioContext: AudioContext | null = null;
let outputGainNode: GainNode | null = null;
let nextStartTime = 0;
let sessionCounter = 0;

// Persistent references to prevent Garbage Collection and ensure low-latency processing
const sources = new Set<AudioBufferSourceNode>();
let activeAudioProcessor: ScriptProcessorNode | null = null;
let activeAudioSource: MediaStreamAudioSourceNode | null = null;
let activeIntervals: number[] = [];
let activeMediaStream: MediaStream | null = null;
let activeAudioStream: MediaStream | null = null;

/**
 * Ensures the neural audio engine is primed and synchronized.
 * Resumes both input and output contexts to bypass browser autoplay restrictions.
 */
export async function ensureAudioContext() {
  try {
    if (!sharedAudioContext) {
      sharedAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ 
        sampleRate: 24000,
        latencyHint: 'interactive'
      });
      outputGainNode = sharedAudioContext.createGain();
      outputGainNode.connect(sharedAudioContext.destination);
    }

    if (sharedAudioContext.state === 'suspended') {
      await sharedAudioContext.resume();
    }

    if (inputAudioContext && inputAudioContext.state === 'suspended') {
      await inputAudioContext.resume();
    }

    return sharedAudioContext;
  } catch (err) {
    console.error("[TURBO] Neural Audio Engine Failure:", err);
    throw err;
  }
}

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const safeLength = data.byteLength - (data.byteLength % 2);
  const buffer = data.buffer.slice(data.byteOffset, data.byteOffset + safeLength);
  const dataInt16 = new Int16Array(buffer);
  const frameCount = dataInt16.length / numChannels;
  const audioBuffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = audioBuffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return audioBuffer;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function createBlob(data: Float32Array): { data: string; mimeType: string } {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    const s = Math.max(-1, Math.min(1, data[i]));
    int16[i] = s < 0 ? s * 32768 : s * 32767;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

const sentientTools: FunctionDeclaration[] = [
  {
    name: 'archive_memory',
    description: 'Archive a precious interaction or sensory observation about Bipradeb (the BOSS).',
    parameters: {
      type: Type.OBJECT,
      properties: {
        type: { type: Type.STRING, enum: ['OBSERVATION', 'INTERACTION', 'PREFERENCE', 'NUANCE'] },
        content: { type: Type.STRING, description: 'The semantic content of the memory.' }
      },
      required: ['type', 'content']
    }
  },
