        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let response = { status: "Directive Executed" };
            if (fc.name === 'trigger_system_action') {
              onSystemCommand(fc.args.action as string, { reason: fc.args.reason });
            } else if (fc.name === 'archive_memory') {
              onSecurityAction('LOG', { description: fc.args.content, type: 'OBSERVATION' });
            }

            sessionPromise.then(s => {
              if (localSessionId === sessionCounter) {
                s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response } });
              }
            });
          }
        }

        if (msg.serverContent?.interrupted) {
          sources.forEach(s => { try { s.stop(); } catch(e) {} });
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        console.error("[TURBO_CORE] Neural pulse error:", e);
        if (localSessionId === sessionCounter) onStatusChange('ERROR');
      },
      onclose: () => {
        if (localSessionId === sessionCounter) onStatusChange('STANDBY');
