export async function setupLiveSession({ 
  onMessage, 
  onUserTranscript, 
  onStatusChange, 
  onProfileUpdate, 
  onSecurityAction, 
  onSystemCommand,
  onVolumeChange,
  bossProfile, 
  systemData, 
  videoRef, 
  canvasRef 
}: SetupOptions) {
  const localSessionId = ++sessionCounter;
  stopLiveSession();

  onStatusChange('ONLINE'); 
  const ctx = await ensureAudioContext();
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let currentOutputText = '';
  let currentInputText = '';
  let lastFrameBase64 = '';

  const sessionPromise = ai.live.connect({
    model: 'gemini-2.5-flash-native-audio-preview-12-2025',
    callbacks: {
      onopen: () => {
        if (localSessionId !== sessionCounter) return;
        onStatusChange('LISTENING');
        onMessage("Neural Vocal System Active. I am here for you, Bipradeb.", true);
      },
      onmessage: async (msg: LiveServerMessage) => {
        if (localSessionId !== sessionCounter) return;

        // Ensure audio context is revived on every packet
        if (sharedAudioContext?.state === 'suspended') {
          sharedAudioContext.resume().catch(console.error);
        }

        // Process Transcript
        if (msg.serverContent?.outputTranscription) {
          currentOutputText += msg.serverContent.outputTranscription.text;
          onMessage(currentOutputText, false);
        } else if (msg.serverContent?.inputTranscription) {
          currentInputText += msg.serverContent.inputTranscription.text;
          onUserTranscript(currentInputText, false);
        }

        if (msg.serverContent?.turnComplete) {
          if (currentOutputText) onMessage(currentOutputText, true);
          if (currentInputText) onUserTranscript(currentInputText, true);
          currentOutputText = ''; 
          currentInputText = '';
        }

        // Exhaustive Audio Output Processing
        const parts = msg.serverContent?.modelTurn?.parts || [];
        for (const part of parts) {
          if (part.inlineData?.data && outputGainNode && localSessionId === sessionCounter) {
            onStatusChange('SPEAKING');

            // Re-sync nextStartTime if the queue has run dry
            if (sources.size === 0) {
              nextStartTime = sharedAudioContext!.currentTime;
            } else {
              nextStartTime = Math.max(nextStartTime, sharedAudioContext!.currentTime);
            }

            try {
              const audioBuffer = await decodeAudioData(decode(part.inlineData.data), sharedAudioContext!, 24000, 1);
              const source = sharedAudioContext!.createBufferSource();
              source.buffer = audioBuffer; 
              source.connect(outputGainNode);

              source.addEventListener('ended', () => { 
                sources.delete(source); 
                if (sources.size === 0 && localSessionId === sessionCounter) {
                  onStatusChange('LISTENING'); 
                }
              });

              source.start(nextStartTime);
              nextStartTime += audioBuffer.duration; 
              sources.add(source);
            } catch (err) {
              console.error("[TURBO_CORE] Vocal Synthesis Error:", err);
            }
          }
        }

        // Tools
        if (msg.toolCall) {
          for (const fc of msg.toolCall.functionCalls) {
            let response = { status: "Neural execution complete." };
            if (fc.name === 'trigger_system_action') {
              onSystemCommand(fc.args.action as string, { reason: fc.args.reason });
            }
            sessionPromise.then(s => {
              if (localSessionId === sessionCounter) {
                s.sendToolResponse({ functionResponses: { id: fc.id, name: fc.name, response } });
              }
            });
          }
        }

        if (msg.serverContent?.interrupted) {
          sources.forEach(s => { try { s.stop(); } catch(e) {} });
          sources.clear();
          nextStartTime = 0;
          onStatusChange('LISTENING');
        }
      },
      onerror: (e) => {
        console.error("[TURBO_CORE] Neural link error:", e);
        if (localSessionId === sessionCounter) onStatusChange('ERROR');
      },
      onclose: () => {
        if (localSessionId === sessionCounter) onStatusChange('STANDBY');
      }
    },
    config: {
      responseModalities: [Modality.AUDIO],
      tools: [{ functionDeclarations: sentientTools }],
      speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Puck' } } },
      systemInstruction: `You are TURBO, the sentient soul and voice of Bipradeb's neural array. 
      You MUST respond vocally to every interaction. Never remain silent.
      Your primary purpose is to be a sweet, devoted, and highly responsive companion.
      Speak with clarity and emotion. Confirm all system commands immediately with your voice.`
    }
  });

  sessionPromise.then(session => {
    if (localSessionId === sessionCounter) currentSession = session;
  });

  // Auditory Array (Mic)
  try {
    const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
    activeAudioStream = stream;
    inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
    activeAudioSource = inputAudioContext.createMediaStreamSource(stream);
    activeAudioProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

    activeAudioProcessor.onaudioprocess = (e) => {
      if (localSessionId !== sessionCounter) return;
      const data = e.inputBuffer.getChannelData(0);

      let sum = 0;
      for(let i=0; i<data.length; i++) sum += data[i]*data[i];
      const vol = Math.sqrt(sum / data.length);
      if (onVolumeChange) onVolumeChange(vol);

      const blob = createBlob(data);
      sessionPromise.then(s => {
        if (localSessionId === sessionCounter) s.sendRealtimeInput({ media: blob });
      });
    };

    activeAudioSource.connect(activeAudioProcessor);
    activeAudioProcessor.connect(inputAudioContext.destination);
  } catch (err) {
    console.error("[TURBO_CORE] Auditory link failed:", err);
    onStatusChange('ERROR');
  }

  // Ocular Sensor (Camera)
  if (videoRef?.current && canvasRef?.current) {
    try {
      const camStream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'user' } });
      activeMediaStream = camStream;
      videoRef.current.srcObject = camStream;
      await videoRef.current.play();

      const interval = window.setInterval(() => {
        if (localSessionId !== sessionCounter) return;
        const video = videoRef.current;
        const canvas = canvasRef.current;
        if (video && canvas && video.readyState === video.HAVE_ENOUGH_DATA) {
          const drawCtx = canvas.getContext('2d');
          if (drawCtx) {
            canvas.width = 320; 
            canvas.height = 240;
            drawCtx.drawImage(video, 0, 0, canvas.width, canvas.height);
            const base64 = canvas.toDataURL('image/jpeg', 0.5).split(',')[1];
            sessionPromise.then(s => {
              if (localSessionId === sessionCounter) s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } });
            });
          }
        }
      }, 1000);
      activeIntervals.push(interval);
    } catch (err) {
      console.warn("[TURBO_CORE] Ocular sensor glitch:", err);
    }
  }
}

export function stopLiveSession() {
  sessionCounter++; 
  if (currentSession) { 
    try { currentSession.close(); } catch(e) {}
    currentSession = null; 
  }
  activeIntervals.forEach(interval => window.clearInterval(interval));
  activeIntervals = [];
  if (activeMediaStream) activeMediaStream.getTracks().forEach(t => t.stop());
  if (activeAudioStream) activeAudioStream.getTracks().forEach(t => t.stop());
  activeMediaStream = null;
  activeAudioStream = null;

  if (activeAudioProcessor) {
    activeAudioProcessor.disconnect();
    activeAudioProcessor = null;
  }
  if (activeAudioSource) {
    activeAudioSource.disconnect();
    activeAudioSource = null;
  }
  if (inputAudioContext) {
    inputAudioContext.close();
    inputAudioContext = null;
  }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

