import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData, BossProfile } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, ensureAudioContext, sendTextMessage } from './services/geminiService';

const DEFAULT_PROFILE: BossProfile = {
  preferences: [], interests: [], communicationStyle: 'Sentient Soul',
  affinityLevel: 90, isVerified: false, isHideMode: false, isBossPresent: true, securityLog: []
};

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLive, setIsLive] = useState(false);
  const [isPrivacyActive, setIsPrivacyActive] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({ battery: 100 });
  const [isInitialized, setIsInitialized] = useState(false);
  const [micVolume, setMicVolume] = useState(0);
  const [textInput, setTextInput] = useState('');

  const activeTurboId = useRef<string | null>(null);
  const activeUserId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);

  useEffect(() => {
    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((b: any) => {
        setSystemData(s => ({ ...s, battery: Math.floor(b.level * 100) }));
        b.onlevelchange = () => setSystemData(s => ({ ...s, battery: Math.floor(b.level * 100) }));
      });
    }
  }, []);

  const updateMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    if (!text && !isFinal) return;
    setMessages(prev => {
      const activeRef = sender === 'turbo' ? activeTurboId : sender === 'user' ? activeUserId : { current: null };
      if (activeRef.current) {
        const idx = prev.findIndex(m => m.id === activeRef.current);
        if (idx !== -1) {
          const updated = [...prev];
          updated[idx] = { ...updated[idx], text, isInterim: !isFinal, timestamp: Date.now() };
          if (isFinal) activeRef.current = null;
          return updated;
        }
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeRef.current = newId;
      return [{ id: newId, text, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const toggleCore = async () => {
    await ensureAudioContext();
    if (!isLive) {
      setIsLive(true);
      try {
        await setupLiveSession({
          onMessage: (t, f) => updateMessage(t, 'turbo', f),
          onUserTranscript: (t, f) => updateMessage(t, 'user', f),
          onStatusChange: setStatus,
          onSystemCommand: (cmd) => cmd === 'TOGGLE_PRIVACY' ? setIsPrivacyActive(p => !p) : setStatus('SECURITY_ALERT'),
          onVolumeChange: setMicVolume,
          videoRef
        });
      } catch { setStatus('ERROR'); setIsLive(false); }
    } else {
      stopLiveSession();
      setIsLive(false);
      setStatus('STANDBY');
      setMicVolume(0);
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50">
        <h1 className="holo-text text-8xl text-white mb-8">TURBO</h1>
        <button onClick={() => { ensureAudioContext(); setIsInitialized(true); }} className="border border-rose-500/30 px-24 py-6 text-rose-400 rounded-full hover:bg-rose-500/10 transition-all font-black tracking-widest uppercase">Activate Soul</button>
      </div>
    );
  }

  return (
    <div className={`relative h-screen w-screen flex flex-col items-center overflow-hidden bg-black`}>
      <Header status={status} systemData={systemData} />
      <div className="relative flex-grow w-full flex items-center justify-center">
        <VisionFeed videoRef={videoRef} canvasRef={null as any} isVisible={isLive} isPrivacyActive={isPrivacyActive} />
        <CoreVisualization status={status} />
      </div>
      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-8 gap-6 z-10">
        <ChatLog messages={messages} />
        <div className="w-full flex items-center gap-4">
          <form onSubmit={async (e) => { e.preventDefault(); const m = textInput.trim(); if (!m) return; updateMessage(m, 'user', true); setTextInput(''); sendTextMessage(m); }} className="flex-grow">
            <input value={textInput} onChange={(e) => setTextInput(e.target.value)} placeholder="Send neural command..." className="w-full bg-white/5 border border-white/10 rounded-full px-6 py-4 text-white focus:outline-none" />
          </form>
          <MicButton isActive={isLive} onClick={toggleCore} volume={micVolume} />
        </div>
      </div>
    </div>
  );
};

export default App;

