            console.error("Session failed:", err);
            setErrorLog("Sensor Link Failed. Check Permissions.");
            setStatus('ERROR');
            setIsLive(false);
          }
        }, 100);
      } else {
        stopLiveSession();
        setIsLive(false);
        setStatus('STANDBY');
        setMicVolume(0);
