          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-32 bg-red-950/40 border border-red-500/30 px-4 py-2 rounded-lg text-red-400 text-xs font-black uppercase tracking-widest animate-bounce">
            {errorLog}
          </div>
        )}
      </div>

      {/* Interaction HUD */}
      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-8 gap-6 z-10">
        <ChatLog messages={messages} />

        <div className="w-full flex items-center gap-4">
          <form 
            onSubmit={async (e) => { 
              e.preventDefault(); 
              const m = textInput.trim(); 
              if (!m) return; 
              updateMessage(m, 'user', true); 
              setTextInput(''); 
              sendTextMessage(m); 
            }} 
            className="flex-grow"
          >
