    description: 'Connect to global networks to fetch current events, weather, or human trends.',
    parameters: {
      type: Type.OBJECT,
      properties: {
        focus: { type: Type.STRING, enum: ['GLOBAL_NEWS', 'LOCAL_WEATHER', 'TECH_TRENDS'] }
      },
