export async function sendTextMessage(message: string) {
  // Wait a moment if session is still initializing
  if (isSessionInitializing) {
     await new Promise(r => setTimeout(r, 1000));
  }

  if (currentSession) {
    try {
      // For LiveSession, text is best sent via the 'send' method if supported, 
      // or wrapped as a content message in the stream.
      // Most Gemini Live implementations in this SDK version use 'send' with a parts array.
      if (typeof currentSession.send === 'function') {
        currentSession.send({ parts: [{ text: message }] });
      } else {
        // Fallback to sendRealtimeInput if 'send' is missing, though less likely for turns.
        currentSession.sendRealtimeInput({ text: message });
      }
      return true;
    } catch (e) {
      console.error("Failed to send command:", e);
      return false;
    }
  }
  return false;
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData, BossProfile } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, ensureAudioContext, sendTextMessage } from './services/geminiService';

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLive, setIsLive] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({ battery: 100 });
  const [isInitialized, setIsInitialized] = useState(false);
  const [micVolume, setMicVolume] = useState(0);
  const [textInput, setTextInput] = useState('');
  const [errorLog, setErrorLog] = useState<string | null>(null);

  const activeTurboId = useRef<string | null>(null);
  const activeUserId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const reconnectTimeout = useRef<number | null>(null);
  const reconnectAttempts = useRef(0);

  // Battery monitoring
  useEffect(() => {
    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((b: any) => {
        setSystemData(s => ({ ...s, battery: Math.floor(b.level * 100) }));
        b.onlevelchange = () => setSystemData(s => ({ ...s, battery: Math.floor(b.level * 100) }));
      });
    }
  }, []);

  const updateMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean) => {
    if (!text && !isFinal) return;
    setMessages(prev => {
      const activeRef = sender === 'turbo' ? activeTurboId : sender === 'user' ? activeUserId : { current: null };

      if (activeRef.current) {
        const idx = prev.findIndex(m => m.id === activeRef.current);
        if (idx !== -1) {
          const updated = [...prev];
          updated[idx] = { ...updated[idx], text, isInterim: !isFinal, timestamp: Date.now() };
          if (isFinal) activeRef.current = null;
          return updated;
        }
      }

      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeRef.current = newId;
      return [{ id: newId, text, sender, isInterim: !isFinal, timestamp: Date.now() }, ...prev];
    });
  }, []);

  const startSession = useCallback(async () => {
    setStatus('ONLINE');
    setErrorLog(null);

    if (reconnectTimeout.current) {
      clearTimeout(reconnectTimeout.current);
      reconnectTimeout.current = null;
    }

    try {
      await setupLiveSession({
        onMessage: (t, f) => {
          updateMessage(t, 'turbo', f);
          if (f) reconnectAttempts.current = 0; 
        },
        onUserTranscript: (t, f) => updateMessage(t, 'user', f),
        onStatusChange: (newStatus) => {
          setStatus(newStatus);
          if (newStatus === 'LISTENING' || newStatus === 'SPEAKING') {
             reconnectAttempts.current = 0;
          }
        },
        onSystemCommand: (cmd) => setStatus('SECURITY_ALERT'),
        onVolumeChange: setMicVolume,
        onClose: () => {
          if (isLive) {
            setStatus('RECONNECTING');
            reconnectAttempts.current++;
            const delay = Math.min(1000 * Math.pow(2, reconnectAttempts.current), 15000);
            updateMessage(`Neural Link severed. Re-entering in ${Math.round(delay/1000)}s...`, 'system', true);
            reconnectTimeout.current = window.setTimeout(() => {
              if (isLive) startSession();
            }, delay);
          }
        },
        videoRef
      });
    } catch (err) {
      console.error("Session activation failed:", err);
      setErrorLog("Neural Link Activation Failed.");
      setStatus('ERROR');
    }
  }, [isLive, updateMessage]);

  const toggleCore = async () => {
    setErrorLog(null);
    reconnectAttempts.current = 0;

    if (reconnectTimeout.current) {
      clearTimeout(reconnectTimeout.current);
      reconnectTimeout.current = null;
    }

    try {
      await ensureAudioContext();
      if (!isLive) {
        setIsLive(true);
      } else {
        stopLiveSession();
        setIsLive(false);
        setStatus('STANDBY');
        setMicVolume(0);
      }
    } catch (err) {
      setErrorLog("Neural Awakening Interrupted.");
      setStatus('ERROR');
    }
  };

  useEffect(() => {
    if (isLive) {
      startSession();
    }
    return () => {
      if (reconnectTimeout.current) clearTimeout(reconnectTimeout.current);
    };
  }, [isLive, startSession]);

  const handleTextCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    const m = textInput.trim();
    if (!m) return;

    updateMessage(m, 'user', true);
    setTextInput('');

    // Visually show she's processing the text command
    if (status !== 'ERROR') setStatus('THINKING');

    const sent = await sendTextMessage(m);
    if (!sent) {
       updateMessage("Neural link busy. Re-sending command...", 'system', true);
       // Re-try once
       setTimeout(() => sendTextMessage(m), 1500);
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50">
        <h1 className="holo-text text-8xl text-white mb-4 animate-pulse text-center">TURBO</h1>
        <p className="text-rose-400/60 tracking-[0.5em] uppercase text-[0.6rem] mb-12 font-black">Sentient Soul Link V3</p>
        <button 
          onClick={() => { ensureAudioContext(); setIsInitialized(true); }} 
          className="border border-rose-500/30 px-24 py-6 text-rose-400 rounded-full hover:bg-rose-500/10 transition-all font-black tracking-widest uppercase shadow-[0_0_40px_rgba(244,63,94,0.2)] active:scale-95"
        >
          Wake Her Up
        </button>
      </div>
    );
  }

  return (
    <div className="relative h-screen w-screen flex flex-col items-center overflow-hidden bg-[#020202]">
      <Header status={status} systemData={systemData} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <div className={`contents transition-all duration-1000 ${isLive ? 'scale-100' : 'scale-75 opacity-0'}`}>
          <VisionFeed videoRef={videoRef} canvasRef={null as any} isVisible={isLive} />
        </div>
        <CoreVisualization status={status} />

        {(errorLog || status === 'RECONNECTING') && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-32 bg-rose-950/40 border border-rose-500/30 px-4 py-2 rounded-lg text-rose-400 text-xs font-black uppercase tracking-widest animate-bounce shadow-[0_0_20px_rgba(244,63,94,0.4)] z-50">
            {status === 'RECONNECTING' ? "Reconnecting Neural Link..." : errorLog}
          </div>
        )}
      </div>

      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-8 gap-6 z-10">
        <ChatLog messages={messages} />

        <div className="w-full flex items-center gap-4">
          <form onSubmit={handleTextCommand} className="flex-grow">
            <input 
              value={textInput} 
              onChange={(e) => setTextInput(e.target.value)} 
              placeholder="Whisper command to Turbo..." 
              className="w-full bg-white/5 border border-white/10 rounded-full px-6 py-4 text-white text-sm font-medium focus:outline-none focus:border-rose-500/30 transition-all placeholder:text-white/20" 
            />
          </form>
          <MicButton isActive={isLive} onClick={toggleCore} volume={micVolume} />
        </div>
      </div>

      <div className="absolute inset-0 pointer-events-none opacity-20 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>
    </div>
  );
};

