                onSystemCommand(fc.args.observation as string);
                sessionPromise.then(s => {
                  if (s && s.readyState === 1) {
                    s.sendToolResponse({
                      functionResponses: { id: fc.id, name: fc.name, response: { result: "Environment analysis complete." } }
