      if (localId === sessionCounter) {
        currentSession = s; 
      } else {
        s.close();
      }
    }).catch(() => {
       if (localId === sessionCounter) onStatusChange('ERROR');
    });

  } catch (err) {
    console.error("Sensory Acquisition Failed:", err);
    if (localId === sessionCounter) onStatusChange('ERROR');
  }
}

export function stopLiveSession() {
  sessionCounter++;
  const sessionToClose = currentSession;
  currentSession = null;
  if (sessionToClose) { try { sessionToClose.close(); } catch(e) {} }
  activeIntervals.forEach(window.clearInterval);
  activeIntervals = [];
  [activeMediaStream, activeAudioStream].forEach(s => s?.getTracks().forEach(t => t.stop()));
  activeMediaStream = activeAudioStream = null;
  [activeAudioProcessor, activeAudioSource].forEach(n => n?.disconnect());
  activeAudioProcessor = activeAudioSource = null;
  if (inputAudioContext) { inputAudioContext.close().catch(() => {}); inputAudioContext = null; }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

