              if (s && (s as any).readyState === 1 || (s as any).ws?.readyState === 1) {
                try {
                  s.sendRealtimeInput({ media: { data: base64Audio, mimeType: 'audio/pcm;rate=16000' } });
                } catch(err) { /* Catch transient buffer issues */ }
              }
            });
          };
          activeAudioSource.connect(activeAudioProcessor);
          activeAudioProcessor.connect(inputAudioContext.destination);

          // Eye (Camera) Stream Initialization
