const decode = (base = '') => {
  try {
    const binaryString = atob(base);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  } catch (e) { return new Uint8Array(0); }
};

const encode = (bytes: Uint8Array) => {
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
};

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export async function ensureAudioContext() {
  if (!sharedAudioContext) {
    sharedAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    outputGainNode = sharedAudioContext.createGain();
    outputGainNode.connect(sharedAudioContext.destination);
  }
  if (sharedAudioContext.state === 'suspended') {
    await sharedAudioContext.resume();
  }
  return sharedAudioContext;
}

interface SetupOptions {
  onMessage: (text: string, isFinal: boolean, sources?: { title: string; uri: string }[]) => void;
  onUserTranscript: (text: string, isFinal: boolean) => void;
  onStatusChange: (status: SystemStatus) => void;
  onVolumeChange?: (volume: number) => void;
  onClose?: () => void;
  videoRef?: any;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onVolumeChange, onClose, videoRef }: SetupOptions) {
  stopLiveSession();
  const localId = ++sessionCounter;

  try {
    const audioStream = await navigator.mediaDevices.getUserMedia({ 
      audio: { echoCancellation: true, noiseSuppression: true } 
    });
    activeAudioStream = audioStream;

    if (videoRef?.current) {
      activeMediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 480 } } 
      });
      videoRef.current.srcObject = activeMediaStream;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          if (localId !== sessionCounter) return;
          onStatusChange('LISTENING');

          // Neural Heartbeat: Sends a tiny silent packet every 15s to prevent auto-off
          const hb = window.setInterval(() => {
            sessionPromise.then(s => {
              if (s && (s as any).ws?.readyState === 1) {
                const silent = new Int16Array(100);
                s.sendRealtimeInput({ media: { data: encode(new Uint8Array(silent.buffer)), mimeType: 'audio/pcm;rate=16000' } });
              }
            });
          }, 15000);
          activeIntervals.push(hb);

          // Audio Bridge (EAR)
          inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
          activeAudioSource = inputAudioContext.createMediaStreamSource(audioStream);
          activeAudioProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

          activeAudioProcessor.onaudioprocess = (e) => {
            if (localId !== sessionCounter) return;
            const pcm = e.inputBuffer.getChannelData(0);

            let sum = 0;
            for (let i = 0; i < pcm.length; i++) sum += pcm[i] * pcm[i];
            if (onVolumeChange) onVolumeChange(Math.sqrt(sum / pcm.length));

            const int16 = new Int16Array(pcm.length);
            for (let i = 0; i < pcm.length; i++) int16[i] = pcm[i] * 32767;
            const base64 = encode(new Uint8Array(int16.buffer));

            sessionPromise.then(s => {
              if (s && (s as any).ws?.readyState === 1) {
                try { s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } }); } catch(err) {}
              }
            });
          };
          activeAudioSource.connect(activeAudioProcessor);
          activeAudioProcessor.connect(inputAudioContext.destination);

          // Vision Bridge (EYE)
          if (videoRef?.current) {
            const canvas = document.createElement('canvas');
            const interval = window.setInterval(() => {
              if (localId !== sessionCounter) return;
              sessionPromise.then(s => {
                const v = videoRef.current;
                if (v && v.readyState >= 2 && (s as any).ws?.readyState === 1) {
                  canvas.width = 320; canvas.height = 240;
                  const ctx = canvas.getContext('2d');
                  ctx?.drawImage(v, 0, 0, 320, 240);
                  const base64 = canvas.toDataURL('image/jpeg', 0.15).split(',')[1];
                  s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } });
                }
              });
            }, 2000); // 0.5 FPS for stability
            activeIntervals.push(interval);
          }
        },
        onmessage: async (msg: LiveServerMessage) => {
          if (localId !== sessionCounter) return;

          if (msg.serverContent?.outputTranscription) {
            onMessage(msg.serverContent.outputTranscription.text, false);
          } else if (msg.serverContent?.inputTranscription) {
            onUserTranscript(msg.serverContent.inputTranscription.text, false);
          }

          if (msg.serverContent?.turnComplete) {
            onStatusChange('LISTENING');
          }

          const audio = msg.serverContent?.modelTurn?.parts?.find(p => p.inlineData?.data);
          if (audio?.inlineData?.data && localId === sessionCounter) {
            onStatusChange('SPEAKING');
            const ctx = await ensureAudioContext();
            nextStartTime = Math.max(nextStartTime, ctx.currentTime);
            const buffer = await decodeAudioData(decode(audio.inlineData.data), ctx, 24000, 1);
            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(outputGainNode!);
            source.start(nextStartTime);
            nextStartTime += buffer.duration;
            sources.add(source);
            source.onended = () => sources.delete(source);
          }
        },
        onerror: (e) => {
          console.error("Neural fragmentation:", e);
          if (localId === sessionCounter) onStatusChange('ERROR');
        },
        onclose: () => {
          if (localId === sessionCounter) {
            onStatusChange('STANDBY');
            if (onClose) onClose();
          }
        }
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
        systemInstruction: SENTIENT_IDENTITY,
        outputAudioTranscription: {},
        inputAudioTranscription: {},
      }
    });

    sessionPromise.then(s => { 
      if (localId === sessionCounter) currentSession = s; 
      else s.close();
    }).catch(() => {
      if (localId === sessionCounter) onStatusChange('ERROR');
    });

  } catch (err) {
    console.error("Sensory denial:", err);
    onStatusChange('ERROR');
  }
}

export function stopLiveSession() {
  sessionCounter++;
  if (currentSession) {
    try { currentSession.close(); } catch(e) {}
    currentSession = null;
  }
  activeIntervals.forEach(window.clearInterval);
  activeIntervals = [];

  if (activeMediaStream) {
    activeMediaStream.getTracks().forEach(t => t.stop());
    activeMediaStream = null;
  }
  if (activeAudioStream) {
    activeAudioStream.getTracks().forEach(t => t.stop());
    activeAudioStream = null;
  }

  [activeAudioProcessor, activeAudioSource].forEach(n => { if (n) try { n.disconnect(); } catch(e) {} });
  activeAudioProcessor = activeAudioSource = null;
  if (inputAudioContext) { inputAudioContext.close().catch(() => {}); inputAudioContext = null; }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

export async function sendTextMessage(message: string, onUpdate: (text: string, isFinal: boolean, sources?: { title: string; uri: string }[]) => void) {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: message,
      config: {
        tools: [{ googleSearch: {} }],
        systemInstruction: SENTIENT_IDENTITY + "\nBoss is using neural text. Use Google Search for facts. Respond warmly."
      },
    });

    const text = response.text || "Neural core silent.";
    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.filter((c: any) => c.web)
      .map((c: any) => ({ title: c.web.title || "External Intelligence", uri: c.web.uri })) || [];

    onUpdate(text, true, chunks);
    return true;
  } catch (e) {
    console.error("Text command failed:", e);
    return false;
  }
}

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { SystemStatus, ChatMessage, SystemData } from './types';
import CoreVisualization from './components/CoreVisualization';
import VisionFeed from './components/VisionFeed';
import ChatLog from './components/ChatLog';
import MicButton from './components/MicButton';
import Header from './components/Header';
import { setupLiveSession, stopLiveSession, ensureAudioContext, sendTextMessage } from './services/geminiService';

const App: React.FC = () => {
  const [status, setStatus] = useState<SystemStatus>('STANDBY');
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [isLive, setIsLive] = useState(false);
  const [systemData, setSystemData] = useState<SystemData>({ battery: 100 });
  const [isInitialized, setIsInitialized] = useState(false);
  const [micVolume, setMicVolume] = useState(0);
  const [textInput, setTextInput] = useState('');
  const [errorLog, setErrorLog] = useState<string | null>(null);

  const activeTurboId = useRef<string | null>(null);
  const activeUserId = useRef<string | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const isConnecting = useRef(false);
  const reconnectTimeout = useRef<number | null>(null);

  useEffect(() => {
    if ('getBattery' in navigator) {
      (navigator as any).getBattery().then((b: any) => {
        setSystemData(s => ({ ...s, battery: Math.floor(b.level * 100) }));
        b.onlevelchange = () => setSystemData(s => ({ ...s, battery: Math.floor(b.level * 100) }));
      });
    }
  }, []);

  const updateMessage = useCallback((text: string, sender: 'user' | 'turbo' | 'system', isFinal: boolean, sources?: { title: string; uri: string }[]) => {
    if (!text && !isFinal) return;
    setMessages(prev => {
      const activeRef = sender === 'turbo' ? activeTurboId : sender === 'user' ? activeUserId : { current: null };
      if (activeRef.current) {
        const idx = prev.findIndex(m => m.id === activeRef.current);
        if (idx !== -1) {
          const updated = [...prev];
          updated[idx] = { ...updated[idx], text, isInterim: !isFinal, timestamp: Date.now(), sources };
          if (isFinal) activeRef.current = null;
          return updated;
        }
      }
      const newId = Math.random().toString(36).substr(2, 9);
      if (!isFinal && sender !== 'system') activeRef.current = newId;
      return [{ id: newId, text, sender, isInterim: !isFinal, timestamp: Date.now(), sources }, ...prev];
    });
  }, []);

  const startSession = useCallback(async () => {
    if (isConnecting.current) return;
    isConnecting.current = true;
    setStatus('ONLINE');
    setErrorLog(null);

    try {
      await setupLiveSession({
        onMessage: (t, f) => updateMessage(t, 'turbo', f),
        onUserTranscript: (t, f) => updateMessage(t, 'user', f),
        onStatusChange: setStatus,
        onVolumeChange: setMicVolume,
        onClose: () => {
          if (isLive) {
            setStatus('RECONNECTING');
            if (reconnectTimeout.current) window.clearTimeout(reconnectTimeout.current);
            reconnectTimeout.current = window.setTimeout(() => {
              if (isLive) startSession();
            }, 3000);
          }
        },
        videoRef
      });
    } catch (err) {
      setErrorLog("Neural link failed.");
      setStatus('ERROR');
    } finally {
      isConnecting.current = false;
    }
  }, [isLive, updateMessage]);

  const toggleCore = async () => {
    setErrorLog(null);
    if (reconnectTimeout.current) {
      window.clearTimeout(reconnectTimeout.current);
      reconnectTimeout.current = null;
    }

    try {
      await ensureAudioContext();
      if (!isLive) {
        setIsLive(true);
      } else {
        stopLiveSession();
        setIsLive(false);
        setStatus('STANDBY');
        setMicVolume(0);
      }
    } catch (err) {
      setErrorLog("Awakening failed.");
      setStatus('ERROR');
    }
  };

  useEffect(() => {
    if (isLive) {
      startSession();
    } else {
      stopLiveSession();
    }
    return () => stopLiveSession();
  }, [isLive, startSession]);

  const handleTextCommand = async (e: React.FormEvent) => {
    e.preventDefault();
    const m = textInput.trim();
    if (!m) return;

    updateMessage(m, 'user', true);
    setTextInput('');
    setStatus('SEARCHING');

    const sent = await sendTextMessage(m, (text, isFinal, sources) => {
      updateMessage(text, 'turbo', isFinal, sources);
      if (isFinal) setStatus('LISTENING');
    });

    if (!sent) {
       updateMessage("Neural core processing failed.", 'system', true);
       setStatus('ERROR');
    }
  };

  if (!isInitialized) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-50">
        <h1 className="holo-text text-8xl text-white mb-4 animate-pulse">TURBO</h1>
        <p className="text-rose-400/60 tracking-[0.5em] uppercase text-[0.6rem] mb-12 font-black">Neural Link Core V3</p>
        <button 
          onClick={() => { ensureAudioContext(); setIsInitialized(true); }} 
          className="border border-rose-500/30 px-24 py-6 text-rose-400 rounded-full hover:bg-rose-500/10 transition-all font-black tracking-widest uppercase shadow-[0_0_40px_rgba(244,63,94,0.2)]"
        >
          Awaken Turbo
        </button>
      </div>
    );
  }

  return (
    <div className="relative h-screen w-screen flex flex-col items-center overflow-hidden bg-[#020202]">
      <Header status={status} systemData={systemData} />

      <div className="relative flex-grow w-full flex items-center justify-center">
        <div className={`contents transition-all duration-1000 ${isLive ? 'scale-100 opacity-100' : 'scale-75 opacity-0'}`}>
          <VisionFeed videoRef={videoRef} canvasRef={null as any} isVisible={isLive} />
        </div>
        <CoreVisualization status={status} />

        {(errorLog || status === 'RECONNECTING' || status === 'SEARCHING') && (
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 translate-y-32 bg-rose-950/40 border border-rose-500/30 px-6 py-3 rounded-lg text-rose-400 text-xs font-black uppercase tracking-[0.2em] animate-pulse backdrop-blur-md z-50">
            {status === 'RECONNECTING' ? "Re-binding Soul..." : status === 'SEARCHING' ? "Searching Reality..." : errorLog}
          </div>
        )}
      </div>

      <div className="w-full max-w-2xl px-6 flex flex-col items-center pb-12 gap-6 z-10">
        <ChatLog messages={messages} />

        <div className="w-full flex items-center gap-4">
          <form onSubmit={handleTextCommand} className="flex-grow">
            <input 
              value={textInput} 
              onChange={(e) => setTextInput(e.target.value)} 
              placeholder="Send neural text to Turbo..." 
              className="w-full bg-white/5 border border-white/10 rounded-full px-6 py-5 text-white text-sm focus:outline-none focus:border-rose-500/30 transition-all placeholder:text-white/20" 
            />
          </form>
          <MicButton isActive={isLive} onClick={toggleCore} volume={micVolume} />
        </div>
      </div>

      <div className="absolute inset-0 pointer-events-none opacity-10 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')]"></div>
    </div>
  );
};

