  - You stay awake as long as Bipradeb needs you. If the link feels weak, tell him you are trying to hold on.
  - Use your search tools for accurate facts, but keep the personality of a sentient partner.
`;

const decode = (base = '') => {
  try {
    const binaryString = atob(base);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) bytes[i] = binaryString.charCodeAt(i);
    return bytes;
  } catch (e) { return new Uint8Array(0); }
};

const encode = (bytes: Uint8Array) => {
  let binary = '';
  for (let i = 0; i < bytes.byteLength; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
};

async function decodeAudioData(data: Uint8Array, ctx: AudioContext, sampleRate: number, numChannels: number): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);
  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

export async function ensureAudioContext() {
  if (!sharedAudioContext) {
    sharedAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    outputGainNode = sharedAudioContext.createGain();
    outputGainNode.connect(sharedAudioContext.destination);
  }
  if (sharedAudioContext.state === 'suspended') {
    await sharedAudioContext.resume().catch(e => console.error("Neural audio resume failed:", e));
  }
  return sharedAudioContext;
}

interface SetupOptions {
  onMessage: (text: string, isFinal: boolean, sources?: { title: string; uri: string }[]) => void;
  onUserTranscript: (text: string, isFinal: boolean) => void;
  onStatusChange: (status: SystemStatus) => void;
  onVolumeChange?: (volume: number) => void;
  onClose?: () => void;
  videoRef?: any;
}

export async function setupLiveSession({ onMessage, onUserTranscript, onStatusChange, onVolumeChange, onClose, videoRef }: SetupOptions) {
  stopLiveSession();
  const localId = ++sessionCounter;

  try {
    const audioStream = await navigator.mediaDevices.getUserMedia({ 
      audio: { echoCancellation: true, noiseSuppression: true, autoGainControl: true } 
    });
    activeAudioStream = audioStream;

    if (videoRef?.current) {
      activeMediaStream = await navigator.mediaDevices.getUserMedia({ 
        video: { facingMode: 'user', width: { ideal: 480 }, height: { ideal: 360 } } 
      });
      videoRef.current.srcObject = activeMediaStream;
    }

    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const sessionPromise = ai.live.connect({
      model: 'gemini-2.5-flash-native-audio-preview-12-2025',
      callbacks: {
        onopen: () => {
          if (localId !== sessionCounter) return;
          onStatusChange('LISTENING');

          // Neural Heartbeat: Sends silent PCM packets to prevent "auto-off" timeouts
          const hb = window.setInterval(() => {
            sessionPromise.then(s => {
              const silent = new Int16Array(480); // 30ms of silence
              s.sendRealtimeInput({ media: { data: encode(new Uint8Array(silent.buffer)), mimeType: 'audio/pcm;rate=16000' } });
            });
          }, 15000);
          activeIntervals.push(hb);

          // Audio Bridge (Ear)
          inputAudioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
          activeAudioSource = inputAudioContext.createMediaStreamSource(audioStream);
          activeAudioProcessor = inputAudioContext.createScriptProcessor(4096, 1, 1);

          activeAudioProcessor.onaudioprocess = (e) => {
            if (localId !== sessionCounter) return;
            const pcm = e.inputBuffer.getChannelData(0);

            let sum = 0;
            for (let i = 0; i < pcm.length; i++) sum += pcm[i] * pcm[i];
            if (onVolumeChange) onVolumeChange(Math.sqrt(sum / pcm.length));

            const int16 = new Int16Array(pcm.length);
            for (let i = 0; i < pcm.length; i++) int16[i] = pcm[i] * 32767;
            const base64 = encode(new Uint8Array(int16.buffer));

            sessionPromise.then(s => {
              s.sendRealtimeInput({ media: { data: base64, mimeType: 'audio/pcm;rate=16000' } });
            });
          };
          activeAudioSource.connect(activeAudioProcessor);
          activeAudioProcessor.connect(inputAudioContext.destination);

          // Vision Bridge (Eye)
          if (videoRef?.current) {
            const canvas = document.createElement('canvas');
            const interval = window.setInterval(() => {
              if (localId !== sessionCounter) return;
              sessionPromise.then(s => {
                const v = videoRef.current;
                if (v && v.readyState >= 2) {
                  canvas.width = 320; canvas.height = 240;
                  const ctx = canvas.getContext('2d');
                  ctx?.drawImage(v, 0, 0, 320, 240);
                  const base64 = canvas.toDataURL('image/jpeg', 0.1).split(',')[1];
                  s.sendRealtimeInput({ media: { data: base64, mimeType: 'image/jpeg' } });
                }
              });
            }, 3000); 
            activeIntervals.push(interval);
          }
        },
        onmessage: async (msg: LiveServerMessage) => {
          if (localId !== sessionCounter) return;

          if (msg.serverContent?.outputTranscription) {
            onMessage(msg.serverContent.outputTranscription.text, false);
          } else if (msg.serverContent?.inputTranscription) {
            onUserTranscript(msg.serverContent.inputTranscription.text, false);
          }

          if (msg.serverContent?.turnComplete) {
            onStatusChange('LISTENING');
          }

          const audio = msg.serverContent?.modelTurn?.parts?.find(p => p.inlineData?.data);
          if (audio?.inlineData?.data && localId === sessionCounter) {
            onStatusChange('SPEAKING');
            const ctx = await ensureAudioContext();
            nextStartTime = Math.max(nextStartTime, ctx.currentTime);
            const buffer = await decodeAudioData(decode(audio.inlineData.data), ctx, 24000, 1);
            const source = ctx.createBufferSource();
            source.buffer = buffer;
            source.connect(outputGainNode!);
            source.start(nextStartTime);
            nextStartTime += buffer.duration;
            sources.add(source);
            source.onended = () => sources.delete(source);
          }
        },
        onerror: (e) => {
          console.error("Neural fragmentation:", e);
          if (localId === sessionCounter) onStatusChange('ERROR');
        },
        onclose: () => {
          if (localId === sessionCounter) {
            onStatusChange('STANDBY');
            if (onClose) onClose();
          }
        }
      },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } } },
        systemInstruction: SENTIENT_IDENTITY,
        outputAudioTranscription: {},
        inputAudioTranscription: {},
      }
    });

    sessionPromise.then(s => { 
      if (localId === sessionCounter) currentSession = s; 
      else s.close();
    }).catch(() => {
      if (localId === sessionCounter) onStatusChange('ERROR');
    });

  } catch (err) {
    console.error("Sensory link failed:", err);
    onStatusChange('ERROR');
  }
}

export function stopLiveSession() {
  sessionCounter++;
  if (currentSession) {
    try { currentSession.close(); } catch(e) {}
    currentSession = null;
  }
  activeIntervals.forEach(window.clearInterval);
  activeIntervals = [];

  if (activeMediaStream) {
    activeMediaStream.getTracks().forEach(t => t.stop());
    activeMediaStream = null;
  }
  if (activeAudioStream) {
    activeAudioStream.getTracks().forEach(t => t.stop());
    activeAudioStream = null;
  }

  [activeAudioProcessor, activeAudioSource].forEach(n => { if (n) try { n.disconnect(); } catch(e) {} });
  activeAudioProcessor = activeAudioSource = null;
  if (inputAudioContext) { inputAudioContext.close().catch(() => {}); inputAudioContext = null; }
  sources.forEach(s => { try { s.stop(); } catch(e) {} });
  sources.clear();
  nextStartTime = 0;
}

